  monthlyInterest: number; // Juros de mora % ao mês
  active: boolean;
}

export type LoanStatus = 'Ativo' | 'Inadimplente' | 'Quitado';
export type InstallmentStatus = 'Pago' | 'Atrasado' | 'Pendente';

export interface AppliedPenalty {
  patternId?: string;
  fixedRate: number;
  monthlyRate: number;
  daysLate: number;
  amount: number;
  baseValue: number;
}

export interface Loan {
  id: string;
  clientId: string;
  collaboratorId: string;
  principal: number;
  monthlyInterestRate: number;
  months: number;
  startDate: string;
  status: LoanStatus;
  installmentsStatus?: Record<number, InstallmentStatus>; 
  appliedPenalty?: AppliedPenalty;
}

export interface CashFlowPoint {
