}

import { Loan, Collaborator, LoanStatus, InstallmentStatus } from '../types';

export const formatCurrency = (val: number) => {
  return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
};

export const calculatePenalty = (base: number, fixedRate: number, monthlyMora: number, days: number): number => {
  const fixed = base * (fixedRate / 100);
  const mora = base * (monthlyMora / 100) * (days / 30);
  return fixed + mora;
};

export const calculateTotals = (loans: Loan[], collaborators: Collaborator[], startDate?: string, endDate?: string) => {
  let filteredLoans = loans;

  if (startDate || endDate) {
    filteredLoans = loans.filter(l => {
      const loanDate = l.startDate.slice(0, 7);
      const isAfter = startDate ? loanDate >= startDate.slice(0, 7) : true;
      const isBefore = endDate ? loanDate <= endDate.slice(0, 7) : true;
      return isAfter && isBefore;
    });
  }

  let totalPrincipal = 0;
  let totalProjectedInterest = 0;
  let totalPenaltyRevenue = 0;
  let totalCommissions = 0;

  filteredLoans.forEach(loan => {
    // Só conta para a carteira/projeção se não estiver quitado
    if (loan.status !== 'Quitado') {
      totalPrincipal += loan.principal;
      const monthlyInterest = loan.principal * (loan.monthlyInterestRate / 100);
      const totalLoanInterest = monthlyInterest * loan.months;
      totalProjectedInterest += totalLoanInterest;

      if (loan.appliedPenalty) {
        totalPenaltyRevenue += loan.appliedPenalty.amount;
      }

      // Cálculo de Comissão
      const collab = collaborators.find(c => c.id === loan.collaboratorId);
      if (collab) {
        if (collab.type === 'fixed_per_client') {
          totalCommissions += collab.value;
        } else {
          const baseValue = collab.base === 'gross' 
            ? (loan.principal + totalLoanInterest) 
            : totalLoanInterest;
          totalCommissions += baseValue * (collab.value / 100);
        }
      }
    }
  });

  const netProfit = totalProjectedInterest + totalPenaltyRevenue - totalCommissions;
  const roi = totalPrincipal > 0 ? (netProfit / totalPrincipal) * 100 : 0;

  return {
    totalPrincipal,
    totalProjectedRevenue: totalPrincipal + totalProjectedInterest + totalPenaltyRevenue,
    totalProjectedProfit: netProfit,
    totalPenaltyRevenue,
    totalCommissions,
    roi,
    lastDate: filteredLoans.length > 0 ? filteredLoans.sort((a,b) => b.startDate.localeCompare(a.startDate))[0].startDate : ''
  };
};

