  // Simplificado para refletir entradas baseadas no status manual
  const flowMap = new Map<string, { inflow: number; outflow: number }>();

  loans.forEach(loan => {
    const startMonth = loan.startDate.slice(0, 7);
    const mData = flowMap.get(startMonth) || { inflow: 0, outflow: 0 };
    mData.outflow += loan.principal;
    flowMap.set(startMonth, mData);

    // Projetar parcelas simplificadamente
    const monthlyInterest = loan.principal * (loan.monthlyInterestRate / 100);
    const installmentAmount = (loan.principal / loan.months) + monthlyInterest;

    for (let i = 1; i <= loan.months; i++) {
        const d = new Date(loan.startDate);
        d.setMonth(d.getMonth() + i);
        const monthKey = d.toISOString().slice(0, 7);
        const current = flowMap.get(monthKey) || { inflow: 0, outflow: 0 };
        current.inflow += installmentAmount;
        flowMap.set(monthKey, current);
    }
  });

  const sortedMonths = Array.from(flowMap.keys()).sort();
  let accumulated = 0;
  return sortedMonths.map(date => {
    const d = flowMap.get(date)!;
    const net = d.inflow - d.outflow;
    accumulated += net;
    return { date, inflow: d.inflow, outflow: d.outflow, net, accumulated };
  });
};

