import React, { useState } from 'react';
import { Loan, Client, Collaborator, LoanStatus, InstallmentStatus, PenaltyPattern, AppliedPenalty } from '../types';
import { formatCurrency, calculatePenalty } from '../utils/calculations';
import { 
  Trash2, ChevronDown, ChevronUp, Calendar, Filter, Calculator, 
  ShieldAlert, ArrowRight, Gavel, X, Clock, CheckCircle2, AlertTriangle 
} from 'lucide-react';

interface Props {
  loans: Loan[];
  clients: Client[];
  collaborators: Collaborator[];
  penaltyPatterns: PenaltyPattern[];
  onDelete: (id: string) => void;
  onUpdate: (loan: Loan) => void;
}

export const LoanList: React.FC<Props> = ({ loans, clients, collaborators, penaltyPatterns, onDelete, onUpdate }) => {
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [statusFilter, setStatusFilter] = useState<'all' | LoanStatus>('all');
  const [penaltyModal, setPenaltyModal] = useState<{loanId: string, days: number, patternId: string} | null>(null);

  const filteredLoans = loans.filter(l => statusFilter === 'all' ? true : l.status === statusFilter);

  const handleUpdateStatus = (loan: Loan, status: LoanStatus) => {
    onUpdate({ ...loan, status });
  };

  const handleApplyPenalty = () => {
    if (!penaltyModal) return;
    const loan = loans.find(l => l.id === penaltyModal.loanId);
    const pattern = penaltyPatterns.find(p => p.id === penaltyModal.patternId);
    if (!loan || !pattern) return;

    // Base: Valor da Parcela ou Principal? Aqui usamos o Principal como base de juros simples total do contrato conforme prompt
    const amount = calculatePenalty(loan.principal, pattern.fixedRate, pattern.monthlyInterest, penaltyModal.days);

    onUpdate({
      ...loan,
      appliedPenalty: {
        patternId: pattern.id,
        fixedRate: pattern.fixedRate,
        monthlyRate: pattern.monthlyInterest,
        daysLate: penaltyModal.days,
        amount,
        baseValue: loan.principal
      }
    });
    setPenaltyModal(null);
  };

  const renderDetails = (loan: Loan) => {
    const monthlyInterestVal = loan.principal * (loan.monthlyInterestRate / 100);
    const totalInterest = monthlyInterestVal * loan.months;
    const totalPenalty = loan.appliedPenalty?.amount || 0;
    const totalReceivable = loan.principal + totalInterest + totalPenalty;

    return (
      <div className="mt-6 space-y-6 animate-fade-in">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
           {/* Controle de Status Manual */}
           <div className="bg-slate-50 p-5 rounded-2xl border border-slate-200">
              <h5 className="text-[10px] font-black uppercase text-slate-400 mb-4 tracking-widest">Controle de Status (Manual)</h5>
              <div className="flex flex-wrap gap-2">
                 {(['Ativo', 'Inadimplente', 'Quitado'] as LoanStatus[]).map(s => (
                   <button 
                    key={s} 
                    onClick={() => handleUpdateStatus(loan, s)}
                    className={`px-4 py-2 rounded-xl text-xs font-bold transition-all border ${
                      loan.status === s ? 'bg-slate-900 text-white border-slate-900 shadow-md' : 'bg-white text-slate-600 border-slate-200 hover:border-slate-300'
                    }`}
                   >
                     {s}
                   </button>
                 ))}
              </div>
           </div>

           {/* Multa Aplicada */}
           <div className="bg-rose-50 p-5 rounded-2xl border border-rose-100 flex flex-col justify-between">
              <div className="flex justify-between items-center mb-4">
                 <div className="flex items-center gap-2">
                    <Gavel className="w-4 h-4 text-rose-600" />
                    <h5 className="text-[10px] font-black uppercase text-rose-500 tracking-widest">Multa de Atraso</h5>
                 </div>
                 <button onClick={() => setPenaltyModal({loanId: loan.id, days: 30, patternId: ''})} className="text-[10px] font-black uppercase bg-white px-3 py-1.5 rounded-lg border border-rose-200 text-rose-600 hover:bg-rose-100">
                   {loan.appliedPenalty ? 'Recalcular' : 'Aplicar Padrão'}
                 </button>
              </div>
              {loan.appliedPenalty ? (
                <div className="flex items-end justify-between">
                   <div className="text-[10px] font-bold text-rose-400">
                     {loan.appliedPenalty.daysLate} dias | {loan.appliedPenalty.fixedRate}% + {loan.appliedPenalty.monthlyRate}%/mês
                   </div>
                   <div className="text-xl font-black text-rose-700">{formatCurrency(loan.appliedPenalty.amount)}</div>
                </div>
              ) : (
                <p className="text-xs text-rose-400 italic">Nenhuma multa aplicada a este contrato.</p>
              )}
           </div>
        </div>

        {/* Resumo da Operação */}
        <div className="bg-slate-900 text-white p-6 rounded-2xl shadow-xl relative overflow-hidden">
           <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-6 relative z-10">
              <div>
                <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Total Emprestado</p>
                <p className="text-lg font-bold">{formatCurrency(loan.principal)}</p>
              </div>
              <div>
                <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Total Juros</p>
                <p className="text-lg font-bold text-blue-400">{formatCurrency(totalInterest)}</p>
              </div>
              <div>
                <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Multas</p>
                <p className="text-lg font-bold text-rose-400">{formatCurrency(totalPenalty)}</p>
              </div>
              <div className="md:col-span-2 text-right">
                <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Lucro Total da Operação</p>
                <p className="text-2xl font-black text-emerald-400 leading-none">{formatCurrency(totalInterest + totalPenalty)}</p>
              </div>
           </div>
           <div className="mt-6 pt-6 border-t border-slate-800 flex justify-between items-center">
              <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Valor Total a Receber</span>
              <span className="text-xl font-black">{formatCurrency(totalReceivable)}</span>
           </div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200 flex gap-4 overflow-x-auto no-scrollbar">
        {(['all', 'Ativo', 'Inadimplente', 'Quitado'] as const).map(s => (
          <button key={s} onClick={() => setStatusFilter(s)} className={`px-5 py-2 rounded-xl text-xs font-bold transition-all border whitespace-nowrap ${statusFilter === s ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-600 border-slate-200'}`}>
            {s === 'all' ? 'Todos Contratos' : s}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 gap-4">
        {filteredLoans.map(loan => {
           const client = clients.find(c => c.id === loan.clientId);
           const isExp = expandedId === loan.id;
           return (
             <div key={loan.id} className={`bg-white p-5 rounded-2xl border transition-all ${isExp ? 'border-blue-300 ring-4 ring-blue-50' : 'border-slate-200'}`}>
                <div className="flex justify-between items-center">
                   <div className="flex items-center gap-4">
                      <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center font-bold text-slate-600">{client?.name.charAt(0)}</div>
                      <div>
                         <h4 className="font-black text-slate-800 uppercase tracking-tighter">{client?.name || 'Cliente'}</h4>
                         <p className="text-[10px] font-bold text-slate-400 uppercase font-mono">{loan.id} | {loan.startDate}</p>
                      </div>
                   </div>
                   <div className="flex items-center gap-4">
                      <span className={`px-2.5 py-1 rounded-lg text-[10px] font-black uppercase border ${
                        loan.status === 'Ativo' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 
                        loan.status === 'Quitado' ? 'bg-slate-50 text-slate-500 border-slate-100' : 'bg-rose-50 text-rose-600 border-rose-100'
                      }`}>
                        {loan.status}
                      </span>
                      <button onClick={() => setExpandedId(isExp ? null : loan.id)} className="p-2 hover:bg-slate-100 rounded-lg text-slate-400">
                         {isExp ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}
                      </button>
                   </div>
                </div>
                {isExp && renderDetails(loan)}
             </div>
           );
        })}
      </div>

      {penaltyModal && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl p-8 border border-slate-200 animate-slide-up">
            <h3 className="text-xl font-bold text-slate-800 mb-6">Aplicar Padrão de Multa</h3>
            <div className="space-y-6">
               <div>
                  <label className="block text-xs font-black text-slate-400 uppercase mb-2">Padrão de Cálculo</label>
                  <select value={penaltyModal.patternId} onChange={e => setPenaltyModal({...penaltyModal, patternId: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border rounded-xl font-bold">
                    <option value="">Selecione...</option>
                    {penaltyPatterns.filter(p => p.active).map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                  </select>
               </div>
               <div>
                  <label className="block text-xs font-black text-slate-400 uppercase mb-2">Dias de Atraso</label>
                  <input type="number" value={penaltyModal.days} onChange={e => setPenaltyModal({...penaltyModal, days: Number(e.target.value)})} className="w-full px-4 py-3 bg-slate-50 border rounded-xl font-bold" />
               </div>
               <div className="flex gap-4">
                  <button onClick={() => setPenaltyModal(null)} className="flex-1 py-3 px-4 border rounded-xl font-bold text-slate-500">Cancelar</button>
                  <button onClick={handleApplyPenalty} className="flex-1 py-3 px-4 bg-slate-900 text-white rounded-xl font-bold">Confirmar</button>
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

