import { GoogleGenAI } from "@google/genai";
import { Loan, Client, Collaborator } from "../types";
import { generateCashFlow, calculateTotals } from "../utils/calculations";

/**
 * Analyzes financial risk and projections using Google Gemini API.
 */
export const analyzeFinancials = async (
  loans: Loan[],
  clients: Client[],
  collaborators: Collaborator[],
  userQuery: string
): Promise<string> => {
  if (!process.env.API_KEY) {
    return "Erro de configuração: Chave de API não encontrada (process.env.API_KEY).";
  }

  // Initialize client inside the function to ensure up-to-date environment context
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Prepare context data
  const cashFlow = generateCashFlow(loans, collaborators);
  const totals = calculateTotals(loans, collaborators);

  // Summarize loan list with resolved names and detailed history for risk analysis
  const loanSummary = loans.map(l => {
    const client = clients.find(c => c.id === l.clientId);
    const collab = collaborators.find(c => c.id === l.collaboratorId);
    return {
      id: l.id,
      cliente: client ? client.name : l.clientId,
      cliente_status: client ? client.status : 'unknown',
      colaborador: collab ? collab.name : l.collaboratorId,
      principal: l.principal,
      taxa: l.monthlyInterestRate,
      parcelas: l.months,
      inicio: l.startDate,
      status: l.status,
      // Fix: Use 'value' instead of 'commissionRate' from Collaborator type
      comissao_colaborador: collab ? collab.value : 0,
      historico_parcelas: l.installmentsStatus || {} // Crucial para análise de risco
    };
  });

  const contextData = {
    resumo_financeiro: totals,
    fluxo_caixa_projecao: cashFlow.slice(0, 24),
    carteira_emprestimos: loanSummary,
    clientes_cadastrados: clients.map(c => ({
        id: c.id,
        nome: c.name,
        status: c.status,
        obs: c.notes
    })),
    colaboradores_cadastrados: collaborators
  };

  const systemPrompt = `
    Você é um SISTEMA ESPECIALISTA EM RISCO FINANCEIRO e análise de empréstimos.

    Sua função expandida agora inclui:
    - calcular cronogramas e projeções financeiras.
    - PREVER A PROBABILIDADE DE INADIMPLÊNCIA (Default Risk).
    - analisar o histórico de pagamentos de cada cliente.

    DIRETRIZES DE ANÁLISE DE RISCO:
    1. Analise o 'historico_parcelas': 
       - Se houver 'atrasado', o risco aumenta exponencialmente.
       - Se houver 'pago' recorrente, o risco diminui.
    2. Considere a Taxa de Juros: Taxas muito acima da média (ex: > 20%) indicam empréstimos de alto risco.
    3. Considere o Valor Principal: Valores altos sem histórico prévio de pagamento 'pago' no sistema são alertas.
    4. Relação Prazo: Empréstimos muito longos (>12 meses) em juros simples aumentam a exposição ao risco.

    FORMATOS DE RESPOSTA OBRIGATÓRIOS:

    1. ANÁLISE DE RISCO ("Analise o risco do empréstimo [ID]")
    Responda com:
    - Score de Risco: [Baixo / Médio / Alto / Crítico]
    - Probabilidade Estimada: [0-100]%
    - Fatores de Risco: (Lista de pontos positivos e negativos)
    - Recomendação: (Ex: "Manter observação", "Refinanciar", "Encerrar novos créditos")

    2. PROJEÇÃO MENSAL ("Projeção do mês YYYY-MM")
    - Total a receber: R$ ...
    - Total de lucro: R$ ...
    - Lucro líquido: R$ ...

    3. PROJEÇÃO FUTURA (Tabela Markdown)

    RESTRIÇÕES:
    - Seja matemático. Se um cliente tem 1 parcela atrasada de 3, a probabilidade básica de inadimplência é de no mínimo 33%.
    - Use os dados reais fornecidos no JSON abaixo.

    DADOS DO SISTEMA (JSON):
    ${JSON.stringify(contextData, null, 2)}

    Responda sempre em Português de forma profissional e concisa.
  `;

  try {
    // Generate content using the recommended Gemini 3 Pro model
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: userQuery,
      config: {
        systemInstruction: systemPrompt,
        thinkingConfig: { thinkingBudget: 2048 } // Provide thinking budget for better reasoning
      }
    });

    // Access the generated text directly from the response object property
    return response.text || "Não foi possível gerar uma análise no momento.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Ocorreu um erro ao conectar com o analista financeiro IA. Verifique sua chave de API ou tente novamente.";
  }
};

