}

export type CommissionType = 'fixed_per_client' | 'percentage';
export type CommissionBase = 'gross' | 'profit';

export interface Collaborator {
  id: string;
  name: string;
  type: CommissionType;
  base: CommissionBase;
  value: number; // Valor em R$ ou %
}

export interface PenaltyPattern {
  id: string;
  name: string;
  fixedRate: number; // Multa fixa %
  monthlyInterest: number; // Juros de mora % ao mês
  active: boolean;
}

export type LoanStatus = 'Ativo' | 'Inadimplente' | 'Quitado';
export type InstallmentStatus = 'Pago' | 'Atrasado' | 'Pendente';

export interface Installment {
  number: number;
  dueDate: string;
  principalValue: number;
  interestValue: number;
  penaltyValue: number;
  status: InstallmentStatus;
}

export interface AppliedPenalty {
  patternId?: string;
  fixedRate: number;
  monthlyRate: number;
  daysLate: number;
  amount: number;
  baseValue: number;
}

export interface Loan {
  id: string;
  clientId: string;
  collaboratorId: string;
  principal: number;
  monthlyInterestRate: number;
  months: number;
  startDate: string;
  status: LoanStatus;
  installments: Installment[];
  appliedPenalty?: AppliedPenalty;
}

export interface MonthlyStats {
  month: string; // YYYY-MM
  toReceive: number;
  interestReceived: number;
  penaltiesReceived: number;
  commissionsExpense: number;
  netProfit: number;
}

export enum ViewState {
  DASHBOARD = 'DASHBOARD',
  LOANS = 'LOANS',
  CLIENTS = 'CLIENTS',
  COLLABORATORS = 'COLLABORATORS',
  PENALTY_PATTERNS = 'PENALTY_PATTERNS',
  AI_ANALYST = 'AI_ANALYST',
}

import { Loan, Collaborator, Installment, MonthlyStats } from '../types';

export const formatCurrency = (val: number) => {
  return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
};

export const calculatePenalty = (base: number, fixedRate: number, monthlyMora: number, days: number): number => {
  const fixed = base * (fixedRate / 100);
  const mora = base * (monthlyMora / 100) * (days / 30);
  return fixed + mora;
};

export const generateInstallments = (loan: Partial<Loan>): Installment[] => {
  const installments: Installment[] = [];
  const principalPerMonth = (loan.principal || 0) / (loan.months || 1);
  const interestPerMonth = (loan.principal || 0) * ((loan.monthlyInterestRate || 0) / 100);

  for (let i = 1; i <= (loan.months || 1); i++) {
    const d = new Date(loan.startDate + 'T12:00:00');
    d.setMonth(d.getMonth() + i);
    installments.push({
      number: i,
      dueDate: d.toISOString().split('T')[0],
      principalValue: principalPerMonth,
      interestValue: interestPerMonth,
      penaltyValue: 0,
      status: 'Pendente'
    });
  }
  return installments;
};

export const calculateMonthlyBreakdown = (loans: Loan[], collaborators: Collaborator[]): MonthlyStats[] => {
  const monthsMap = new Map<string, MonthlyStats>();

  loans.forEach(loan => {
    const collab = collaborators.find(c => c.id === loan.collaboratorId);

    // Distribuir comissão no primeiro mês do contrato (mês de origem)
    const startMonth = loan.startDate.slice(0, 7);
    const existingStart = monthsMap.get(startMonth) || { month: startMonth, toReceive: 0, interestReceived: 0, penaltiesReceived: 0, commissionsExpense: 0, netProfit: 0 };

    if (collab) {
      let commission = 0;
      const totalInterest = (loan.principal * (loan.monthlyInterestRate / 100)) * loan.months;
      if (collab.type === 'fixed_per_client') commission = collab.value;
      else commission = (collab.base === 'gross' ? (loan.principal + totalInterest) : totalInterest) * (collab.value / 100);
      existingStart.commissionsExpense += commission;
    }
    monthsMap.set(startMonth, existingStart);

    loan.installments.forEach(inst => {
      const instMonth = inst.dueDate.slice(0, 7);
      const mData = monthsMap.get(instMonth) || { month: instMonth, toReceive: 0, interestReceived: 0, penaltiesReceived: 0, commissionsExpense: 0, netProfit: 0 };

      if (inst.status === 'Pago') {
        mData.interestReceived += inst.interestValue;
        mData.penaltiesReceived += inst.penaltyValue;
      } else {
        mData.toReceive += inst.principalValue + inst.interestValue + inst.penaltyValue;
      }

      monthsMap.set(instMonth, mData);
    });
  });

  return Array.from(monthsMap.values())
    .map(m => ({ ...m, netProfit: m.interestReceived + m.penaltiesReceived - m.commissionsExpense }))
    .sort((a, b) => a.month.localeCompare(b.month));
};

export const calculateTotals = (loans: Loan[], collaborators: Collaborator[], startDate?: string, endDate?: string) => {
  const monthlyData = calculateMonthlyBreakdown(loans, collaborators);

  const filteredMonths = monthlyData.filter(m => {
    const isAfter = startDate ? m.month >= startDate.slice(0, 7) : true;
    const isBefore = endDate ? m.month <= endDate.slice(0, 7) : true;
    return isAfter && isBefore;
  });

  const totalPrincipalEmprestado = loans.reduce((acc, l) => acc + l.principal, 0);
  const toReceive = filteredMonths.reduce((acc, m) => acc + m.toReceive, 0);
  const netProfit = filteredMonths.reduce((acc, m) => acc + m.netProfit, 0);
  const penalties = filteredMonths.reduce((acc, m) => acc + m.penaltiesReceived, 0);

  const roi = totalPrincipalEmprestado > 0 ? (netProfit / totalPrincipalEmprestado) * 100 : 0;

  return {
    totalPrincipal: loans.filter(l => l.status !== 'Quitado').reduce((acc, l) => acc + l.principal, 0),
    toReceive,
    netProfit,
    penalties,
    roi,
    monthlyData: filteredMonths,
    lastDate: filteredMonths.length > 0 ? filteredMonths[filteredMonths.length - 1].month : ''
  };
};

