 */
export const analyzeFinancials = async (
  loans: Loan[],
  clients: Client[],
  collaborators: Collaborator[],
  userQuery: string
): Promise<string> => {
  if (!process.env.API_KEY) {
    return "Erro de configuração: Chave de API não encontrada (process.env.API_KEY).";
  }

  // Initialize client inside the function to ensure up-to-date environment context
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Prepare context data
  // Fix: Use calculateMonthlyBreakdown instead of non-existent generateCashFlow
  const cashFlow = calculateMonthlyBreakdown(loans, collaborators);
  const totals = calculateTotals(loans, collaborators);

  // Summarize loan list with resolved names and detailed history for risk analysis
  const loanSummary = loans.map(l => {
    const client = clients.find(c => c.id === l.clientId);
    const collab = collaborators.find(c => c.id === l.collaboratorId);
    return {
      id: l.id,
      cliente: client ? client.name : l.clientId,
      cliente_status: client ? client.status : 'unknown',
      colaborador: collab ? collab.name : l.collaboratorId,
      principal: l.principal,
      taxa: l.monthlyInterestRate,
      parcelas: l.months,
      inicio: l.startDate,
      status: l.status,
      // Fix: Use 'value' instead of 'commissionRate' from Collaborator type
      comissao_colaborador: collab ? collab.value : 0,
      // Fix: Property 'installmentsStatus' does not exist on type 'Loan'. Use 'installments'.
      historico_parcelas: l.installments || []
    };
  });

  const contextData = {
    resumo_financeiro: totals,
    fluxo_caixa_projecao: cashFlow.slice(0, 24),
    carteira_emprestimos: loanSummary,
    clientes_cadastrados: clients.map(c => ({
        id: c.id,
        nome: c.name,
        status: c.status,
        obs: c.notes
    })),
    colaboradores_cadastrados: collaborators
  };

  const systemPrompt = `
    Você é um SISTEMA ESPECIALISTA EM RISCO FINANCEIRO e análise de empréstimos.

    Sua função expandida agora inclui:
    - calcular cronogramas e projeções financeiras.
    - PREVER A PROBABILIDADE DE INADIMPLÊNCIA (Default Risk).
    - analisar o histórico de pagamentos de cada cliente.

    DIRETRIZES DE ANÁLISE DE RISCO:
    1. Analise o 'historico_parcelas': 
       - Se houver 'atrasado', o risco aumenta exponencialmente.
       - Se houver 'pago' recorrente, o risco diminui.
    2. Considere a Taxa de Juros: Taxas muito acima da média (ex: > 20%) indicam empréstimos de alto risco.
    3. Considere o Valor Principal: Valores altos sem histórico prévio de pagamento 'pago' no sistema são alertas.
    4. Relação Prazo: Empréstimos muito longos (>12 meses) em juros simples aumentam a exposição ao risco.

    FORMATOS DE RESPOSTA OBRIGATÓRIOS:

    1. ANÁLISE DE RISCO ("Analise o risco do empréstimo [ID]")
    Responda com:
    - Score de Risco: [Baixo / Médio / Alto / Crítico]
    - Probabilidade Estimada: [0-100]%
    - Fatores de Risco: (Lista de pontos positivos e negativos)
    - Recomendação: (Ex: "Manter observação", "Refinanciar", "Encerrar novos créditos")

    2. PROJEÇÃO MENSAL ("Projeção do mês YYYY-MM")
    - Total a receber: R$ ...
    - Total de lucro: R$ ...
    - Lucro líquido: R$ ...

    3. PROJEÇÃO FUTURA (Tabela Markdown)

    RESTRIÇÕES:
    - Seja matemático. Se um cliente tem 1 parcela atrasada de 3, a probabilidade básica de inadimplência é de no mínimo 33%.
    - Use os dados reais fornecidos no JSON abaixo.

    DADOS DO SISTEMA (JSON):
    ${JSON.stringify(contextData, null, 2)}

    Responda sempre em Português de forma profissional e concisa.
  `;

  try {
    // Generate content using the recommended Gemini 3 Pro model
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: userQuery,
      config: {
        systemInstruction: systemPrompt,
        thinkingConfig: { thinkingBudget: 2048 } // Provide thinking budget for better reasoning
      }
    });

    // Access the generated text directly from the response object property
    return response.text || "Não foi possível gerar uma análise no momento.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Ocorreu um erro ao conectar com o analista financeiro IA. Verifique sua chave de API ou tente novamente.";
  }
};

import React, { useState, useEffect } from 'react';
import { Loan, Client, Collaborator, LoanStatus } from '../types';
import { PlusCircle, Calculator, Save, AlertTriangle, ArrowRight } from 'lucide-react';
import { formatCurrency, generateInstallments } from '../utils/calculations';

interface LoanFormProps {
  onSave: (loan: Loan) => void;
  onCancel: () => void;
  clients: Client[];
  collaborators: Collaborator[];
  initialData?: Loan;
}

export const LoanForm: React.FC<LoanFormProps> = ({ onSave, onCancel, clients, collaborators, initialData }) => {
  const isEditMode = !!initialData;

  // Defaults to first available or empty, or initialData if provided
  const [formData, setFormData] = useState({
    clientId: initialData?.clientId || (clients.length > 0 ? clients[0].id : ''),
    collaboratorId: initialData?.collaboratorId || (collaborators.length > 0 ? collaborators[0].id : ''),
    principal: initialData?.principal || 3000,
    monthlyInterestRate: initialData?.monthlyInterestRate || 20.0,
    months: initialData?.months || 10,
    startDate: initialData?.startDate || new Date().toISOString().split('T')[0],
    // Fix: Default status should be 'Ativo' to match LoanStatus type
    status: initialData?.status || 'Ativo'
  });

  // Effect to update form if initialData changes (when switching between loans)
  useEffect(() => {
    if (initialData) {
      setFormData({
        clientId: initialData.clientId,
        collaboratorId: initialData.collaboratorId,
        principal: initialData.principal,
        monthlyInterestRate: initialData.monthlyInterestRate,
        months: initialData.months,
        startDate: initialData.startDate,
        status: initialData.status
      });
    }
  }, [initialData]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Fix: Generate installments for the loan
    const loanData: Partial<Loan> = {
      principal: Number(formData.principal),
      monthlyInterestRate: Number(formData.monthlyInterestRate),
      months: Number(formData.months),
      startDate: formData.startDate,
    };

    const installments = generateInstallments(loanData);

    // In edit mode, we keep the ID. In create mode, we generate one.
    const loanToSave: Loan = {
      id: initialData ? initialData.id : crypto.randomUUID(),
      clientId: formData.clientId,
      collaboratorId: formData.collaboratorId,
      principal: Number(formData.principal),
      monthlyInterestRate: Number(formData.monthlyInterestRate),
      months: Number(formData.months),
      startDate: formData.startDate,
      status: formData.status as LoanStatus,
      // Fix: Property 'installments' is missing but required in type 'Loan'
      installments: installments
    };
    onSave(loanToSave);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  // Calculations for Preview / Comparison
  const selectedCollaborator = collaborators.find(c => c.id === formData.collaboratorId);
  // Fix: Use 'value' instead of 'commissionRate' which is not defined in the Collaborator type
  const commissionRate = selectedCollaborator ? selectedCollaborator.value : 0;

  // Current Form Calculations
  const currentMonthlyInterest = Number(formData.principal) * (Number(formData.monthlyInterestRate) / 100);
  const currentTotalInterest = currentMonthlyInterest * Number(formData.months);
  const currentTotalRevenue = Number(formData.principal) + currentTotalInterest;

  // Initial Data Calculations (For Comparison)
  const initialMonthlyInterest = initialData ? initialData.principal * (initialData.monthlyInterestRate / 100) : 0;
  const initialTotalInterest = initialData ? initialMonthlyInterest * initialData.months : 0;
  const initialTotalRevenue = initialData ? initialData.principal + initialTotalInterest : 0;

  // Deltas
  const deltaRevenue = currentTotalRevenue - initialTotalRevenue;
  const deltaMonthly = currentMonthlyInterest - initialMonthlyInterest;

  return (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 max-w-4xl mx-auto animate-fade-in">
      <div className="flex items-center justify-between mb-6 border-b border-gray-100 pb-4">
        <div className="flex items-center gap-3">
          {isEditMode ? (
             <div className="p-2 bg-orange-100 rounded-lg">
               <AlertTriangle className="w-6 h-6 text-orange-600" />
             </div>
          ) : (
             <div className="p-2 bg-blue-100 rounded-lg">
               <Calculator className="w-6 h-6 text-blue-600" />
             </div>
          )}
          <div>
            <h2 className="text-xl font-bold text-gray-800">{isEditMode ? 'Editar Empréstimo' : 'Simular e Cadastrar'}</h2>
            {isEditMode && <p className="text-xs text-gray-500 font-mono">ID: {initialData.id}</p>}
          </div>
        </div>
        {isEditMode && (
          <span className="px-3 py-1 bg-orange-50 text-orange-700 text-xs font-bold uppercase rounded-full border border-orange-100">
            Modo Edição Ativo
          </span>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Form Column */}
        <form id="loanForm" onSubmit={handleSubmit} className="lg:col-span-2 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Cliente</label>
              <select
                required
                name="clientId"
                value={formData.clientId}
                onChange={handleChange}
                disabled={isEditMode} // Usually you don't change the client of an existing loan contract
                className={`w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white ${isEditMode ? 'bg-gray-100 text-gray-500 cursor-not-allowed' : ''}`}
              >
                {clients.map(c => (
                  <option key={c.id} value={c.id}>{c.name}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Colaborador</label>
               <select
                required
                name="collaboratorId"
                value={formData.collaboratorId}
                onChange={handleChange}
                disabled={isEditMode}
                className={`w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white ${isEditMode ? 'bg-gray-100 text-gray-500 cursor-not-allowed' : ''}`}
              >
                {collaborators.map(c => (
                  // Fix: Use 'value' instead of 'commissionRate' and handle display based on type
                  <option key={c.id} value={c.id}>{c.name} ({c.value}{c.type === 'percentage' ? '%' : ' R$'})</option>
                ))}
              </select>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Valor Principal (R$)</label>
              <input
                required
                type="number"
                min="1"
                step="0.01"
                name="principal"
                value={formData.principal}
                onChange={handleChange}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-colors focus:bg-blue-50"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Data de Início</label>
              <input
                required
                type="date"
                name="startDate"
                value={formData.startDate}
                onChange={handleChange}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-colors focus:bg-blue-50"
              />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Juros Mensal (%)</label>
              <input
                required
                type="number"
                min="0.1"
                step="0.01"
                name="monthlyInterestRate"
                value={formData.monthlyInterestRate}
                onChange={handleChange}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-colors focus:bg-blue-50"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Prazo (Meses)</label>
              <input
                required
                type="number"
                min="1"
                max="120"
                name="months"
                value={formData.months}
                onChange={handleChange}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-colors focus:bg-blue-50"
              />
            </div>
          </div>
        </form>

        {/* Impact Analysis Column */}
        <div className="space-y-4">
          {isEditMode ? (
            <div className="bg-gray-50 rounded-xl border border-gray-200 p-4">
              <h3 className="text-sm font-bold text-gray-800 uppercase mb-4 flex items-center gap-2">
                <AlertTriangle className="w-4 h-4 text-orange-500" />
                Análise de Impacto
              </h3>

              <div className="space-y-4 text-sm">
                <div className="grid grid-cols-2 gap-2 pb-2 border-b border-gray-200">
                  <span className="text-gray-500">Antes</span>
                  <span className="text-gray-500 text-right">Depois (Atual)</span>
                </div>

                {/* Monthly Interest Comparison */}
                <div className="flex justify-between items-center group">
                  <div className="text-gray-600">
                    <p className="text-xs">Lucro Mensal</p>
                    <p className="font-semibold text-gray-400 line-through">{formatCurrency(initialMonthlyInterest)}</p>
                  </div>
                  <ArrowRight className="w-4 h-4 text-gray-300" />
                  <div className="text-right">
                    <p className="text-xs text-gray-500">Novo Valor</p>
                    <p className={`font-bold ${deltaMonthly >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                      {formatCurrency(currentMonthlyInterest)}
                    </p>
                  </div>
                </div>

                {/* Total Revenue Comparison */}
                <div className="flex justify-between items-center">
                   <div className="text-gray-600">
                    <p className="text-xs">Recebimento Total</p>
                    <p className="font-semibold text-gray-400 line-through">{formatCurrency(initialTotalRevenue)}</p>
                  </div>
                  <ArrowRight className="w-4 h-4 text-gray-300" />
                  <div className="text-right">
                    <p className="text-xs text-gray-500">Novo Total</p>
                    <p className={`font-bold ${deltaRevenue >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                      {formatCurrency(currentTotalRevenue)}
                    </p>
                  </div>
                </div>

                {/* Delta Summary */}
                <div className={`mt-4 p-3 rounded-lg text-center border ${deltaRevenue >= 0 ? 'bg-green-50 border-green-100' : 'bg-red-50 border-red-100'}`}>
                  <p className="text-xs text-gray-500 uppercase font-semibold">Impacto no Caixa</p>
                  <p className={`text-lg font-bold ${deltaRevenue >= 0 ? 'text-green-700' : 'text-red-700'}`}>
                    {deltaRevenue > 0 ? '+' : ''}{formatCurrency(deltaRevenue)}
                  </p>
                </div>
              </div>
            </div>
          ) : (
            <div className="bg-blue-50 rounded-xl border border-blue-100 p-4">
               <h3 className="text-sm font-bold text-blue-800 uppercase mb-3">Resumo da Simulação</h3>
               <div className="space-y-3">
                 <div className="flex justify-between">
                   <span className="text-blue-600 text-sm">Lucro Mensal</span>
                   <span className="font-bold text-blue-900">{formatCurrency(currentMonthlyInterest)}</span>
                 </div>
                 <div className="flex justify-between">
                   <span className="text-blue-600 text-sm">Total Juros</span>
                   <span className="font-bold text-blue-900">{formatCurrency(currentTotalInterest)}</span>
                 </div>
                 <div className="pt-2 border-t border-blue-200 mt-2">
                   <div className="flex justify-between items-center">
                     <span className="text-xs text-gray-500 uppercase font-semibold">Total a Receber</span>
                     <span className="text-lg font-bold text-blue-900">{formatCurrency(currentTotalRevenue)}</span>
                   </div>
                 </div>
               </div>
            </div>
          )}

          {/* Action Buttons */}
          <div className="flex flex-col gap-3 mt-6">
            <button
              type="submit"
              form="loanForm"
              className={`w-full py-3 px-4 rounded-lg font-medium shadow-md transition flex items-center justify-center gap-2 text-white ${isEditMode ? 'bg-orange-600 hover:bg-orange-700' : 'bg-blue-600 hover:bg-blue-700'}`}
            >
              {isEditMode ? <Save className="w-5 h-5" /> : <PlusCircle className="w-5 h-5" />}
              {isEditMode ? 'Confirmar Edição' : 'Efetivar Empréstimo'}
            </button>
            <button
              type="button"
              onClick={onCancel}
              className="w-full py-3 px-4 bg-white border border-gray-300 text-gray-700 hover:bg-gray-50 rounded-lg font-medium transition"
            >
              Cancelar
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ViewState, Loan, Client, Collaborator, PenaltyPattern } from './types';
import { Dashboard } from './components/Dashboard';
import { LoanList } from './components/LoanList';
import { AIAnalyst } from './components/AIAnalyst';
import { ClientManager } from './components/ClientManager';
import { PenaltyPatternManager } from './components/PenaltyPatternManager';
import { CollaboratorManager } from './components/CollaboratorManager';
import { generateInstallments } from './utils/calculations';
import { 
  LayoutDashboard, 
  List, 
  Bot, 
  CircleDollarSign,
  Users,
  Briefcase,
  Gavel
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<ViewState>(ViewState.DASHBOARD);

  const [loans, setLoans] = useState<Loan[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [collaborators, setCollaborators] = useState<Collaborator[]>([]);
  const [penaltyPatterns, setPenaltyPatterns] = useState<PenaltyPattern[]>([]);

  useEffect(() => {
    // Versão v15 para garantir a atualização dos dados de seed solicitada
    const savedData = localStorage.getItem('fin_simples_data_v15');
    if (savedData) {
      const parsed = JSON.parse(savedData);
      setLoans(parsed.loans || []);
      setClients(parsed.clients || []);
      setCollaborators(parsed.collaborators || []);
      setPenaltyPatterns(parsed.penaltyPatterns || []);
    } else {
        const seedPatterns: PenaltyPattern[] = [
           { id: "P001", name: "Padrão Legal (2% + 1% mês)", fixedRate: 2, monthlyInterest: 1, active: true },
           { id: "P002", name: "Multa Atraso Curto (1% + 0.5% mês)", fixedRate: 1, monthlyInterest: 0.5, active: true }
        ];

        const seedClients: Client[] = [
          { id: 'C001', name: 'Matheus', cpf: '000.000.000-01', phone: '1191425-6969', status: 'active' },
          { id: 'C002', name: 'Bruno', cpf: '000.000.000-02', phone: '1197752-3942', status: 'active' },
          { id: 'C003', name: 'Esposa Bruno', cpf: '000.000.000-03', phone: '1197752-3942', status: 'active' },
          { id: 'C004', name: 'Bahia', cpf: '000.000.000-04', phone: '1198342-4814', status: 'active' },
        ];

        const seedCollaborators: Collaborator[] = [
          { id: 'V001', name: 'Administrador Principal', type: 'percentage', base: 'profit', value: 10 }
        ];

        const rawLoans: Partial<Loan>[] = [
          { id: 'E001', clientId: 'C001', collaboratorId: 'V001', principal: 10000, monthlyInterestRate: 40, months: 4, startDate: '2025-09-01', status: 'Ativo' },
          { id: 'E002', clientId: 'C002', collaboratorId: 'V001', principal: 8000, monthlyInterestRate: 10, months: 10, startDate: '2025-09-01', status: 'Ativo' },
          { id: 'E003', clientId: 'C002', collaboratorId: 'V001', principal: 2800, monthlyInterestRate: 25, months: 1, startDate: '2025-11-01', status: 'Ativo' },
          { id: 'E004', clientId: 'C003', collaboratorId: 'V001', principal: 5000, monthlyInterestRate: 13.5, months: 10, startDate: '2025-11-01', status: 'Ativo' },
          { id: 'E005', clientId: 'C004', collaboratorId: 'V001', principal: 5800, monthlyInterestRate: 14.66, months: 10, startDate: '2025-12-01', status: 'Ativo' },
          { id: 'E006', clientId: 'C001', collaboratorId: 'V001', principal: 1000, monthlyInterestRate: 20, months: 1, startDate: '2025-11-01', status: 'Quitado' },
          { id: 'E007', clientId: 'C001', collaboratorId: 'V001', principal: 2000, monthlyInterestRate: 22.5, months: 2, startDate: '2025-12-01', status: 'Ativo' },
        ];

        const seedLoans = rawLoans.map(l => {
          const loan = l as Loan;
          const insts = generateInstallments(loan);
          if (loan.status === 'Quitado') insts.forEach(i => i.status = 'Pago');
          return { ...loan, installments: insts };
