            <button onClick={() => setPeriod(3)} className="px-3 py-1.5 bg-slate-50 dark:bg-slate-800 hover:bg-slate-100 text-[10px] font-black text-slate-600 dark:text-slate-300 uppercase rounded-lg border border-slate-200 dark:border-slate-700 transition">3 Meses</button>
