import React, { useState } from 'react';
import { Loan, Collaborator, Client } from '../types';
import { calculateTotals, formatCurrency } from '../utils/calculations';
import {
  ComposedChart,
  Line,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer
} from 'recharts';
import { TrendingUp, Wallet, PiggyBank, Clock, ShieldAlert, Filter, ChevronRight, Info, BellRing, CalendarDays, Users } from 'lucide-react';

interface DashboardProps {
  loans: Loan[];
  collaborators: Collaborator[];
  clients: Client[];
}

const KPICard = ({ title, value, subtext, icon: Icon, color }: any) => (
  <div className="bg-white dark:bg-slate-900 p-5 sm:p-6 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm hover:shadow-md transition-all flex flex-col justify-between min-h-[140px]">
    <div className="flex justify-between items-start">
      <div className={`p-2.5 rounded-xl ${color} text-white shrink-0`}>
        <Icon className="w-5 h-5" />
      </div>
      <div className="text-right min-w-0">
        <p className="text-[10px] font-bold text-gray-400 dark:text-slate-500 uppercase tracking-widest truncate">{title}</p>
        <div className="text-lg sm:text-2xl font-black text-gray-800 dark:text-slate-100 break-all leading-tight">
          {value}
        </div>
      </div>
    </div>
    {subtext && <p className="text-[10px] sm:text-xs text-gray-500 dark:text-slate-400 font-medium mt-2 truncate">{subtext}</p>}
  </div>
);

export const Dashboard: React.FC<DashboardProps> = ({ loans, collaborators, clients }) => {
  const [filterStart, setFilterStart] = useState('');
  const [filterEnd, setFilterEnd] = useState('');

  const setPeriod = (months: number) => {
    const start = new Date().toISOString().slice(0, 7);
    const end = new Date();
    end.setMonth(end.getMonth() + months);
    setFilterStart(start);
    setFilterEnd(end.toISOString().slice(0, 7));
  };

  const stats = calculateTotals(loans, collaborators, filterStart, filterEnd);

  const roiStatus = stats.roi > 30 ? { label: 'Positivo', color: 'text-emerald-600 bg-emerald-50 dark:bg-emerald-950/30 dark:text-emerald-400' } 
                  : stats.roi > 10 ? { label: 'Neutro', color: 'text-blue-600 bg-blue-50 dark:bg-blue-950/30 dark:text-blue-400' }
                  : { label: 'Atenção', color: 'text-rose-600 bg-rose-50 dark:bg-rose-950/30 dark:text-rose-400' };

  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const next7Days = new Date(today);
  next7Days.setDate(today.getDate() + 7);

  const upcomingInstallments = loans.reduce((acc, loan) => {
    const upcoming = loan.installments.filter(inst => {
      if (inst.status !== 'Pendente') return false;
      const dueDate = new Date(inst.dueDate + 'T12:00:00');
      return dueDate >= today && dueDate <= next7Days;
    });
    return [...acc, ...upcoming];
  }, [] as any[]);

  const upcomingCount = upcomingInstallments.length;

  return (
    <div className="space-y-6">
      {/* Alerta de Vencimentos */}
      {upcomingCount > 0 && (
        <div className="bg-amber-50 dark:bg-amber-950/20 border border-amber-200 dark:border-amber-900/50 p-4 rounded-2xl flex flex-col sm:flex-row items-center justify-between gap-4 shadow-sm animate-pulse-slow">
          <div className="flex items-center gap-3 w-full sm:w-auto">
            <div className="p-2 bg-amber-100 dark:bg-amber-900/40 rounded-xl text-amber-600 dark:text-amber-400 shrink-0">
              <BellRing className="w-5 h-5" />
            </div>
            <div>
              <p className="text-sm font-bold text-amber-900 dark:text-amber-100">Atenção Operacional</p>
              <p className="text-xs text-amber-700 dark:text-amber-300 font-medium">Você tem <span className="font-black">{upcomingCount} parcelas</span> vencendo em breve.</p>
            </div>
          </div>
          <button 
            onClick={() => setPeriod(0)}
            className="w-full sm:w-auto flex items-center justify-center gap-1.5 px-4 py-2 bg-amber-600 dark:bg-amber-700 text-white rounded-lg text-[10px] font-black uppercase hover:bg-amber-700 transition"
          >
            <CalendarDays className="w-3.5 h-3.5" />
            Ver no Fluxo
          </button>
        </div>
      )}

      {/* Filtro Período */}
      <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl border border-gray-200 dark:border-slate-800 shadow-sm space-y-4">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-slate-100 dark:bg-slate-800 rounded-lg text-slate-500 dark:text-slate-400 shrink-0"><Filter className="w-5 h-5" /></div>
            <h2 className="font-bold text-slate-700 dark:text-slate-200">Filtro de Período de Caixa</h2>
