            {activeTab === ViewState.CLIENTS && <ClientManager clients={clients} loans={loans} onAddClient={c => setClients([...clients, c])} onUpdateClient={u => setClients(clients.map(c => c.id === u.id ? u : c))} onDeleteClient={id => setClients(clients.filter(c => c.id !== id))} />}
            {activeTab === ViewState.LOANS && <LoanList loans={loans} clients={clients} collaborators={collaborators} penaltyPatterns={penaltyPatterns} onDelete={id => setLoans(loans.filter(l => l.id !== id))} onUpdate={u => setLoans(loans.map(l => l.id === u.id ? u : l))} />}
            {activeTab === ViewState.EXPENSES && <ExpenseManager expenses={expenses} portfolios={portfolios} onAdd={handleAddExpense} onUpdate={handleUpdateExpense} onDelete={handleDeleteExpense} />}
            {activeTab === ViewState.PORTFOLIOS && <PortfolioManager portfolios={portfolios} movements={portfolioMovements} onAdd={p => setPortfolios([...portfolios, p])} onUpdate={u => setPortfolios(portfolios.map(p => p.id === u.id ? u : p))} onDelete={id => setPortfolios(portfolios.filter(p => p.id !== id))} onAddMovement={m => setPortfolioMovements([...portfolioMovements, m])} />}
            {activeTab === ViewState.COLLABORATORS && <CollaboratorManager collaborators={collaborators} onAdd={c => setCollaborators([...collaborators, c])} onUpdate={u => setCollaborators(collaborators.map(c => c.id === u.id ? u : c))} onDelete={id => setCollaborators(collaborators.filter(c => c.id !== id))} />}
            {activeTab === ViewState.PENALTY_PATTERNS && <PenaltyPatternManager patterns={penaltyPatterns} onAdd={p => setPenaltyPatterns([...penaltyPatterns, p])} onUpdate={u => setPenaltyPatterns(penaltyPatterns.map(p => p.id === u.id ? p : p))} onDelete={id => setPenaltyPatterns(penaltyPatterns.filter(p => p.id !== id))} />}
            {activeTab === ViewState.AI_ANALYST && <AIAnalyst loans={loans} clients={clients} collaborators={collaborators} />}
          </div>
        </div>
      </main>
    </div>
  );
};

