import React, { useState } from 'react';
import { Portfolio, PortfolioType, PortfolioMovement } from '../types';
import { formatCurrency } from '../utils/calculations';
import { 
  Plus, 
  Trash2, 
  Edit, 
  Save, 
  X, 
  Search, 
  Wallet, 
  ArrowUpRight, 
  ArrowDownLeft, 
  CalendarDays,
  History,
  TrendingUp,
  Settings2,
  Lock
} from 'lucide-react';

interface Props {
  portfolios: Portfolio[];
  movements: PortfolioMovement[];
  onAdd: (p: Portfolio) => void;
  onUpdate: (p: Portfolio) => void;
  onDelete: (id: string) => void;
  onAddMovement: (m: PortfolioMovement) => void;
}

export const PortfolioManager: React.FC<Props> = ({ portfolios, movements, onAdd, onUpdate, onDelete, onAddMovement }) => {
  const [view, setView] = useState<'grid' | 'details' | 'form' | 'movementForm'>('grid');
  const [selectedPortfolio, setSelectedPortfolio] = useState<Portfolio | null>(null);
  const [editingPortfolio, setEditingPortfolio] = useState<Portfolio | null>(null);

  const [portfolioForm, setPortfolioForm] = useState<Portfolio>({
    id: '',
    name: '',
    type: 'Caixa'
  });

  const [movementForm, setMovementForm] = useState<PortfolioMovement>({
    id: '',
    portfolioId: '',
    date: new Date().toISOString().split('T')[0],
    amount: 0,
    origin: 'Manual',
    description: ''
  });

  const getPortfolioStats = (id: string) => {
    const pMovements = movements.filter(m => m.portfolioId === id);
    const inflows = pMovements.filter(m => m.amount > 0).reduce((acc, m) => acc + m.amount, 0);
    const outflows = pMovements.filter(m => m.amount < 0).reduce((acc, m) => acc + Math.abs(m.amount), 0);
    return {
      balance: inflows - outflows,
      totalIn: inflows,
      totalOut: outflows,
      history: pMovements.sort((a, b) => b.date.localeCompare(a.date))
    };
  };

  const handleOpenPortfolioForm = (p?: Portfolio) => {
    if (p) {
      setPortfolioForm(p);
      setEditingPortfolio(p);
    } else {
      setPortfolioForm({ id: crypto.randomUUID(), name: '', type: 'Reserva' });
      setEditingPortfolio(null);
    }
    setView('form');
  };

  const handleOpenMovementForm = (p: Portfolio) => {
    setMovementForm({
      id: crypto.randomUUID(),
      portfolioId: p.id,
      date: new Date().toISOString().split('T')[0],
      amount: 0,
      origin: 'Manual',
      description: ''
    });
    setView('movementForm');
  };

  const handlePortfolioSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingPortfolio) onUpdate(portfolioForm);
    else onAdd(portfolioForm);
    setView('grid');
  };

  const handleMovementSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAddMovement(movementForm);
    setView('details');
  };

  const handleDeletePortfolio = (id: string) => {
    const stats = getPortfolioStats(id);
    if (stats.balance !== 0) {
      alert("Não é possível excluir uma carteira com saldo ativo. Zere o saldo antes de excluir.");
      return;
    }
    if (window.confirm("Deseja realmente excluir esta carteira?")) {
      onDelete(id);
      setView('grid');
    }
  };

  return (
    <div className="space-y-8 animate-fade-in">
      {view === 'grid' && (
        <>
          <div className="flex justify-between items-center bg-white dark:bg-slate-900 p-5 rounded-3xl border border-slate-200 dark:border-slate-800">
            <div>
              <h2 className="text-xl font-black text-slate-800 dark:text-slate-100 uppercase tracking-tight">Carteiras de Alocação</h2>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Controle de balanço e ativos externos</p>
            </div>
            <button onClick={() => handleOpenPortfolioForm()} className="px-5 py-2.5 bg-blue-600 text-white rounded-2xl font-black uppercase text-[10px] flex items-center gap-2 shadow-lg shadow-blue-200 dark:shadow-none hover:bg-blue-700 transition">
              <Plus className="w-4 h-4" /> Nova Carteira
            </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {portfolios.map(p => {
              const stats = getPortfolioStats(p.id);
              return (
                <div key={p.id} className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm hover:shadow-md transition-all group flex flex-col justify-between min-h-[220px]">
                  <div className="flex justify-between items-start">
