import React, { useState, useMemo } from 'react';
import { Loan, Installment } from '../types';
import { formatCurrency } from '../utils/calculations';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Legend, 
  ComposedChart, 
  Line 
} from 'recharts';
import { 
  TrendingUp, 
  Target, 
  Calendar, 
  ArrowUpRight, 
  Users, 
  Layers, 
  Clock, 
  CheckCircle2, 
  AlertCircle 
} from 'lucide-react';

interface ForecastProps {
  loans: Loan[];
}

export const Forecast: React.FC<ForecastProps> = ({ loans }) => {
  // Configurações do Simulador
  const [targetInterest, setTargetInterest] = useState<number>(100000);
  const [targetMonths, setTargetMonths] = useState<number>(12);
  const [avgTicket, setAvgTicket] = useState<number>(5000);
  const [avgProfitPerLoan, setAvgProfitPerLoan] = useState<number>(1500);

  // 1. Filtragem e Cálculos de Dados Atuais (Apenas Ativos)
  const activeLoans = useMemo(() => loans.filter(l => l.status === 'Ativo'), [loans]);

  const stats = useMemo(() => {
    let totalFutureInterest = 0;
    let totalPrincipalInCirculation = 0;
    let totalFuturePenalty = 0;
    let totalMonthsSum = 0;

    activeLoans.forEach(loan => {
      loan.installments.forEach(inst => {
        if (inst.status !== 'Pago') {
          totalFutureInterest += inst.interestValue;
          totalPrincipalInCirculation += inst.principalValue;
          totalFuturePenalty += inst.penaltyValue;
        }
      });
      totalMonthsSum += loan.months;
    });

    const avgMonths = activeLoans.length > 0 ? totalMonthsSum / activeLoans.length : 0;
    const projectedROI = totalPrincipalInCirculation > 0 ? (totalFutureInterest / totalPrincipalInCirculation) * 100 : 0;

    return {
      predictability: totalFutureInterest,
      principalInCirculation: totalPrincipalInCirculation,
      totalRevenue: totalFutureInterest + totalPrincipalInCirculation + totalFuturePenalty,
      roi: projectedROI,
      avgMonths,
      activeCount: activeLoans.length
    };
  }, [activeLoans]);

  // 2. Preparação dos dados para o gráfico de Linha do Tempo
  const chartData = useMemo(() => {
    const timeline: Record<string, { month: string, principal: number, juros: number, total: number }> = {};
    const today = new Date().toISOString().slice(0, 7);

    activeLoans.forEach(loan => {
      loan.installments.forEach(inst => {
        if (inst.status !== 'Pago') {
          const monthKey = inst.dueDate.slice(0, 7);
          // Somente meses futuros ou atuais
          if (!timeline[monthKey]) {
            timeline[monthKey] = { month: monthKey, principal: 0, juros: 0, total: 0 };
          }
          timeline[monthKey].principal += inst.principalValue;
          timeline[monthKey].juros += inst.interestValue + inst.penaltyValue;
          timeline[monthKey].total += inst.principalValue + inst.interestValue + inst.penaltyValue;
        }
      });
    });

    return Object.values(timeline).sort((a, b) => a.month.localeCompare(b.month));
  }, [activeLoans]);

  // 3. Cálculos do Simulador
  const simulationResults = useMemo(() => {
    const contractsNeeded = Math.ceil(targetInterest / avgProfitPerLoan);
    const contractsMissing = Math.max(0, contractsNeeded - stats.activeCount);
    const monthlyAportNeeded = (contractsMissing * avgTicket) / targetMonths;
    const finalMonthlyRevenue = (contractsNeeded * (avgTicket + avgProfitPerLoan)) / targetMonths;

    const progress = Math.min(100, (stats.predictability / targetInterest) * 100);

    let statusLabel = "Abaixo da meta";
    let statusColor = "text-rose-500 bg-rose-50 dark:bg-rose-950/20";

    if (progress >= 100) {
      statusLabel = "Meta atingida";
      statusColor = "text-emerald-500 bg-emerald-50 dark:bg-emerald-950/20";
    } else if (progress > 50) {
      statusLabel = "Em crescimento";
      statusColor = "text-blue-500 bg-blue-50 dark:bg-blue-950/20";
    }

    return {
      contractsNeeded,
      contractsMissing,
      monthlyAportNeeded,
      finalMonthlyRevenue,
      progress,
      statusLabel,
      statusColor
    };
  }, [targetInterest, avgProfitPerLoan, avgTicket, targetMonths, stats]);

  return (
    <div className="space-y-8 animate-fade-in pb-12">

      {/* 1. RESUMO DE PREVISIBILIDADE */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
        <ForecastCard 
          title="Juros Futuros" 
          value={formatCurrency(stats.predictability)} 
          sub="Previsibilidade atual"
          icon={TrendingUp} 
          color="bg-emerald-500"
        />
        <ForecastCard 
          title="Principal em Aberto" 
          value={formatCurrency(stats.principalInCirculation)} 
          sub="Capital em circulação"
          icon={Layers} 
          color="bg-slate-800"
        />
        <ForecastCard 
          title="Receita Total" 
          value={formatCurrency(stats.totalRevenue)} 
          sub="Principal + Juros + Multas"
          icon={ArrowUpRight} 
          color="bg-blue-600"
        />
        <ForecastCard 
          title="ROI Projetado" 
          value={`${stats.roi.toFixed(1)}%`} 
          sub="Rentabilidade da carteira"
          icon={Target} 
          color="bg-indigo-600"
        />
        <ForecastCard 
          title="Prazo Médio" 
          value={`${stats.avgMonths.toFixed(1)} meses`} 
          sub="Tempo médio contratos"
          icon={Clock} 
          color="bg-orange-500"
        />
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">

        {/* 2. LINHA DO TEMPO (GRÁFICO) */}
        <div className="xl:col-span-2 bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm">
          <div className="flex justify-between items-center mb-8">
            <div>
              <h3 className="text-sm font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest flex items-center gap-2">
                <Calendar className="w-4 h-4" /> Linha do Tempo de Recebimentos
              </h3>
              <p className="text-xs text-slate-400 mt-1">Projeção mensal baseada em contratos ativos</p>
            </div>
          </div>
          <div className="h-[350px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <ComposedChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" className="dark:stroke-slate-800" />
                <XAxis 
                  dataKey="month" 
                  tick={{fontSize: 10, fontWeight: 700, fill: '#94a3b8'}} 
                  axisLine={false} 
                  tickLine={false} 
                  tickFormatter={(val) => val.split('-').reverse().join('/')} 
                />
                <YAxis 
                  tick={{fontSize: 10, fontWeight: 700, fill: '#94a3b8'}} 
                  axisLine={false} 
                  tickLine={false} 
                  tickFormatter={(val) => `R$ ${val/1000}k`}
                />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#0f172a', border: 'none', borderRadius: '16px', color: '#f1f5f9' }} 
                  itemStyle={{ fontSize: '11px', fontWeight: 700 }} 
                  formatter={(value: number) => formatCurrency(value)} 
                />
                <Legend iconType="circle" wrapperStyle={{ fontSize: '10px', fontWeight: 700, paddingTop: '20px' }} />
                <Bar dataKey="principal" name="Principal" fill="#1e293b" radius={[4, 4, 0, 0]} barSize={24} stackId="a" />
                <Bar dataKey="juros" name="Juros/Multas" fill="#10b981" radius={[4, 4, 0, 0]} barSize={24} stackId="a" />
                <Line type="monotone" dataKey="total" name="Total do Mês" stroke="#3b82f6" strokeWidth={2} dot={{ r: 4, fill: '#3b82f6' }} />
              </ComposedChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* 3. SIMULAÇÃO DE META */}
        <div className="space-y-6">
          <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col h-full">
            <h3 className="text-sm font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-6 flex items-center gap-2">
              <Target className="w-4 h-4 text-blue-500" /> Planejamento de Metas
            </h3>

            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Meta de Previsibilidade (R$)</label>
                <input 
                  type="number" 
                  value={targetInterest} 
