                  />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Ticket Médio (R$)</label>
                  <input 
                    type="number" 
                    value={avgTicket} 
                    onChange={e => setAvgTicket(Number(e.target.value))}
