                  />
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Juros Médio/Contrato (R$)</label>
                <input 
                  type="number" 
                  value={avgProfitPerLoan} 
                  onChange={e => setAvgProfitPerLoan(Number(e.target.value))}
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none font-bold focus:ring-2 focus:ring-blue-500 transition" 
                />
              </div>
            </div>

            <div className="mt-8 pt-8 border-t border-slate-50 dark:border-slate-800 space-y-4">
              <div className="flex justify-between items-center p-3 bg-blue-50 dark:bg-blue-950/20 rounded-2xl border border-blue-100 dark:border-blue-900/40">
                <div className="flex items-center gap-2">
                  <Users className="w-4 h-4 text-blue-600" />
                  <span className="text-xs font-bold text-slate-600 dark:text-slate-400">Contratos necessários</span>
                </div>
                <span className="text-sm font-black text-blue-700 dark:text-blue-300">{simulationResults.contractsNeeded}</span>
              </div>

              <div className="flex justify-between items-center p-3 bg-slate-50 dark:bg-slate-800 rounded-2xl border border-slate-100 dark:border-slate-700">
                <span className="text-xs font-bold text-slate-500">Contratos faltantes</span>
                <span className="text-sm font-black text-slate-800 dark:text-slate-100">{simulationResults.contractsMissing}</span>
              </div>

              <div className="flex justify-between items-center p-3 bg-emerald-50 dark:bg-emerald-950/20 rounded-2xl border border-emerald-100 dark:border-emerald-900/40">
                <span className="text-xs font-bold text-emerald-600">Aporte mensal médio</span>
                <span className="text-sm font-black text-emerald-700 dark:text-emerald-400">{formatCurrency(simulationResults.monthlyAportNeeded)}</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* 4. STATUS DA META */}
      <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm">
        <div className="flex flex-col md:flex-row items-center gap-8">
          <div className="w-full md:w-1/3">
            <h4 className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-4">Progresso da Meta</h4>
            <div className="flex items-center gap-4">
              <div className={`p-4 rounded-2xl ${simulationResults.statusColor}`}>
                {simulationResults.progress >= 100 ? <CheckCircle2 className="w-8 h-8" /> : <AlertCircle className="w-8 h-8" />}
              </div>
              <div>
                <p className={`text-sm font-black uppercase tracking-tight ${simulationResults.statusLabel === 'Abaixo da meta' ? 'text-rose-600' : 'text-emerald-600'}`}>{simulationResults.statusLabel}</p>
                <p className="text-3xl font-black text-slate-800 dark:text-slate-100">{simulationResults.progress.toFixed(1)}%</p>
              </div>
            </div>
          </div>

          <div className="w-full md:w-2/3 space-y-4">
            <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest text-slate-400">
              <span>Garantido: {formatCurrency(stats.predictability)}</span>
              <span>Alvo: {formatCurrency(targetInterest)}</span>
            </div>
            <div className="h-4 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
              <div 
                className={`h-full transition-all duration-1000 ease-out ${simulationResults.progress >= 100 ? 'bg-emerald-500' : 'bg-blue-600'}`} 
                style={{ width: `${simulationResults.progress}%` }} 
              />
            </div>
            <p className="text-xs text-slate-500 font-medium italic text-right">
              Faltam {formatCurrency(Math.max(0, targetInterest - stats.predictability))} de juros para atingir o objetivo.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

