import { Loan, Collaborator, Installment, MonthlyStats, Expense } from '../types';

export const formatCurrency = (val: number) => {
  return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
};

export const calculatePenalty = (base: number, fixedRate: number, monthlyMora: number, days: number): number => {
  const fixed = base * (fixedRate / 100);
  const mora = base * (monthlyMora / 100) * (days / 30);
  return fixed + mora;
};

export const generateInstallments = (loan: Partial<Loan>): Installment[] => {
  const installments: Installment[] = [];
  const totalMonths = loan.months || 1;
  const principal = loan.principal || 0;
  const interestPerMonth = principal * ((loan.monthlyInterestRate || 0) / 100);

  for (let i = 1; i <= totalMonths; i++) {
    const d = new Date(loan.startDate + 'T12:00:00');
    d.setMonth(d.getMonth() + i);

    // Regra: Principal (Capital) é devolvido integralmente apenas na última parcela.
    const principalValue = i === totalMonths ? principal : 0;

    installments.push({
      number: i,
      dueDate: d.toISOString().split('T')[0],
      principalValue: principalValue,
      interestValue: interestPerMonth,
      penaltyValue: 0,
      status: 'Pendente'
    });
  }
  return installments;
};

export const calculateMonthlyBreakdown = (loans: Loan[], collaborators: Collaborator[], expenses: Expense[] = []): MonthlyStats[] => {
  const monthsMap = new Map<string, MonthlyStats>();

  const getMonthData = (month: string): MonthlyStats => {
    if (!monthsMap.has(month)) {
      monthsMap.set(month, { 
        month, toReceive: 0, interestReceived: 0, penaltiesReceived: 0, 
        interestTotal: 0, penaltiesTotal: 0, commissionsExpense: 0, 
        operationalExpenses: 0, transfersToPortfolio: 0, netProfit: 0, cashFlow: 0 
      });
    }
    return monthsMap.get(month)!;
  };

  // Cálculo de Comissões e Juros Totais (Projetados)
  loans.forEach(loan => {
    const collab = collaborators.find(c => c.id === loan.collaboratorId);
    const startMonth = loan.startDate.slice(0, 7);
    const mData = getMonthData(startMonth);

    // Comissão é uma despesa provisionada/paga no início do contrato
    if (collab) {
      let commission = 0;
      const totalInterest = (loan.principal * (loan.monthlyInterestRate / 100)) * loan.months;
      if (collab.type === 'fixed_per_client') commission = collab.value;
      else commission = (collab.base === 'gross' ? (loan.principal + totalInterest) : totalInterest) * (collab.value / 100);
      mData.commissionsExpense += commission;
    }
  });

  // Fluxo de Parcelas
  loans.forEach(loan => {
    loan.installments.forEach(inst => {
      const instMonth = inst.dueDate.slice(0, 7);
      const mData = getMonthData(instMonth);

      // Sempre somar ao juros total projetado do mês de vencimento
      mData.interestTotal += inst.interestValue;
      mData.penaltiesTotal += inst.penaltyValue;

      if (inst.status === 'Pago') {
        mData.interestReceived += inst.interestValue;
        mData.penaltiesReceived += inst.penaltyValue;
        // Entrada de Caixa: Principal + Juros + Multa
        mData.cashFlow += inst.principalValue + inst.interestValue + inst.penaltyValue;
      } else {
        // Futuro a receber
        mData.toReceive += inst.principalValue + inst.interestValue + inst.penaltyValue;
      }
    });

    // Saída de Caixa: O empréstimo do Capital Principal
    const startMonth = loan.startDate.slice(0, 7);
    const startMData = getMonthData(startMonth);
    startMData.cashFlow -= loan.principal;
  });

  // Despesas e Transferências
  expenses.forEach(exp => {
    const expMonth = exp.date.slice(0, 7);
    const mData = getMonthData(expMonth);

    if (exp.type === 'operational') {
      mData.operationalExpenses += exp.amount;
    } else {
      mData.transfersToPortfolio += exp.amount;
    }
  });

  return Array.from(monthsMap.values())
    .map(m => ({ 
      ...m, 
      // Lucro Líquido = O que de fato entrou de juros/multa - despesas - comissões
      netProfit: m.interestReceived + m.penaltiesReceived - m.commissionsExpense - m.operationalExpenses,
      // Fluxo de Caixa = Entradas reais - Saídas reais (Empréstimos + Despesas + Transferências + Comissões)
      cashFlow: m.cashFlow - m.commissionsExpense - m.operationalExpenses - m.transfersToPortfolio
    }))
    .sort((a, b) => a.month.localeCompare(b.month));
};

export const calculateTotals = (loans: Loan[], collaborators: Collaborator[], expenses: Expense[] = [], startDate?: string, endDate?: string) => {
  const monthlyData = calculateMonthlyBreakdown(loans, collaborators, expenses);

  const filteredMonths = monthlyData.filter(m => {
    const isAfter = startDate ? m.month >= startDate.slice(0, 7) : true;
    const isBefore = endDate ? m.month <= endDate.slice(0, 7) : true;
    return isAfter && isBefore;
  });

  const totalPrincipalEmprestado = loans.reduce((acc, l) => acc + l.principal, 0);

  // Receita Projetada (Total a receber no período: P+J+M das parcelas pendentes)
  const toReceive = filteredMonths.reduce((acc, m) => acc + m.toReceive, 0);

  // Lucro Projetado (Total de Juros que serão ganhos com os contratos ativos)
  // Nota: Consideramos apenas os contratos que ainda estão ativos para a projeção
  const activeLoans = loans.filter(l => l.status === 'Ativo');
  const lucroProjetado = activeLoans.reduce((acc, l) => {
    return acc + l.installments.filter(i => i.status !== 'Pago').reduce((sum, inst) => sum + inst.interestValue, 0);
  }, 0);

  // Lucro Líquido (Realizado no período: Juros/Multas Pagos - Despesas - Comissões)
  const netProfit = filteredMonths.reduce((acc, m) => acc + m.netProfit, 0);

  // Caixa Disponível (Saldo acumulado real de todo o histórico)
  const totalCash = monthlyData.reduce((acc, m) => acc + m.cashFlow, 0);

  const penalties = filteredMonths.reduce((acc, m) => acc + m.penaltiesReceived, 0);
  const commissions = filteredMonths.reduce((acc, m) => acc + m.commissionsExpense, 0);
  const operationalExpenses = filteredMonths.reduce((acc, m) => acc + m.operationalExpenses, 0);

  const roi = totalPrincipalEmprestado > 0 ? (netProfit / totalPrincipalEmprestado) * 100 : 0;

  return {
    totalPrincipal: loans.filter(l => l.status !== 'Quitado').reduce((acc, l) => acc + l.principal, 0),
    toReceive,
    lucroProjetado,
    netProfit,
    totalCash,
    penalties,
    commissions,
    operationalExpenses,
    roi,
    monthlyData: filteredMonths,
    lastDate: filteredMonths.length > 0 ? filteredMonths[filteredMonths.length - 1].month : ''
  };
};

