export const Dashboard: React.FC<DashboardProps> = ({ loans, collaborators, clients, expenses }) => {
  const [filterStart, setFilterStart] = useState('');
  const [filterEnd, setFilterEnd] = useState('');

  const setPeriod = (months: number) => {
    const start = new Date().toISOString().slice(0, 7);
    const end = new Date();
    end.setMonth(end.getMonth() + months);
    setFilterStart(start);
    setFilterEnd(end.toISOString().slice(0, 7));
  };

  const stats = calculateTotals(loans, collaborators, expenses, filterStart, filterEnd);

  const roiStatus = stats.roi > 30 ? { label: 'Positivo', color: 'text-emerald-600 bg-emerald-50 dark:bg-emerald-950/30 dark:text-emerald-400 border-emerald-100 dark:border-emerald-900/50' } 
                  : stats.roi > 10 ? { label: 'Neutro', color: 'text-blue-600 bg-blue-50 dark:bg-blue-950/30 dark:text-blue-400 border-blue-100 dark:border-blue-900/50' }
                  : { label: 'Atenção', color: 'text-rose-600 bg-rose-50 dark:bg-rose-950/30 dark:text-rose-400 border-rose-100 dark:border-rose-900/50' };

  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const next7Days = new Date(today);
  next7Days.setDate(today.getDate() + 7);

  const upcomingInstallments = loans.reduce((acc, loan) => {
    const upcoming = loan.installments.filter(inst => {
      if (inst.status !== 'Pendente') return false;
      const dueDate = new Date(inst.dueDate + 'T12:00:00');
      return dueDate >= today && dueDate <= next7Days;
    });
    return [...acc, ...upcoming];
  }, [] as any[]);

  const upcomingCount = upcomingInstallments.length;

  return (
    <div className="space-y-8 animate-fade-in">
      {/* Alerta de Operação Próxima */}
      {upcomingCount > 0 && (
        <div className="bg-amber-50 dark:bg-amber-950/20 border border-amber-200 dark:border-amber-900/50 p-5 rounded-2xl flex flex-col sm:flex-row items-center justify-between gap-4 shadow-sm">
          <div className="flex items-center gap-4 w-full sm:w-auto">
            <div className="p-3 bg-amber-100 dark:bg-amber-900/40 rounded-xl text-amber-600 dark:text-amber-400 shrink-0">
              <BellRing className="w-6 h-6" />
            </div>
            <div>
              <p className="text-sm font-black text-amber-900 dark:text-amber-100 uppercase tracking-tight">Atenção Operacional</p>
              <p className="text-xs text-amber-700 dark:text-amber-300 font-medium">Você possui <span className="font-black underline">{upcomingCount} parcelas</span> vencendo nos próximos 7 dias.</p>
            </div>
          </div>
          <button onClick={() => setPeriod(0)} className="w-full sm:w-auto px-6 py-2.5 bg-amber-600 dark:bg-amber-700 text-white rounded-xl text-[11px] font-black uppercase hover:bg-amber-700 transition shadow-lg shadow-amber-200 dark:shadow-none">Ver Fluxo de Caixa</button>
        </div>
      )}

      {/* Filtros de Análise */}
      <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-gray-200 dark:border-slate-800 shadow-sm">
        <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-slate-100 dark:bg-slate-800 rounded-xl text-slate-500 dark:text-slate-400 shrink-0"><Filter className="w-5 h-5" /></div>
            <div>
              <h2 className="text-lg font-black text-slate-800 dark:text-slate-100 uppercase tracking-tight">Análise Temporal</h2>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Janela de visualização do caixa e lucro</p>
            </div>
          </div>
          <div className="flex flex-wrap items-center gap-3">
            <div className="grid grid-cols-2 gap-2 sm:flex">
              <button onClick={() => setPeriod(0)} className="px-4 py-2 bg-slate-50 dark:bg-slate-800 hover:bg-slate-100 text-[10px] font-black text-slate-600 dark:text-slate-300 uppercase rounded-xl border transition">Mês Atual</button>
              <button onClick={() => setPeriod(3)} className="px-4 py-2 bg-slate-50 dark:bg-slate-800 hover:bg-slate-100 text-[10px] font-black text-slate-600 dark:text-slate-300 uppercase rounded-xl border transition">Próx. 3 Meses</button>
            </div>
            <div className="flex gap-2">
              <input type="month" value={filterStart} onChange={e => setFilterStart(e.target.value)} className="px-3 py-2 bg-white dark:bg-slate-800 border dark:border-slate-700 rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-blue-500" />
              <input type="month" value={filterEnd} onChange={e => setFilterEnd(e.target.value)} className="px-3 py-2 bg-white dark:bg-slate-800 border dark:border-slate-700 rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-blue-500" />
            </div>
            <button onClick={() => {setFilterStart(''); setFilterEnd('');}} className="p-2.5 bg-slate-900 dark:bg-slate-100 dark:text-slate-900 text-white rounded-xl"><Clock className="w-4 h-4" /></button>
          </div>
        </div>
      </div>

      {/* KPI Cards — Nova Hierarquia SimpleFy v1.1 */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <KPICard 
          title="Receita Projetada" 
          value={formatCurrency(stats.toReceive)} 
          subtext="Total pendente (Principal + Juros)" 
          icon={TrendingUp} 
          color="bg-slate-400 dark:bg-slate-600" 
        />
        <KPICard 
          title="Lucro Projetado" 
          value={formatCurrency(stats.lucroProjetado)} 
          subtext="Juros brutos a receber" 
          icon={Target} 
          color="bg-indigo-500 dark:bg-indigo-600" 
        />
        <KPICard 
          title="Lucro Líquido" 
          value={formatCurrency(stats.netProfit)} 
          subtext="Juros recebidos - Despesas (Período)" 
          icon={PiggyBank} 
          color="bg-emerald-500 dark:bg-emerald-600" 
        />
        <KPICard 
          title="Caixa Disponível" 
          value={formatCurrency(stats.totalCash)} 
          subtext="Saldo real disponível para uso" 
          icon={Wallet} 
          color="bg-blue-600 dark:bg-blue-700"
          variant="highlight"
        />
      </div>

      {/* Gráfico e Cards Secundários */}
      <div className="grid grid-cols-1 xl:grid-cols-4 gap-8">
        <div className="xl:col-span-3 space-y-6">
          <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-gray-200 dark:border-slate-800 shadow-sm flex flex-col h-[400px]">
            <h3 className="text-sm font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-8 flex items-center gap-2"><Clock className="w-4 h-4" /> Evolução de Caixa</h3>
            <div className="flex-1 w-full min-h-0">
              <ResponsiveContainer width="100%" height="100%">
                <ComposedChart data={stats.monthlyData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" className="dark:stroke-slate-800" />
                  <XAxis dataKey="month" tick={{fontSize: 10, fontWeight: 700, fill: '#94a3b8'}} axisLine={false} tickLine={false} tickFormatter={(val) => val.split('-').reverse().join('/')} />
                  <YAxis tick={{fontSize: 10, fontWeight: 700, fill: '#94a3b8'}} axisLine={false} tickLine={false} />
                  <Tooltip contentStyle={{ backgroundColor: '#0f172a', border: 'none', borderRadius: '16px', color: '#f1f5f9' }} itemStyle={{ fontSize: '11px', fontWeight: 700 }} formatter={(value: number) => formatCurrency(value)} />
                  <Bar dataKey="cashFlow" name="Fluxo de Caixa" fill="#3b82f6" radius={[4, 4, 0, 0]} barSize={24} />
                  <Line type="monotone" dataKey="netProfit" name="Lucro Líquido" stroke="#10b981" strokeWidth={3} dot={{ r: 4, fill: '#10b981', stroke: '#fff', strokeWidth: 2 }} />
                </ComposedChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="bg-slate-900 dark:bg-slate-800 p-6 rounded-2xl shadow-lg flex flex-col md:flex-row items-center justify-between gap-6 border border-slate-800">
            <div className="flex items-center gap-3">
              <div className="p-2.5 bg-blue-500/10 rounded-xl"><Info className="w-5 h-5 text-blue-400" /></div>
              <div><p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Resumo Consolidado</p><p className="text-white font-bold text-sm">Visão geral do período filtrado</p></div>
            </div>
            <div className="grid grid-cols-2 sm:flex gap-8 w-full sm:w-auto">
              <div><p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">Recuperação de Multas</p><p className="text-base font-black text-emerald-400">{formatCurrency(stats.penalties)}</p></div>
              <div><p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">Despesas Operacionais</p><p className="text-base font-black text-rose-400">{formatCurrency(stats.operationalExpenses)}</p></div>
            </div>
          </div>
        </div>

        <div className="space-y-6 flex flex-col">
          <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-gray-200 dark:border-slate-800 shadow-sm flex flex-col items-center justify-center text-center space-y-6 flex-1 min-h-[200px]">
            <div className="flex flex-col items-center space-y-3"><ShieldAlert className="w-8 h-8 text-slate-300 dark:text-slate-700" /><h3 className="text-xs font-black text-gray-400 dark:text-slate-500 uppercase tracking-widest">ROI Geral</h3></div>
            <div className="space-y-2"><div className="text-5xl font-black text-slate-800 dark:text-slate-100">{stats.roi.toFixed(1)}%</div><div className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase inline-block border ${roiStatus.color}`}>{roiStatus.label}</div></div>
            <p className="text-[10px] text-gray-400 font-bold uppercase pt-6 border-t border-gray-50 dark:border-slate-800 w-full">Fechamento: {stats.lastDate ? stats.lastDate.split('-').reverse().join('/') : 'N/A'}</p>
          </div>
          <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl border border-rose-100 dark:border-slate-800 shadow-sm flex flex-col justify-between min-h-[140px]">
            <div className="flex justify-between items-start gap-4">
              <div className="p-3 rounded-xl bg-rose-500 text-white shrink-0 shadow-sm"><ShieldAlert className="w-5 h-5" /></div>
              <div className="text-right flex-1 min-w-0">
                <p className="text-[10px] font-black text-rose-400 dark:text-rose-500 uppercase tracking-widest mb-1">Alertas</p>
                <div className="text-xl font-black text-rose-700 dark:text-rose-400 truncate leading-none">{formatCurrency(stats.operationalExpenses + stats.commissions)}</div>
              </div>
            </div>
            <div className="mt-4 pt-4 border-t border-rose-50 dark:border-slate-800/50">
               <p className="text-[10px] text-rose-600 dark:text-rose-500 font-bold uppercase">Custo Operacional Total</p>
