export interface Client {
  id: string;
  name: string;
  cpf?: string;
  phone?: string;
  email?: string;
  notes?: string;
  status: 'active' | 'inactive';
}

export type CommissionType = 'fixed_per_client' | 'percentage';
export type CommissionBase = 'gross' | 'profit';

export interface Collaborator {
  id: string;
  name: string;
  type: CommissionType;
  base: CommissionBase;
  value: number; // Valor em R$ ou %
}

export interface PenaltyPattern {
  id: string;
  name: string;
  fixedRate: number; // Multa fixa %
  monthlyInterest: number; // Juros de mora % ao mês
  active: boolean;
}

export type LoanStatus = 'Ativo' | 'Inadimplente' | 'Quitado';
export type InstallmentStatus = 'Pago' | 'Atrasado' | 'Pendente';

export interface Installment {
  number: number;
  dueDate: string;
  principalValue: number;
  interestValue: number;
  penaltyValue: number;
  status: InstallmentStatus;
}

export interface AppliedPenalty {
  patternId?: string;
  fixedRate: number;
  monthlyRate: number;
  daysLate: number;
  amount: number;
  baseValue: number;
}

export interface Loan {
  id: string;
  clientId: string;
  collaboratorId: string;
  principal: number;
  monthlyInterestRate: number;
  months: number;
  startDate: string;
  status: LoanStatus;
  installments: Installment[];
  appliedPenalty?: AppliedPenalty;
}

export type ExpenseCategory = 'Operacional' | 'Pessoal' | 'Investimento';
export type ExpenseType = 'operational' | 'transfer_to_portfolio';

export interface Expense {
  id: string;
  date: string;
  amount: number;
  category: ExpenseCategory;
  description: string;
  type: ExpenseType;
  destination?: string; // ID da Carteira
}

export type PortfolioType = 'Caixa' | 'Criptomoedas' | 'Dólar' | 'Reserva' | 'Outros';

export interface Portfolio {
  id: string;
  name: string;
  type: PortfolioType;
}

export interface PortfolioMovement {
  id: string;
  portfolioId: string;
  date: string;
  amount: number;
  origin: string; // Ex: 'Despesa -> Transferência' ou 'Manual'
  description: string;
}

export interface MonthlyStats {
  month: string; // YYYY-MM
  toReceive: number;
  interestReceived: number;
  penaltiesReceived: number;
  interestTotal: number; // Projetado
  penaltiesTotal: number; // Projetado
  commissionsExpense: number;
