import React, { useState } from 'react';
import { AppSettings } from '../types';
import { Settings, DollarSign, Receipt, Layout, Save, CheckCircle2, ShieldAlert, ToggleLeft, ToggleRight } from 'lucide-react';

interface SettingsViewProps {
  settings: AppSettings;
  onSave: (settings: AppSettings) => void;
}

export const SettingsView: React.FC<SettingsViewProps> = ({ settings, onSave }) => {
  const [formData, setFormData] = useState<AppSettings>(settings);
  const [showSuccess, setShowSuccess] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.defaultPenaltyRate > 10) {
      if (!window.confirm("A multa padrão está acima de 10%. Deseja continuar?")) return;
    }
    onSave(formData);
    setShowSuccess(true);
    setTimeout(() => setShowSuccess(false), 3000);
  };

  const toggleVisibility = (key: keyof AppSettings['dashboardVisibility']) => {
    setFormData({
      ...formData,
      dashboardVisibility: {
        ...formData.dashboardVisibility,
        [key]: !formData.dashboardVisibility[key]
      }
    });
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fade-in">
      <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm">
        <div className="flex items-center gap-4 mb-8">
          <div className="p-3 bg-blue-600 rounded-2xl text-white">
            <Settings className="w-6 h-6" />
          </div>
          <div>
            <h2 className="text-xl font-black text-slate-800 dark:text-slate-100 uppercase tracking-tight">Configurações do Sistema</h2>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Controle global das regras e visualização</p>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="space-y-10">
          {/* Seção Financeira */}
          <section className="space-y-6">
            <div className="flex items-center gap-2 text-sm font-black text-slate-800 dark:text-slate-100 uppercase tracking-widest">
              <DollarSign className="w-4 h-4 text-blue-500" /> Regras Financeiras
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Multa Padrão por Atraso (%)</label>
                <input 
                  type="number" step="0.01" min="0"
                  value={formData.defaultPenaltyRate} 
                  onChange={e => setFormData({...formData, defaultPenaltyRate: Number(e.target.value)})}
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none font-black dark:text-slate-100" 
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Juros de Mora Padrão (% / mês)</label>
                <input 
                  type="number" step="0.01" min="0"
                  value={formData.defaultMoraRate} 
                  onChange={e => setFormData({...formData, defaultMoraRate: Number(e.target.value)})}
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none font-black dark:text-slate-100" 
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Regra de Cálculo</label>
                <select 
                  value={formData.interestType} 
                  onChange={e => setFormData({...formData, interestType: e.target.value as any})}
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none font-bold dark:text-slate-100"
                >
                  <option value="Simples">Juros Simples</option>
                  <option value="Composto" disabled>Juros Compostos (Em breve)</option>
                </select>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Casas Decimais</label>
                <input 
                  type="number" min="0" max="4"
                  value={formData.decimalPlaces} 
                  onChange={e => setFormData({...formData, decimalPlaces: Number(e.target.value)})}
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none font-black dark:text-slate-100" 
                />
              </div>
            </div>
            <div className="p-4 bg-blue-50 dark:bg-blue-900/10 border border-blue-100 dark:border-blue-900/30 rounded-2xl flex gap-3">
              <ShieldAlert className="w-5 h-5 text-blue-500 shrink-0" />
              <p className="text-[10px] text-blue-700 dark:text-blue-300 font-bold uppercase leading-tight">
                As regras financeiras acima serão aplicadas apenas em novos contratos. Alterações em contratos existentes devem ser feitas individualmente.
              </p>
            </div>
          </section>

          {/* Seção de Despesas */}
          <section className="space-y-6">
            <div className="flex items-center gap-2 text-sm font-black text-slate-800 dark:text-slate-100 uppercase tracking-widest">
              <Receipt className="w-4 h-4 text-emerald-500" /> Despesas & Carteira
            </div>
            <div className="space-y-4">
              <button 
                type="button"
                onClick={() => setFormData({...formData, expenseImpactsProfit: !formData.expenseImpactsProfit})}
