              </button>

              <button 
                type="button"
                onClick={() => setFormData({...formData, allowTransfers: !formData.allowTransfers})}
                className="w-full flex items-center justify-between p-4 bg-slate-50 dark:bg-slate-800 rounded-2xl border dark:border-slate-700"
              >
                <div className="text-left">
                  <p className="text-xs font-black text-slate-700 dark:text-slate-200 uppercase">Permitir Transferências</p>
                  <p className="text-[10px] text-slate-400 font-medium">Ativar fluxo de saída de Caixa para Carteiras de alocação.</p>
                </div>
                {formData.allowTransfers ? <ToggleRight className="w-8 h-8 text-emerald-600" /> : <ToggleLeft className="w-8 h-8 text-slate-300" />}
              </button>
            </div>
          </section>

          {/* Seção de Dashboard */}
          <section className="space-y-6">
            <div className="flex items-center gap-2 text-sm font-black text-slate-800 dark:text-slate-100 uppercase tracking-widest">
              <Layout className="w-4 h-4 text-orange-500" /> Visualização do Dashboard
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              <VisibilityToggle label="Receita Projetada" active={formData.dashboardVisibility.receitaProjetada} onClick={() => toggleVisibility('receitaProjetada')} />
              <VisibilityToggle label="Lucro Projetado" active={formData.dashboardVisibility.lucroProjetado} onClick={() => toggleVisibility('lucroProjetado')} />
              <VisibilityToggle label="Lucro Líquido" active={formData.dashboardVisibility.lucroLiquido} onClick={() => toggleVisibility('lucroLiquido')} />
              <VisibilityToggle label="Caixa Disponível" active={formData.dashboardVisibility.caixaDisponivel} onClick={() => toggleVisibility('caixaDisponivel')} />
              <VisibilityToggle label="ROI Geral" active={formData.dashboardVisibility.roi} onClick={() => toggleVisibility('roi')} />
            </div>
          </section>

          <div className="flex items-center justify-between pt-4 border-t border-slate-50 dark:border-slate-800">
            {showSuccess ? (
              <div className="flex items-center gap-2 text-emerald-600 font-bold text-xs uppercase animate-slide-up">
                <CheckCircle2 className="w-5 h-5" /> Configurações atualizadas!
              </div>
            ) : <div />}
            <button 
              type="submit" 
              className="px-8 py-3 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 rounded-2xl font-black uppercase text-xs shadow-xl active:scale-95 transition-all flex items-center gap-2"
            >
              <Save className="w-4 h-4" /> Salvar Configurações
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

