                  <p className="text-3xl font-black text-slate-900 dark:text-white">{formatCurrency(getPortfolioStats(selectedPortfolio.id).balance)}</p>
                </div>

                <div className="grid grid-cols-2 gap-4 mt-6">
                  <div className="p-4 bg-emerald-50 dark:bg-emerald-950/20 rounded-2xl text-left border border-emerald-100 dark:border-emerald-900/40">
                    <p className="text-[9px] font-black text-emerald-600 uppercase mb-1">Entradas</p>
                    <p className="font-black text-emerald-700 dark:text-emerald-400">{formatCurrency(getPortfolioStats(selectedPortfolio.id).totalIn)}</p>
                  </div>
                  <div className="p-4 bg-rose-50 dark:bg-rose-950/20 rounded-2xl text-left border border-rose-100 dark:border-rose-900/40">
                    <p className="text-[9px] font-black text-rose-600 uppercase mb-1">Saídas</p>
                    <p className="font-black text-rose-700 dark:text-emerald-400">{formatCurrency(getPortfolioStats(selectedPortfolio.id).totalOut)}</p>
                  </div>
                </div>

                <button 
                  onClick={() => handleOpenMovementForm(selectedPortfolio)}
                  className="w-full mt-8 py-4 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 rounded-2xl font-black uppercase text-xs flex items-center justify-center gap-2 shadow-xl"
                >
                  <Plus className="w-4 h-4" /> Lançamento Manual
                </button>
              </div>
            </div>

            <div className="lg:col-span-2">
              <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden">
                <div className="px-8 py-6 bg-slate-50 dark:bg-slate-800/50 border-b dark:border-slate-800 flex justify-between items-center">
                  <h3 className="text-sm font-black text-slate-800 dark:text-slate-100 uppercase tracking-widest flex items-center gap-2">
                    <History className="w-4 h-4 text-blue-500" /> Histórico de Movimentação
                  </h3>
                </div>
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead>
                      <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/20">
                        <th className="px-8 py-4">Data</th>
                        <th className="px-8 py-4">Origem</th>
                        <th className="px-8 py-4">Descrição</th>
                        <th className="px-8 py-4 text-right">Valor</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
                      {getPortfolioStats(selectedPortfolio.id).history.map(m => (
                        <tr key={m.id} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/30 transition-colors">
                          <td className="px-8 py-5 text-xs font-bold text-slate-600 dark:text-slate-400 whitespace-nowrap">
                            {m.date.split('-').reverse().join('/')}
                          </td>
                          <td className="px-8 py-5">
                            <span className="text-[10px] font-black uppercase text-slate-400 bg-slate-100 dark:bg-slate-800 px-2 py-0.5 rounded-lg whitespace-nowrap">
                              {m.origin}
                            </span>
                          </td>
                          <td className="px-8 py-5 text-xs font-medium text-slate-700 dark:text-slate-300">
                            {m.description}
                          </td>
                          <td className={`px-8 py-5 text-right font-black text-sm ${m.amount > 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
                            {m.amount > 0 ? '+' : ''}{formatCurrency(m.amount)}
                          </td>
                        </tr>
                      ))}
                      {getPortfolioStats(selectedPortfolio.id).history.length === 0 && (
                        <tr>
                          <td colSpan={4} className="px-8 py-16 text-center text-slate-400 italic font-bold">Nenhuma movimentação para esta carteira.</td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {(view === 'form' || view === 'movementForm') && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-3xl shadow-2xl p-8 border border-slate-200 dark:border-slate-800 animate-slide-up">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-slate-800 dark:text-slate-100 uppercase tracking-tight">
                {view === 'form' 
                  ? (editingPortfolio ? 'Editar Carteira' : 'Nova Carteira') 
                  : `Novo Lançamento: ${selectedPortfolio?.name}`}
              </h3>
              <button onClick={() => view === 'form' ? setView('grid') : setView('details')} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full">
                <X className="w-5 h-5 text-slate-400" />
              </button>
            </div>

            {view === 'form' ? (
              <form onSubmit={handlePortfolioSubmit} className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Nome da Carteira</label>
                  <input required type="text" value={portfolioForm.name} onChange={e => setPortfolioForm({...portfolioForm, name: e.target.value})} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none font-bold dark:text-slate-100" placeholder="Ex: Fundo Imobiliário" />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Tipo de Ativo</label>
                  <select value={portfolioForm.type} onChange={e => setPortfolioForm({...portfolioForm, type: e.target.value as PortfolioType})} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none font-bold dark:text-slate-100">
                    <option value="Caixa">Caixa</option>
                    <option value="Criptomoedas">Criptomoedas</option>
                    <option value="Dólar">Dólar</option>
                    <option value="Reserva">Reserva</option>
                    <option value="Outros">Outros</option>
                  </select>
                </div>
                <div className="flex gap-4 pt-4">
                  <button type="submit" className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-xs shadow-xl active:scale-95 transition-all">Salvar</button>
                  <button type="button" onClick={() => setView('grid')} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-500 rounded-2xl font-black uppercase text-xs transition-all">Cancelar</button>
                </div>
              </form>
            ) : (
              <form onSubmit={handleMovementSubmit} className="space-y-6">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Data</label>
                    <input required type="date" value={movementForm.date} onChange={e => setMovementForm({...movementForm, date: e.target.value})} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none font-bold dark:text-slate-100" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Valor (R$)</label>
                    <input required type="number" step="0.01" value={movementForm.amount} onChange={e => setMovementForm({...movementForm, amount: Number(e.target.value)})} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none font-black dark:text-slate-100" />
                    <p className="text-[9px] text-slate-400 mt-1 uppercase font-bold">Use negativo (-) para saídas</p>
                  </div>
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Descrição</label>
                  <input required type="text" value={movementForm.description} onChange={e => setMovementForm({...movementForm, description: e.target.value})} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none font-bold dark:text-slate-100" placeholder="Ex: Aporte inicial..." />
                </div>
                <div className="flex gap-4 pt-4">
                  <button type="submit" className="flex-1 py-4 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 rounded-2xl font-black uppercase text-xs shadow-xl active:scale-95 transition-all">Confirmar Lançamento</button>
                  <button type="button" onClick={() => setView('details')} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-500 rounded-2xl font-black uppercase text-xs transition-all">Cancelar</button>
                </div>
              </form>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export interface Client {
  id: string;
  name: string;
  cpf?: string;
  phone?: string;
  email?: string;
  notes?: string;
  status: 'active' | 'inactive';
}

export type CommissionType = 'fixed_per_client' | 'percentage';
export type CommissionBase = 'gross' | 'profit';

export interface Collaborator {
  id: string;
  name: string;
  type: CommissionType;
  base: CommissionBase;
  value: number; // Valor em R$ ou %
}

export interface PenaltyPattern {
  id: string;
  name: string;
  fixedRate: number; // Multa fixa %
  monthlyInterest: number; // Juros de mora % ao mês
  active: boolean;
}

export type LoanStatus = 'Ativo' | 'Inadimplente' | 'Quitado';
export type InstallmentStatus = 'Pago' | 'Atrasado' | 'Pendente';

export interface Installment {
  number: number;
  dueDate: string;
  principalValue: number;
  interestValue: number;
  penaltyValue: number;
  status: InstallmentStatus;
}

export interface AppliedPenalty {
  patternId?: string;
  fixedRate: number;
  monthlyRate: number;
  daysLate: number;
  amount: number;
  baseValue: number;
}

export interface Loan {
  id: string;
  clientId: string;
  collaboratorId: string;
  principal: number;
  monthlyInterestRate: number;
  months: number;
  startDate: string;
  status: LoanStatus;
  installments: Installment[];
  appliedPenalty?: AppliedPenalty;
}

export type ExpenseCategory = 'Operacional' | 'Pessoal' | 'Investimento';
export type ExpenseType = 'operational' | 'transfer_to_portfolio';

export interface Expense {
  id: string;
  date: string;
  amount: number;
  category: ExpenseCategory;
  description: string;
  type: ExpenseType;
  destination?: string; // ID da Carteira
}

export type PortfolioType = 'Caixa' | 'Criptomoedas' | 'Dólar' | 'Reserva' | 'Outros';

export interface Portfolio {
  id: string;
  name: string;
  type: PortfolioType;
}

export interface PortfolioMovement {
  id: string;
  portfolioId: string;
  date: string;
  amount: number;
  origin: string; // Ex: 'Despesa -> Transferência' ou 'Manual'
  description: string;
}

export interface MonthlyStats {
  month: string; // YYYY-MM
  toReceive: number;
  interestReceived: number;
  penaltiesReceived: number;
  interestTotal: number; // Projetado
  penaltiesTotal: number; // Projetado
  commissionsExpense: number;
  operationalExpenses: number;
  transfersToPortfolio: number;
  netProfit: number;
  cashFlow: number;
}

export interface UserProfile {
  name: string;
  email: string;
  businessName: string;
  currency: 'BRL' | 'USD';
  timezone: string;
  startDate: string;
  notes: string;
}

export interface AppSettings {
  defaultPenaltyRate: number;
  defaultMoraRate: number;
  interestType: 'Simples' | 'Composto';
  decimalPlaces: number;
  expenseImpactsProfit: boolean;
  allowTransfers: boolean;
  expenseCategories: string[];
  dashboardVisibility: {
    receitaProjetada: boolean;
    lucroProjetado: boolean;
    lucroLiquido: boolean;
    caixaDisponivel: boolean;
    roi: boolean;
  };
}

export enum ViewState {
  DASHBOARD = 'DASHBOARD',
  LOANS = 'LOANS',
  CLIENTS = 'CLIENTS',
  COLLABORATORS = 'COLLABORATORS',
  PENALTY_PATTERNS = 'PENALTY_PATTERNS',
  EXPENSES = 'EXPENSES',
  PORTFOLIOS = 'PORTFOLIOS',
  FORECAST = 'FORECAST',
  AI_ANALYST = 'AI_ANALYST',
  PROFILE = 'PROFILE',
  SETTINGS = 'SETTINGS',
  LOAN_CALCULATOR = 'LOAN_CALCULATOR'
}

import React, { useState, useEffect } from 'react';
import { ViewState, Loan, Client, Collaborator, PenaltyPattern, Expense, Portfolio, PortfolioMovement, UserProfile, AppSettings } from './types';
import { Dashboard } from './components/Dashboard';
import { LoanList } from './components/LoanList';
import { AIAnalyst } from './components/AIAnalyst';
import { ClientManager } from './components/ClientManager';
import { PenaltyPatternManager } from './components/PenaltyPatternManager';
import { CollaboratorManager } from './components/CollaboratorManager';
import { ExpenseManager } from './components/ExpenseManager';
import { PortfolioManager } from './components/PortfolioManager';
import { Forecast } from './components/Forecast';
import { ProfileWidget } from './components/ProfileWidget';
import { ProfileView } from './components/ProfileView';
import { SettingsView } from './components/SettingsView';
import { LoanCalculator } from './components/LoanCalculator';
import { LoanForm } from './components/LoanForm';
import { LogoText } from './components/Logo';
import { generateInstallments } from './utils/calculations';
import { 
  LayoutDashboard, 
  List, 
  Bot, 
  Users,
  Briefcase,
  Gavel,
  Sun,
  Moon,
  Menu,
  X,
  Calculator
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<ViewState>(ViewState.DASHBOARD);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const savedTheme = localStorage.getItem('theme');
    return savedTheme === 'dark' || (!savedTheme && window.matchMedia('(prefers-color-scheme: dark)').matches);
  });

  const [loans, setLoans] = useState<Loan[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [collaborators, setCollaborators] = useState<Collaborator[]>([]);
  const [penaltyPatterns, setPenaltyPatterns] = useState<PenaltyPattern[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [portfolios, setPortfolios] = useState<Portfolio[]>([]);
  const [portfolioMovements, setPortfolioMovements] = useState<PortfolioMovement[]>([]);

  // Estado para preenchimento automático do LoanForm a partir da calculadora
  const [preFilledLoan, setPreFilledLoan] = useState<Partial<Loan> | null>(null);
  const [isAddingLoan, setIsAddingLoan] = useState(false);

  // Novos estados para Perfil e Configurações
  const [userProfile, setUserProfile] = useState<UserProfile>({
    name: 'Gestor SimpleFy',
    email: 'gestor@simplefy.com',
    businessName: 'SimpleFy Management',
    currency: 'BRL',
    timezone: 'GMT-3 (Brasília)',
    startDate: new Date().toISOString().split('T')[0],
    notes: ''
  });

  const [appSettings, setAppSettings] = useState<AppSettings>({
    defaultPenaltyRate: 2,
    defaultMoraRate: 1,
    interestType: 'Simples',
    decimalPlaces: 2,
    expenseImpactsProfit: true,
    allowTransfers: true,
    expenseCategories: ['Operacional', 'Pessoal', 'Investimento'],
    dashboardVisibility: {
      receitaProjetada: true,
      lucroProjetado: true,
      lucroLiquido: true,
      caixaDisponivel: true,
      roi: true,
    }
  });

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    const savedData = localStorage.getItem('simplefy_data_v22');
    if (savedData) {
      const parsed = JSON.parse(savedData);
      setLoans(parsed.loans || []);
      setClients(parsed.clients || []);
      setCollaborators(parsed.collaborators || []);
      setPenaltyPatterns(parsed.penaltyPatterns || []);
      setExpenses(parsed.expenses || []);
      setPortfolios(parsed.portfolios || []);
      setPortfolioMovements(parsed.portfolioMovements || []);
      if (parsed.userProfile) setUserProfile(parsed.userProfile);
      if (parsed.appSettings) setAppSettings(parsed.appSettings);
    } else {
        const seedPatterns: PenaltyPattern[] = [
           { id: "P001", name: "Padrão Legal (2% + 1% mês)", fixedRate: 2, monthlyInterest: 1, active: true },
           { id: "P002", name: "Multa Atraso Curto (1% + 0.5% mês)", fixedRate: 1, monthlyInterest: 0.5, active: true }
        ];

        const seedClients: Client[] = [
          { id: 'C001', name: 'Matheus', cpf: '000.000.000-01', phone: '1191425-6969', status: 'active' },
          { id: 'C002', name: 'Bruno', cpf: '000.000.000-02', phone: '1197752-3942', status: 'active' },
          { id: 'C003', name: 'Esposa Bruno', cpf: '000.000.000-03', phone: '1197752-3942', status: 'active' },
          { id: 'C004', name: 'Bahia', cpf: '000.000.000-04', phone: '1198342-4814', status: 'active' },
        ];

        const seedCollaborators: Collaborator[] = [
          { id: 'V001', name: 'Administrador Principal', type: 'percentage', base: 'profit', value: 0 }
        ];

        const seedPortfolios: Portfolio[] = [
          { id: 'PORT001', name: 'Reserva Emergência', type: 'Reserva' },
          { id: 'PORT002', name: 'Conta Cripto', type: 'Criptomoedas' }
        ];

        const rawLoans: Partial<Loan>[] = [
          { id: 'E001', clientId: 'C001', collaboratorId: 'V001', principal: 10000, monthlyInterestRate: 10, months: 4, startDate: '2025-09-01', status: 'Ativo' },
          { id: 'E002', clientId: 'C002', collaboratorId: 'V001', principal: 8000, monthlyInterestRate: 10, months: 10, startDate: '2025-09-01', status: 'Ativo' },
          { id: 'E003', clientId: 'C002', collaboratorId: 'V001', principal: 2800, monthlyInterestRate: 25, months: 1, startDate: '2025-11-01', status: 'Ativo' },
          { id: 'E004', clientId: 'C003', collaboratorId: 'V001', principal: 5000, monthlyInterestRate: 13.5, months: 10, startDate: '2025-11-01', status: 'Ativo' },
          { id: 'E005', clientId: 'C004', collaboratorId: 'V001', principal: 5800, monthlyInterestRate: 14.66, months: 10, startDate: '2025-12-01', status: 'Ativo' },
          { id: 'E006', clientId: 'C001', collaboratorId: 'V001', principal: 1000, monthlyInterestRate: 20, months: 1, startDate: '2025-11-01', status: 'Quitado' },
          { id: 'E007', clientId: 'C001', collaboratorId: 'V001', principal: 2000, monthlyInterestRate: 22.5, months: 2, startDate: '2025-12-01', status: 'Ativo' },
        ];

        const seedLoans = rawLoans.map(l => {
          const loan = l as Loan;
          const insts = generateInstallments(loan);
          if (loan.status === 'Quitado') insts.forEach(i => i.status = 'Pago');
          return { ...loan, installments: insts };
        });

        setPenaltyPatterns(seedPatterns);
        setClients(seedClients);
        setCollaborators(seedCollaborators);
        setLoans(seedLoans);
        setExpenses([]);
        setPortfolios(seedPortfolios);
        setPortfolioMovements([]);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('simplefy_data_v22', JSON.stringify({ 
      loans, clients, collaborators, penaltyPatterns, expenses, portfolios, portfolioMovements,
      userProfile, appSettings
    }));
  }, [loans, clients, collaborators, penaltyPatterns, expenses, portfolios, portfolioMovements, userProfile, appSettings]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const handleNavClick = (tab: ViewState) => {
    setActiveTab(tab);
    setIsMobileMenuOpen(false);
    setIsAddingLoan(false);
    setPreFilledLoan(null);
  };

  const handleAddExpense = (e: Expense) => {
    setExpenses([...expenses, e]);
    if (e.type === 'transfer_to_portfolio' && e.destination) {
      const movement: PortfolioMovement = {
        id: crypto.randomUUID(),
        portfolioId: e.destination,
        date: e.date,
        amount: e.amount,
        origin: 'Transferência (Despesas)',
        description: `Ref: ${e.description}`
      };
      setPortfolioMovements(prev => [...prev, movement]);
    }
  };

  const handleUpdateExpense = (u: Expense) => {
    const oldExp = expenses.find(e => e.id === u.id);
    setExpenses(expenses.map(e => e.id === u.id ? u : e));

    setPortfolioMovements(prev => prev.filter(m => !(m.origin === 'Transferência (Despesas)' && m.description.includes(oldExp?.description || '---'))));

    if (u.type === 'transfer_to_portfolio' && u.destination) {
      const movement: PortfolioMovement = {
        id: crypto.randomUUID(),
        portfolioId: u.destination,
        date: u.date,
        amount: u.amount,
        origin: 'Transferência (Despesas)',
        description: `Ref: ${u.description}`
      };
      setPortfolioMovements(prev => [...prev, movement]);
    }
  };

  const handleDeleteExpense = (id: string) => {
    const exp = expenses.find(e => e.id === id);
    setExpenses(expenses.filter(e => e.id !== id));
    if (exp?.type === 'transfer_to_portfolio') {
      setPortfolioMovements(prev => prev.filter(m => !(m.origin === 'Transferência (Despesas)' && m.description.includes(exp.description))));
    }
  };

  const handleCalculatorConversion = (data: { principal: number; rate: number; months: number }) => {
    setPreFilledLoan({
      principal: data.principal,
      monthlyInterestRate: data.rate,
      months: data.months,
      startDate: new Date().toISOString().split('T')[0]
    });
    setActiveTab(ViewState.LOANS);
    setIsAddingLoan(true);
  };

  const getPageTitle = (tab: ViewState) => {
    switch(tab) {
      case ViewState.PORTFOLIOS: return 'Minha Carteira';
      case ViewState.EXPENSES: return 'Minhas Despesas';
      case ViewState.FORECAST: return 'Minha Previsão';
      case ViewState.PROFILE: return 'Meu Perfil';
      case ViewState.SETTINGS: return 'Configurações';
      case ViewState.LOAN_CALCULATOR: return 'Simulador de Empréstimo';
      default: return tab.replace('_', ' ');
    }
  };

  return (
    <div className="min-h-screen flex bg-gray-50 dark:bg-slate-950 overflow-x-hidden">
      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-40 lg:hidden" onClick={() => setIsMobileMenuOpen(false)} />
      )}

      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white flex flex-col transition-transform duration-300 lg:relative lg:translate-x-0 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="h-16 flex items-center justify-between px-6 border-b border-slate-800">
          <LogoText />
          <button onClick={() => setIsMobileMenuOpen(false)} className="lg:hidden p-2 text-slate-400 hover:text-white"><X className="w-6 h-6" /></button>
        </div>
        <nav className="flex-1 py-6 space-y-1 px-3 overflow-y-auto">
          <NavItem icon={LayoutDashboard} label="Dashboard" active={activeTab === ViewState.DASHBOARD} onClick={() => handleNavClick(ViewState.DASHBOARD)} />
          <NavItem icon={Calculator} label="Simulador" active={activeTab === ViewState.LOAN_CALCULATOR} onClick={() => handleNavClick(ViewState.LOAN_CALCULATOR)} color="bg-blue-600" />
          <NavItem icon={Users} label="Clientes" active={activeTab === ViewState.CLIENTS} onClick={() => handleNavClick(ViewState.CLIENTS)} />
          <NavItem icon={List} label="Contratos" active={activeTab === ViewState.LOANS} onClick={() => handleNavClick(ViewState.LOANS)} />
          <NavItem icon={Briefcase} label="Equipe" active={activeTab === ViewState.COLLABORATORS} onClick={() => handleNavClick(ViewState.COLLABORATORS)} />
          <NavItem icon={Gavel} label="Multas" active={activeTab === ViewState.PENALTY_PATTERNS} onClick={() => handleNavClick(ViewState.PENALTY_PATTERNS)} />
          <div className="pt-4 border-t border-slate-800 mt-4 opacity-30 text-[9px] font-black uppercase tracking-widest px-4">Inteligência</div>
          <NavItem icon={Bot} label="Analista IA" active={activeTab === ViewState.AI_ANALYST} onClick={() => handleNavClick(ViewState.AI_ANALYST)} color="bg-indigo-600" />
        </nav>
      </aside>

      <main className="flex-1 min-w-0 flex flex-col h-screen overflow-hidden">
        <header className="bg-white dark:bg-slate-900 shadow-sm border-b border-gray-200 dark:border-slate-800 h-16 flex items-center justify-between px-4 sm:px-8 shrink-0 z-20">
          <div className="flex items-center gap-3">
            <button onClick={() => setIsMobileMenuOpen(true)} className="lg:hidden p-2 -ml-2 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg"><Menu className="w-6 h-6" /></button>
            <h1 className="text-sm sm:text-xl font-black text-slate-800 dark:text-slate-100 uppercase tracking-tight truncate max-w-[150px] sm:max-w-none">
              {getPageTitle(activeTab)}
            </h1>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={toggleTheme} className="p-2.5 rounded-xl bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors">
              {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>
            <ProfileWidget activeTab={activeTab} onNavigate={handleNavClick} />
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 sm:p-8">
          <div className="max-w-7xl mx-auto space-y-6 pb-12">
            {activeTab === ViewState.DASHBOARD && <Dashboard loans={loans} collaborators={collaborators} clients={clients} expenses={expenses} settings={appSettings} />}
            {activeTab === ViewState.CLIENTS && <ClientManager clients={clients} loans={loans} onAddClient={c => setClients([...clients, c])} onUpdateClient={u => setClients(clients.map(c => c.id === u.id ? u : c))} onDeleteClient={id => setClients(clients.filter(c => c.id !== id))} />}
            {activeTab === ViewState.LOANS && (
              isAddingLoan ? (
                <LoanForm 
                  clients={clients} 
                  collaborators={collaborators} 
                  initialData={preFilledLoan ? (preFilledLoan as Loan) : undefined}
                  onSave={(loan) => {
                    setLoans([...loans, loan]);
                    setIsAddingLoan(false);
                    setPreFilledLoan(null);
                  }}
                  onCancel={() => {
                    setIsAddingLoan(false);
                    setPreFilledLoan(null);
                  }}
                />
              ) : (
                <div className="space-y-6">
                  <div className="flex justify-end">
                    <button onClick={() => setIsAddingLoan(true)} className="px-6 py-3 bg-blue-600 text-white rounded-2xl font-black uppercase text-xs shadow-lg hover:bg-blue-700 transition">Novo Contrato</button>
                  </div>
                  <LoanList loans={loans} clients={clients} collaborators={collaborators} penaltyPatterns={penaltyPatterns} onDelete={id => setLoans(loans.filter(l => l.id !== id))} onUpdate={u => setLoans(loans.map(l => l.id === u.id ? u : l))} />
                </div>
              )
            )}
            {activeTab === ViewState.LOAN_CALCULATOR && <LoanCalculator onConvertToLoan={handleCalculatorConversion} />}
            {activeTab === ViewState.FORECAST && <Forecast loans={loans} />}
            {activeTab === ViewState.EXPENSES && <ExpenseManager expenses={expenses} portfolios={portfolios} onAdd={handleAddExpense} onUpdate={handleUpdateExpense} onDelete={handleDeleteExpense} />}
            {activeTab === ViewState.PORTFOLIOS && <PortfolioManager portfolios={portfolios} movements={portfolioMovements} onAdd={p => setPortfolios([...portfolios, p])} onUpdate={u => setPortfolios(portfolios.map(p => p.id === u.id ? u : p))} onDelete={id => setPortfolios(portfolios.filter(p => p.id !== id))} onAddMovement={m => setPortfolioMovements([...portfolioMovements, m])} />}
            {activeTab === ViewState.COLLABORATORS && <CollaboratorManager collaborators={collaborators} onAdd={c => setCollaborators([...collaborators, c])} onUpdate={u => setCollaborators(collaborators.map(c => c.id === u.id ? u : c))} onDelete={id => setCollaborators(collaborators.filter(c => c.id !== id))} />}
            {activeTab === ViewState.PENALTY_PATTERNS && <PenaltyPatternManager patterns={penaltyPatterns} onAdd={p => setPenaltyPatterns([...penaltyPatterns, p])} onUpdate={u => setPenaltyPatterns(penaltyPatterns.map(p => p.id === u.id ? p : p))} onDelete={id => setPenaltyPatterns(penaltyPatterns.filter(p => p.id !== id))} />}
            {activeTab === ViewState.AI_ANALYST && <AIAnalyst loans={loans} clients={clients} collaborators={collaborators} />}
            {activeTab === ViewState.PROFILE && <ProfileView profile={userProfile} onSave={setUserProfile} />}
            {activeTab === ViewState.SETTINGS && <SettingsView settings={appSettings} onSave={setAppSettings} />}
          </div>
        </div>
      </main>
    </div>
  );
};

const NavItem = ({ icon: Icon, label, active, onClick, color }: any) => (
  <button onClick={onClick} className={`w-full flex items-center p-3 rounded-xl transition-all ${active ? (color || 'bg-blue-600 text-white shadow-lg') : 'text-slate-400 hover:bg-slate-800'}`}>
    <Icon className="w-5 h-5 shrink-0" />
    <span className="ml-3 font-bold text-sm truncate">{label}</span>
  </button>
);

export default App;

import React, { useState } from 'react';
import { Portfolio, PortfolioType, PortfolioMovement } from '../types';
import { formatCurrency } from '../utils/calculations';
import { 
  Plus, 
  Trash2, 
  Edit, 
  X, 
  Wallet, 
  ArrowDownLeft, 
  History,
  TrendingUp,
  ArrowUpCircle,
  ArrowDownCircle,
  FileText,
  CalendarDays,
  Tag
} from 'lucide-react';

interface Props {
  portfolios: Portfolio[];
  movements: PortfolioMovement[];
  onAdd: (p: Portfolio) => void;
  onUpdate: (p: Portfolio) => void;
  onDelete: (id: string) => void;
  onAddMovement: (m: PortfolioMovement) => void;
}

export const PortfolioManager: React.FC<Props> = ({ portfolios, movements, onAdd, onUpdate, onDelete, onAddMovement }) => {
  const [view, setView] = useState<'grid' | 'details' | 'form' | 'movementForm'>('grid');
  const [selectedPortfolio, setSelectedPortfolio] = useState<Portfolio | null>(null);
  const [editingPortfolio, setEditingPortfolio] = useState<Portfolio | null>(null);

  // Estado auxiliar para o tipo de movimentação no form (Entrada/Saída)
  const [movementType, setMovementType] = useState<'in' | 'out'>('in');

  const [portfolioForm, setPortfolioForm] = useState<Portfolio>({
    id: '',
    name: '',
    type: 'Caixa'
  });

  const [movementForm, setMovementForm] = useState<PortfolioMovement>({
    id: '',
    portfolioId: '',
    date: new Date().toISOString().split('T')[0],
    amount: 0,
    origin: 'Aporte Manual',
    description: ''
  });

  const getPortfolioStats = (id: string) => {
    const pMovements = movements.filter(m => m.portfolioId === id);
    const inflows = pMovements.filter(m => m.amount > 0).reduce((acc, m) => acc + m.amount, 0);
    const outflows = pMovements.filter(m => m.amount < 0).reduce((acc, m) => acc + Math.abs(m.amount), 0);
    return {
      balance: inflows - outflows,
      totalIn: inflows,
      totalOut: outflows,
      history: pMovements.sort((a, b) => b.date.localeCompare(a.date))
    };
  };

  const handleOpenPortfolioForm = (p?: Portfolio) => {
    if (p) {
      setPortfolioForm(p);
      setEditingPortfolio(p);
    } else {
      setPortfolioForm({ id: crypto.randomUUID(), name: '', type: 'Reserva' });
      setEditingPortfolio(null);
    }
    setView('form');
  };

  const handleOpenMovementForm = (p: Portfolio) => {
    setMovementForm({
      id: crypto.randomUUID(),
      portfolioId: p.id,
      date: new Date().toISOString().split('T')[0],
      amount: 0,
      origin: 'Aporte Manual',
      description: ''
    });
    setMovementType('in');
    setView('movementForm');
  };

  const handlePortfolioSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingPortfolio) onUpdate(portfolioForm);
    else onAdd(portfolioForm);
    setView('grid');
  };

  const handleMovementSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Garante o sinal correto baseado no tipo selecionado
    const finalAmount = movementType === 'in' 
      ? Math.abs(movementForm.amount) 
      : -Math.abs(movementForm.amount);

    onAddMovement({
      ...movementForm,
      amount: finalAmount
    });
    setView('details');
  };

  const handleDeletePortfolio = (id: string) => {
    const stats = getPortfolioStats(id);
    if (stats.balance !== 0) {
      alert("Não é possível excluir uma carteira com saldo ativo. Zere o saldo antes de excluir.");
      return;
    }
    if (window.confirm("Deseja realmente excluir esta carteira?")) {
      onDelete(id);
      setView('grid');
    }
  };

  const sortedGlobalMovements = [...movements].sort((a, b) => b.date.localeCompare(a.date));

  return (
    <div className="space-y-8 animate-fade-in">
      {view === 'grid' && (
        <>
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-white dark:bg-slate-900 p-5 rounded-3xl border border-slate-200 dark:border-slate-800 gap-4">
            <div>
              <h2 className="text-xl font-black text-slate-800 dark:text-slate-100 uppercase tracking-tight">Carteiras de Alocação</h2>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Controle de balanço e ativos externos</p>
            </div>
            <button onClick={() => handleOpenPortfolioForm()} className="w-full md:w-auto px-5 py-2.5 bg-blue-600 text-white rounded-2xl font-black uppercase text-[10px] flex items-center justify-center gap-2 shadow-lg shadow-blue-200 dark:shadow-none hover:bg-blue-700 transition">
              <Plus className="w-4 h-4" /> Nova Carteira
            </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {portfolios.map(p => {
              const stats = getPortfolioStats(p.id);
              return (
                <div key={p.id} className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm hover:shadow-md transition-all group flex flex-col justify-between min-h-[220px]">
                  <div className="flex justify-between items-start">
                    <div className="p-3 bg-slate-100 dark:bg-slate-800 rounded-2xl group-hover:bg-blue-600 group-hover:text-white transition-colors">
                      <Wallet className="w-6 h-6" />
                    </div>
                    <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => handleOpenPortfolioForm(p)} className="p-2 text-slate-400 hover:text-blue-500"><Edit className="w-4 h-4" /></button>
                      <button onClick={() => handleDeletePortfolio(p.id)} className="p-2 text-slate-400 hover:text-rose-600"><Trash2 className="w-4 h-4" /></button>
                    </div>
                  </div>

                  <div className="mt-6">
                    <h3 className="font-black text-slate-800 dark:text-slate-100 text-lg uppercase tracking-tight truncate" title={p.name}>{p.name}</h3>
                    <span className="text-[10px] px-2 py-0.5 bg-slate-100 dark:bg-slate-800 text-slate-500 rounded-lg font-black uppercase tracking-widest">{p.type}</span>
                  </div>

                  <div className="mt-8 pt-4 border-t border-slate-50 dark:border-slate-800 flex justify-between items-end">
                    <div>
                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Saldo Atual</p>
                      <p className={`text-xl font-black ${stats.balance >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>{formatCurrency(stats.balance)}</p>
                    </div>
                    <button 
                      onClick={() => { setSelectedPortfolio(p); setView('details'); }} 
                      className="px-4 py-2 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 text-[10px] font-black uppercase rounded-xl hover:scale-105 transition active:scale-95"
                    >
                      Detalhes
                    </button>
                  </div>
                </div>
              );
            })}
            {portfolios.length === 0 && (
              <div className="col-span-full py-16 text-center bg-white dark:bg-slate-900 rounded-3xl border-2 border-dashed border-slate-200 dark:border-slate-800">
                <p className="text-slate-400 font-bold italic">Nenhuma carteira configurada.</p>
              </div>
            )}
          </div>

          <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
            <div className="px-8 py-6 bg-slate-50 dark:bg-slate-800/50 border-b dark:border-slate-800 flex justify-between items-center">
              <div>
                <h3 className="text-sm font-black text-slate-800 dark:text-slate-100 uppercase tracking-widest flex items-center gap-2">
                  <History className="w-4 h-4 text-blue-500" /> Histórico de Movimentações Consolidado
                </h3>
                <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest mt-1">Todas as carteiras em ordem cronológica</p>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/20">
                    <th className="px-8 py-4">Data</th>
                    <th className="px-8 py-4">Carteira</th>
                    <th className="px-8 py-4">Origem</th>
                    <th className="px-8 py-4">Descrição</th>
                    <th className="px-8 py-4 text-right">Valor</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
                  {sortedGlobalMovements.slice(0, 15).map(m => {
                    const portfolio = portfolios.find(p => p.id === m.portfolioId);
                    return (
                      <tr key={m.id} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/30 transition-colors">
                        <td className="px-8 py-5 text-xs font-bold text-slate-600 dark:text-slate-400 whitespace-nowrap">
                          {m.date.split('-').reverse().join('/')}
                        </td>
                        <td className="px-8 py-5">
                          <div className="flex flex-col">
                            <span className="text-xs font-bold text-slate-800 dark:text-slate-200">{portfolio?.name || '---'}</span>
                            <span className="text-[9px] font-black uppercase text-blue-400">{portfolio?.type}</span>
                          </div>
                        </td>
                        <td className="px-8 py-5">
                          <span className="text-[10px] font-black uppercase text-slate-400 bg-slate-100 dark:bg-slate-800 px-2 py-0.5 rounded-lg whitespace-nowrap">
                            {m.origin}
                          </span>
                        </td>
                        <td className="px-8 py-5 text-xs font-medium text-slate-700 dark:text-slate-300">
                          {m.description}
                        </td>
                        <td className={`px-8 py-5 text-right font-black text-sm ${m.amount > 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
                          {m.amount > 0 ? '+' : ''}{formatCurrency(m.amount)}
                        </td>
                      </tr>
                    );
                  })}
                  {sortedGlobalMovements.length === 0 && (
                    <tr>
                      <td colSpan={5} className="px-8 py-16 text-center text-slate-400 italic font-bold">Nenhuma movimentação registrada no sistema.</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </>
      )}

      {view === 'details' && selectedPortfolio && (
        <div className="space-y-6 animate-slide-up">
          <button onClick={() => setView('grid')} className="flex items-center gap-2 text-[10px] font-black uppercase text-slate-400 hover:text-slate-800 transition">
            <ArrowDownLeft className="w-4 h-4" /> Voltar para Carteiras
          </button>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <div className="lg:col-span-1 space-y-6">
              <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm text-center">
                <div className="w-16 h-16 bg-blue-600 text-white rounded-2xl flex items-center justify-center mx-auto mb-6">
                   <Wallet className="w-8 h-8" />
                </div>
                <h2 className="text-2xl font-black text-slate-800 dark:text-slate-100 uppercase tracking-tight">{selectedPortfolio.name}</h2>
                <span className="text-[10px] font-black uppercase text-slate-400 bg-slate-100 dark:bg-slate-800 px-3 py-1 rounded-full">{selectedPortfolio.type}</span>

                <div className="mt-10 p-6 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border border-slate-100 dark:border-slate-700">
                  <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Saldo Consolidado</p>
                  <p className="text-3xl font-black text-slate-900 dark:text-white">{formatCurrency(getPortfolioStats(selectedPortfolio.id).balance)}</p>
                </div>

                <div className="grid grid-cols-2 gap-4 mt-6">
                  <div className="p-4 bg-emerald-50 dark:bg-emerald-950/20 rounded-2xl text-left border border-emerald-100 dark:border-emerald-900/40">
                    <p className="text-[9px] font-black text-emerald-600 uppercase mb-1">Entradas</p>
                    <p className="font-black text-emerald-700 dark:text-emerald-400">{formatCurrency(getPortfolioStats(selectedPortfolio.id).totalIn)}</p>
                  </div>
                  <div className="p-4 bg-rose-50 dark:bg-rose-950/20 rounded-2xl text-left border border-rose-100 dark:border-rose-900/40">
                    <p className="text-[9px] font-black text-rose-600 uppercase mb-1">Saídas</p>
                    <p className="font-black text-rose-700 dark:text-rose-400">{formatCurrency(getPortfolioStats(selectedPortfolio.id).totalOut)}</p>
                  </div>
                </div>

                <button 
                  onClick={() => handleOpenMovementForm(selectedPortfolio)}
                  className="w-full mt-8 py-4 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 rounded-2xl font-black uppercase text-xs flex items-center justify-center gap-2 shadow-xl"
                >
                  <Plus className="w-4 h-4" /> Registrar Movimentação
                </button>
              </div>
            </div>

            <div className="lg:col-span-2">
              <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden">
                <div className="px-8 py-6 bg-slate-50 dark:bg-slate-800/50 border-b dark:border-slate-800 flex justify-between items-center">
                  <h3 className="text-sm font-black text-slate-800 dark:text-slate-100 uppercase tracking-widest flex items-center gap-2">
                    <History className="w-4 h-4 text-blue-500" /> Histórico Detalhado
                  </h3>
                </div>
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead>
                      <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/20">
                        <th className="px-8 py-4">Data</th>
                        <th className="px-8 py-4">Origem</th>
                        <th className="px-8 py-4">Descrição</th>
                        <th className="px-8 py-4 text-right">Valor</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
                      {getPortfolioStats(selectedPortfolio.id).history.map(m => (
                        <tr key={m.id} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/30 transition-colors">
                          <td className="px-8 py-5 text-xs font-bold text-slate-600 dark:text-slate-400 whitespace-nowrap">
                            {m.date.split('-').reverse().join('/')}
                          </td>
                          <td className="px-8 py-5">
                            <span className="text-[10px] font-black uppercase text-slate-400 bg-slate-100 dark:bg-slate-800 px-2 py-0.5 rounded-lg whitespace-nowrap">
                              {m.origin}
                            </span>
                          </td>
                          <td className="px-8 py-5 text-xs font-medium text-slate-700 dark:text-slate-300">
                            {m.description}
                          </td>
                          <td className={`px-8 py-5 text-right font-black text-sm ${m.amount > 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
                            {m.amount > 0 ? '+' : ''}{formatCurrency(m.amount)}
                          </td>
                        </tr>
                      ))}
                      {getPortfolioStats(selectedPortfolio.id).history.length === 0 && (
                        <tr>
                          <td colSpan={4} className="px-8 py-16 text-center text-slate-400 italic font-bold">Nenhuma movimentação para esta carteira.</td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {(view === 'form' || view === 'movementForm') && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-3xl shadow-2xl p-8 border border-slate-200 dark:border-slate-800 animate-slide-up">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-xl font-black text-slate-800 dark:text-slate-100 uppercase tracking-tight">
                {view === 'form' 
                  ? (editingPortfolio ? 'Editar Carteira' : 'Nova Carteira') 
                  : `Lançamento: ${selectedPortfolio?.name}`}
              </h3>
              <button onClick={() => view === 'form' ? setView('grid') : setView('details')} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full">
                <X className="w-5 h-5 text-slate-400" />
              </button>
            </div>

            {view === 'form' ? (
              <form onSubmit={handlePortfolioSubmit} className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Nome da Carteira</label>
                  <input required type="text" value={portfolioForm.name} onChange={e => setPortfolioForm({...portfolioForm, name: e.target.value})} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none font-bold dark:text-slate-100" placeholder="Ex: Fundo Imobiliário" />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Tipo de Ativo</label>
                  <select value={portfolioForm.type} onChange={e => setPortfolioForm({...portfolioForm, type: e.target.value as PortfolioType})} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none font-bold dark:text-slate-100">
                    <option value="Caixa">Caixa</option>
                    <option value="Criptomoedas">Criptomoedas</option>
                    <option value="Dólar">Dólar</option>
                    <option value="Reserva">Reserva</option>
                    <option value="Outros">Outros</option>
                  </select>
                </div>
                <div className="flex gap-4 pt-4">
                  <button type="submit" className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-xs shadow-xl active:scale-95 transition-all">Salvar</button>
                  <button type="button" onClick={() => setView('grid')} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-500 rounded-2xl font-black uppercase text-xs transition-all">Cancelar</button>
