                <div className="flex gap-4 pt-4">
                  <button type="submit" className="flex-1 py-4 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 rounded-2xl font-black uppercase text-xs shadow-xl active:scale-95 transition-all">Confirmar Registro</button>
                  <button type="button" onClick={() => setView('details')} className="flex-1 py-4 bg-slate-100 dark:bg-slate-800 text-slate-500 rounded-2xl font-black uppercase text-xs transition-all">Cancelar</button>
                </div>
              </form>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

