import React, { useState } from 'react';
import { Loan, Client, Collaborator, LoanStatus, InstallmentStatus, PenaltyPattern, Installment } from '../types';
import { formatCurrency, calculatePenalty } from '../utils/calculations';
import { 
  Trash2, ChevronDown, ChevronUp, Gavel, CheckCircle2, AlertTriangle, Clock, ListOrdered, Wallet, Receipt
} from 'lucide-react';

interface Props {
  loans: Loan[];
  clients: Client[];
  collaborators: Collaborator[];
  penaltyPatterns: PenaltyPattern[];
  onDelete: (id: string) => void;
  onUpdate: (loan: Loan) => void;
}

export const LoanList: React.FC<Props> = ({ loans, clients, collaborators, penaltyPatterns, onDelete, onUpdate }) => {
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [statusFilter, setStatusFilter] = useState<'all' | LoanStatus>('all');
  const [penaltyModal, setPenaltyModal] = useState<{loanId: string, installmentIdx: number, days: number, patternId: string} | null>(null);

  const filteredLoans = loans.filter(l => statusFilter === 'all' ? true : l.status === statusFilter);

  const handleUpdateLoanStatus = (loan: Loan, status: LoanStatus) => {
    onUpdate({ ...loan, status });
  };

  const handleUpdateInstallmentStatus = (loan: Loan, idx: number, status: InstallmentStatus) => {
    const newInstallments = [...loan.installments];
    newInstallments[idx] = { ...newInstallments[idx], status };
    onUpdate({ ...loan, installments: newInstallments });
  };

  const handleApplyPenalty = () => {
    if (!penaltyModal) return;
    const loan = loans.find(l => l.id === penaltyModal.loanId);
    const pattern = penaltyPatterns.find(p => p.id === penaltyModal.patternId);
    if (!loan || !pattern) return;

    const installment = loan.installments[penaltyModal.installmentIdx];
    const amount = calculatePenalty(installment.principalValue, pattern.fixedRate, pattern.monthlyInterest, penaltyModal.days);

    const newInstallments = [...loan.installments];
    newInstallments[penaltyModal.installmentIdx] = {
      ...installment,
      penaltyValue: amount,
      status: 'Atrasado'
    };

    onUpdate({ ...loan, installments: newInstallments });
    setPenaltyModal(null);
  };

  const renderInstallments = (loan: Loan) => (
    <div className="mt-8 border-t border-slate-100 dark:border-slate-800 pt-6">
      <div className="flex items-center gap-2 mb-4">
        <ListOrdered className="w-4 h-4 text-slate-400 dark:text-slate-500" />
        <h5 className="text-[10px] font-black uppercase text-slate-400 dark:text-slate-500 tracking-widest">Parcelas do Contrato (Unitário)</h5>
      </div>
      <div className="overflow-hidden border border-slate-100 dark:border-slate-800 rounded-2xl">
        <table className="w-full text-left text-xs">
          <thead>
            <tr className="bg-slate-50 dark:bg-slate-800/50 text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest border-b border-slate-100 dark:border-slate-800">
              <th className="px-4 py-3">#</th>
              <th className="px-4 py-3">Vencimento</th>
              <th className="px-4 py-3">Principal</th>
              <th className="px-4 py-3">Juros</th>
              <th className="px-4 py-3">Multa</th>
              <th className="px-4 py-3">Status</th>
              <th className="px-4 py-3 text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
            {loan.installments.map((inst, idx) => (
              <tr key={idx} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/30">
                <td className="px-4 py-3 font-bold text-slate-400 dark:text-slate-500">{inst.number}/{loan.months}</td>
                <td className="px-4 py-3 dark:text-slate-300">{inst.dueDate.split('-').reverse().join('/')}</td>
                <td className="px-4 py-3 dark:text-slate-300">{formatCurrency(inst.principalValue)}</td>
                <td className="px-4 py-3 text-blue-600 dark:text-blue-400">{formatCurrency(inst.interestValue)}</td>
                <td className="px-4 py-3 text-rose-600 dark:text-rose-400 font-bold">{inst.penaltyValue > 0 ? formatCurrency(inst.penaltyValue) : '---'}</td>
                <td className="px-4 py-3">
                  <span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase border ${
                    inst.status === 'Pago' ? 'bg-emerald-50 text-emerald-600 border-emerald-100 dark:bg-emerald-950/30 dark:text-emerald-400 dark:border-emerald-900/50' :
                    inst.status === 'Atrasado' ? 'bg-rose-50 text-rose-600 border-rose-100 dark:bg-rose-950/30 dark:text-rose-400 dark:border-rose-900/50' : 
                    'bg-slate-50 text-slate-500 border-slate-100 dark:bg-slate-800 dark:text-slate-400 dark:border-slate-700'
                  }`}>
                    {inst.status}
                  </span>
                </td>
                <td className="px-4 py-3 text-right space-x-1">
                   {(['Pago', 'Atrasado', 'Pendente'] as InstallmentStatus[]).map(s => (
                     <button 
                      key={s} 
                      onClick={() => handleUpdateInstallmentStatus(loan, idx, s)}
                      className={`p-1.5 rounded-lg border transition-all ${inst.status === s ? 'bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 border-slate-900 dark:border-slate-100' : 'bg-white dark:bg-slate-800 text-slate-400 dark:text-slate-500 border-slate-200 dark:border-slate-700 hover:border-slate-300 dark:hover:border-slate-600'}`}
                      title={`Marcar como ${s}`}
                     >
                       {s === 'Pago' && <CheckCircle2 className="w-3.5 h-3.5" />}
                       {s === 'Atrasado' && <AlertTriangle className="w-3.5 h-3.5" />}
                       {s === 'Pendente' && <Clock className="w-3.5 h-3.5" />}
                     </button>
                   ))}
                   <button 
                    onClick={() => setPenaltyModal({loanId: loan.id, installmentIdx: idx, days: 30, patternId: ''})}
                    className="p-1.5 rounded-lg border border-rose-100 dark:border-rose-900 text-rose-600 dark:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-950/30"
                    title="Aplicar Multa"
                   >
                     <Gavel className="w-3.5 h-3.5" />
                   </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  const renderDetails = (loan: Loan) => {
    const totalPrincipal = loan.principal;
    const totalInterest = (loan.principal * (loan.monthlyInterestRate / 100)) * loan.months;
    const totalPenalty = loan.installments.reduce((acc, i) => acc + i.penaltyValue, 0);
    const totalRevenue = totalPrincipal + totalInterest + totalPenalty;
    const totalPaid = loan.installments.reduce((acc, i) => {
      return i.status === 'Pago' ? acc + i.principalValue + i.interestValue + i.penaltyValue : acc;
    }, 0);
    const outstandingBalance = totalRevenue - totalPaid;
    const totalProfit = totalInterest + totalPenalty;

    return (
      <div className="mt-6 space-y-6 animate-fade-in">
        {/* Resumo Consolidado no Topo dos Detalhes */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="bg-slate-50 dark:bg-slate-800 p-4 rounded-2xl border border-slate-100 dark:border-slate-700">
            <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Total de Juros</p>
            <p className="text-base font-black text-blue-600 dark:text-blue-400">{formatCurrency(totalInterest)}</p>
          </div>
          <div className="bg-slate-50 dark:bg-slate-800 p-4 rounded-2xl border border-slate-100 dark:border-slate-700">
            <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Multas Aplicadas</p>
            <p className="text-base font-black text-rose-600 dark:text-rose-400">{formatCurrency(totalPenalty)}</p>
          </div>
          <div className="bg-emerald-50 dark:bg-emerald-950/20 p-4 rounded-2xl border border-emerald-100 dark:border-emerald-900/40">
            <p className="text-[9px] font-black text-emerald-600 uppercase mb-1">Total Já Pago</p>
            <p className="text-base font-black text-emerald-700 dark:text-emerald-400">{formatCurrency(totalPaid)}</p>
          </div>
          <div className="bg-blue-600 p-4 rounded-2xl shadow-lg shadow-blue-200 dark:shadow-none">
            <p className="text-[9px] font-black text-white/70 uppercase mb-1">Saldo Devedor Atual</p>
            <p className="text-base font-black text-white">{formatCurrency(outstandingBalance)}</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
           <div className="bg-slate-50 dark:bg-slate-800 p-5 rounded-2xl border border-slate-200 dark:border-slate-700">
              <h5 className="text-[10px] font-black uppercase text-slate-400 dark:text-slate-500 mb-4 tracking-widest">Status do Contrato</h5>
              <div className="flex flex-wrap gap-2">
                 {(['Ativo', 'Inadimplente', 'Quitado'] as LoanStatus[]).map(s => (
                   <button 
                    key={s} 
                    onClick={() => handleUpdateLoanStatus(loan, s)}
                    className={`px-4 py-2 rounded-xl text-xs font-bold transition-all border ${
                      loan.status === s ? 'bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 border-slate-900 dark:border-slate-100 shadow-md' : 'bg-white dark:bg-slate-900 text-slate-600 dark:text-slate-400 border-slate-200 dark:border-slate-700 hover:border-slate-300 dark:hover:border-slate-600'
                    }`}
                   >
                     {s}
                   </button>
                 ))}
              </div>
           </div>
           <div className="bg-slate-100 dark:bg-slate-800/80 p-5 rounded-2xl border border-slate-200 dark:border-slate-700 flex items-center justify-between">
              <div>
                <h5 className="text-[10px] font-black uppercase text-slate-500 mb-1 tracking-widest">Lucro Total do Contrato</h5>
                <div className="text-2xl font-black text-slate-900 dark:text-white">{formatCurrency(totalProfit)}</div>
              </div>
              <div className="text-right">
                <p className="text-[10px] text-emerald-600 font-black uppercase">{((totalProfit / totalPrincipal) * 100).toFixed(1)}%</p>
                <p className="text-[8px] text-slate-400 font-bold uppercase">ROI Final</p>
              </div>
           </div>
        </div>

        {renderInstallments(loan)}

        <div className="bg-slate-900 dark:bg-slate-800 text-white p-6 rounded-2xl shadow-xl border border-slate-800 dark:border-slate-700">
           <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
              <div>
                <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Principal</p>
                <p className="text-lg font-bold">{formatCurrency(totalPrincipal)}</p>
              </div>
              <div>
                <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Juros Fixos</p>
                <p className="text-lg font-bold text-blue-400">{formatCurrency(totalInterest)}</p>
              </div>
              <div>
                <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Multas</p>
                <p className="text-lg font-bold text-rose-400">{formatCurrency(totalPenalty)}</p>
              </div>
              <div className="text-right">
                <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Receita Total Bruta</p>
                <p className="text-2xl font-black text-white">{formatCurrency(totalRevenue)}</p>
              </div>
           </div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-6">
      <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 flex gap-4 overflow-x-auto no-scrollbar">
        {(['all', 'Ativo', 'Inadimplente', 'Quitado'] as const).map(s => (
          <button key={s} onClick={() => setStatusFilter(s)} className={`px-5 py-2 rounded-xl text-xs font-bold transition-all border whitespace-nowrap ${statusFilter === s ? 'bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 border-slate-900 dark:border-slate-100' : 'bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-400 border-slate-200 dark:border-slate-700 hover:border-slate-300 dark:hover:border-slate-600'}`}>
            {s === 'all' ? 'Todos Contratos' : s}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 gap-4">
        {filteredLoans.map(loan => {
           const client = clients.find(c => c.id === loan.clientId);
           const isExp = expandedId === loan.id;
           return (
             <div key={loan.id} className={`bg-white dark:bg-slate-900 p-5 rounded-2xl border transition-all ${isExp ? 'border-blue-300 dark:border-blue-700 ring-4 ring-blue-50 dark:ring-blue-900/20 shadow-lg' : 'border-slate-200 dark:border-slate-800'}`}>
                <div className="flex justify-between items-center">
                   <div className="flex items-center gap-4">
                      <div className="w-10 h-10 bg-slate-100 dark:bg-slate-800 rounded-xl flex items-center justify-center font-bold text-slate-600 dark:text-slate-300">{client?.name.charAt(0)}</div>
                      <div>
                         <h4 className="font-black text-slate-800 dark:text-slate-100 uppercase tracking-tighter">{client?.name || 'Cliente'}</h4>
                         <p className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase font-mono">{loan.id} | {loan.startDate}</p>
                      </div>
                   </div>
                   <div className="flex items-center gap-4">
                      <span className={`px-2.5 py-1 rounded-lg text-[10px] font-black uppercase border ${
                        loan.status === 'Ativo' ? 'bg-emerald-50 text-emerald-600 border-emerald-100 dark:bg-emerald-950/30 dark:text-emerald-400 dark:border-emerald-900/50' : 
                        loan.status === 'Quitado' ? 'bg-slate-50 text-slate-500 border-slate-100 dark:bg-slate-800 dark:text-slate-400 dark:border-slate-700' : 
                        'bg-rose-50 text-rose-600 border-rose-100 dark:bg-rose-950/30 dark:text-rose-400 dark:border-rose-900/50'
                      }`}>
                        {loan.status}
                      </span>
                      <button onClick={() => setExpandedId(isExp ? null : loan.id)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg text-slate-400">
                         {isExp ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}
                      </button>
                   </div>
                </div>
                {isExp && renderDetails(loan)}
             </div>
           );
        })}
      </div>

      {penaltyModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-3xl shadow-2xl p-8 border border-slate-200 dark:border-slate-800 animate-slide-up">
            <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100 mb-6 tracking-tighter">Multa na Parcela {penaltyModal.installmentIdx + 1}</h3>
            <div className="space-y-6">
               <div>
                  <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Padrão de Cálculo</label>
                  <select value={penaltyModal.patternId} onChange={e => setPenaltyModal({...penaltyModal, patternId: e.target.value})} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl font-bold outline-none focus:ring-2 focus:ring-rose-500 dark:text-slate-200">
                    <option value="">Selecione...</option>
                    {penaltyPatterns.filter(p => p.active).map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                  </select>
               </div>
               <div>
                  <label className="block text-xs font-black text-slate-400 dark:text-slate-500 uppercase mb-2">Dias de Atraso (Manual)</label>
                  <input type="number" value={penaltyModal.days} onChange={e => setPenaltyModal({...penaltyModal, days: Number(e.target.value)})} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl font-bold outline-none focus:ring-2 focus:ring-rose-500 dark:text-slate-200" />
               </div>
               <div className="flex gap-4">
                  <button onClick={() => setPenaltyModal(null)} className="flex-1 py-4 border dark:border-slate-700 rounded-xl font-black uppercase text-xs text-slate-400 dark:text-slate-500">Cancelar</button>
                  <button onClick={handleApplyPenalty} className="flex-1 py-4 bg-rose-600 text-white rounded-xl font-black uppercase text-xs shadow-lg shadow-rose-200 dark:shadow-none">Confirmar Multa</button>
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Loan, Client, Collaborator, LoanStatus } from '../types';
import { PlusCircle, Calculator, Save, AlertTriangle, ArrowRight, UserPlus, Users } from 'lucide-react';
import { formatCurrency, generateInstallments } from '../utils/calculations';

interface LoanFormProps {
  onSave: (loan: Loan, newClient?: Client) => void;
  onCancel: () => void;
  clients: Client[];
  collaborators: Collaborator[];
  initialData?: Loan;
}

export const LoanForm: React.FC<LoanFormProps> = ({ onSave, onCancel, clients, collaborators, initialData }) => {
  const isEditMode = !!initialData;
  const [isNewClientMode, setIsNewClientMode] = useState(clients.length === 0);

  const [formData, setFormData] = useState({
    clientId: initialData?.clientId || (clients.length > 0 ? clients[0].id : ''),
    collaboratorId: initialData?.collaboratorId || (collaborators.length > 0 ? collaborators[0].id : ''),
    principal: initialData?.principal || 3000,
    monthlyInterestRate: initialData?.monthlyInterestRate || 20.0,
    months: initialData?.months || 10,
    startDate: initialData?.startDate || new Date().toISOString().split('T')[0],
    status: initialData?.status || 'Ativo'
  });

  // Estado para criação de novo cliente simultaneamente
  const [newClientData, setNewClientData] = useState<Partial<Client>>({
    name: '',
    cpf: '',
    phone: '',
    status: 'active'
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        clientId: initialData.clientId,
        collaboratorId: initialData.collaboratorId,
        principal: initialData.principal,
        monthlyInterestRate: initialData.monthlyInterestRate,
        months: initialData.months,
        startDate: initialData.startDate,
        status: initialData.status
      });
    }
  }, [initialData]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let finalClientId = formData.clientId;
    let createdClient: Client | undefined = undefined;

    if (isNewClientMode) {
      if (!newClientData.name) {
        alert("Por favor, preencha o nome do novo cliente.");
        return;
      }
      createdClient = {
        id: `C${Date.now()}`, // ID temporário que o App.tsx pode ajustar se preferir
        name: newClientData.name,
        cpf: newClientData.cpf || '',
        phone: newClientData.phone || '',
        status: 'active',
        notes: 'Cadastrado via formulário de contrato'
      };
      finalClientId = createdClient.id;
    }

    const loanData: Partial<Loan> = {
      principal: Number(formData.principal),
      monthlyInterestRate: Number(formData.monthlyInterestRate),
      months: Number(formData.months),
      startDate: formData.startDate,
    };

    const installments = generateInstallments(loanData);

    const loanToSave: Loan = {
      id: initialData ? initialData.id : crypto.randomUUID(),
      clientId: finalClientId,
      collaboratorId: formData.collaboratorId,
      principal: Number(formData.principal),
      monthlyInterestRate: Number(formData.monthlyInterestRate),
      months: Number(formData.months),
      startDate: formData.startDate,
      status: formData.status as LoanStatus,
      installments: installments
    };

    onSave(loanToSave, createdClient);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleNewClientChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setNewClientData(prev => ({ ...prev, [name]: value }));
  };

  const currentMonthlyInterest = Number(formData.principal) * (Number(formData.monthlyInterestRate) / 100);
  const currentTotalInterest = currentMonthlyInterest * Number(formData.months);
  const currentTotalRevenue = Number(formData.principal) + currentTotalInterest;

  const initialMonthlyInterest = initialData ? initialData.principal * (initialData.monthlyInterestRate / 100) : 0;
  const initialTotalRevenue = initialData ? initialData.principal + (initialMonthlyInterest * initialData.months) : 0;
  const deltaRevenue = currentTotalRevenue - initialTotalRevenue;

  return (
    <div className="bg-white dark:bg-slate-900 p-6 sm:p-8 rounded-3xl shadow-xl border border-gray-200 dark:border-slate-800 max-w-5xl mx-auto animate-fade-in">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8 border-b border-gray-100 dark:border-slate-800 pb-6">
        <div className="flex items-center gap-3">
          <div className={`p-3 rounded-2xl ${isEditMode ? 'bg-orange-100 text-orange-600' : 'bg-blue-600 text-white'}`}>
            {isEditMode ? <AlertTriangle className="w-6 h-6" /> : <Calculator className="w-6 h-6" />}
          </div>
          <div>
            <h2 className="text-xl font-black text-slate-800 dark:text-slate-100 uppercase tracking-tight">
              {isEditMode ? 'Editar Contrato' : 'Efetivar Contrato'}
            </h2>
            <p className="text-xs text-slate-500 font-medium">Contrato com Juros Simples Mensal</p>
          </div>
        </div>
        {isEditMode && (
          <span className="self-start px-3 py-1 bg-orange-50 dark:bg-orange-950/30 text-orange-700 dark:text-orange-400 text-[10px] font-black uppercase rounded-full border border-orange-100 dark:border-orange-900/50">
            Ajustando ID: {initialData.id.slice(0, 8)}
          </span>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Form Column */}
        <form id="loanForm" onSubmit={handleSubmit} className="lg:col-span-8 space-y-8">

          {/* Section: Client Selection/Creation */}
          {!isEditMode && (
            <div className="bg-slate-50 dark:bg-slate-800/50 p-6 rounded-2xl border border-slate-100 dark:border-slate-700 space-y-4">
              <div className="flex items-center justify-between">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                  <Users className="w-4 h-4" /> Vínculo do Cliente
                </label>
                <div className="flex bg-white dark:bg-slate-900 p-1 rounded-xl border dark:border-slate-700">
                  <button 
                    type="button" 
                    onClick={() => setIsNewClientMode(false)}
                    className={`px-3 py-1.5 rounded-lg text-[10px] font-black uppercase transition-all ${!isNewClientMode ? 'bg-blue-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    Existente
                  </button>
                  <button 
                    type="button" 
                    onClick={() => setIsNewClientMode(true)}
                    className={`px-3 py-1.5 rounded-lg text-[10px] font-black uppercase transition-all ${isNewClientMode ? 'bg-blue-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    Novo
                  </button>
                </div>
              </div>

              {isNewClientMode ? (
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 animate-slide-up">
                  <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Nome do Novo Cliente</label>
                    <input required type="text" name="name" value={newClientData.name} onChange={handleNewClientChange} className="w-full px-4 py-2.5 bg-white dark:bg-slate-900 border dark:border-slate-700 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold dark:text-slate-100" placeholder="Ex: João da Silva" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-500 uppercase ml-1">CPF (Opcional)</label>
                    <input type="text" name="cpf" value={newClientData.cpf} onChange={handleNewClientChange} className="w-full px-4 py-2.5 bg-white dark:bg-slate-900 border dark:border-slate-700 rounded-xl outline-none font-bold dark:text-slate-100" placeholder="000.000.000-00" />
                  </div>
                  <div className="space-y-1 sm:col-span-2">
                    <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Telefone / WhatsApp</label>
                    <input type="text" name="phone" value={newClientData.phone} onChange={handleNewClientChange} className="w-full px-4 py-2.5 bg-white dark:bg-slate-900 border dark:border-slate-700 rounded-xl outline-none font-bold dark:text-slate-100" placeholder="(11) 99999-9999" />
                  </div>
                </div>
              ) : (
                <div className="space-y-1 animate-slide-up">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Selecionar Cliente</label>
                  <select
                    required
                    name="clientId"
                    value={formData.clientId}
                    onChange={handleChange}
                    className="w-full px-4 py-2.5 bg-white dark:bg-slate-900 border dark:border-slate-700 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition font-bold dark:text-slate-100"
                  >
                    <option value="">Selecione um cliente...</option>
                    {clients.map(c => <option key={c.id} value={c.id}>{c.name} ({c.id})</option>)}
                  </select>
                  {clients.length === 0 && <p className="text-[9px] text-rose-500 font-bold uppercase mt-1">Nenhum cliente cadastrado. Use a aba "Novo" acima.</p>}
                </div>
              )}
            </div>
          )}

          {isEditMode && (
             <div className="space-y-1 mb-6">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cliente</label>
                <input disabled type="text" value={clients.find(c => c.id === formData.clientId)?.name || 'Cliente'} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none font-bold dark:text-slate-100 opacity-50" />
             </div>
          )}

          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Colaborador (Equipe)</label>
             <select
              required
              name="collaboratorId"
              value={formData.collaboratorId}
              onChange={handleChange}
              disabled={isEditMode}
              className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition font-bold dark:text-slate-100 disabled:opacity-50"
            >
              {collaborators.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 pt-4">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Capital Principal (R$)</label>
              <input
                required type="number" step="0.01" name="principal"
                value={formData.principal} onChange={handleChange}
                className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition font-black text-slate-800 dark:text-slate-100"
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Início da Vigência</label>
              <input
                required type="date" name="startDate"
                value={formData.startDate} onChange={handleChange}
                className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition font-bold dark:text-slate-100"
              />
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Taxa Mensal (%)</label>
              <input
                required type="number" step="0.01" name="monthlyInterestRate"
                value={formData.monthlyInterestRate} onChange={handleChange}
                className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition font-black text-blue-600"
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Número de Parcelas</label>
              <input
                required type="number" name="months"
                value={formData.months} onChange={handleChange}
                className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border dark:border-slate-700 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition font-black text-slate-800 dark:text-slate-100"
              />
            </div>
          </div>
        </form>

        {/* Resumo da Simulação - Coluna Lateral */}
        <div className="lg:col-span-4 space-y-4">
          <div className={`p-6 rounded-3xl border shadow-sm ${isEditMode ? 'bg-orange-50/50 dark:bg-orange-950/20 border-orange-100 dark:border-orange-900/40' : 'bg-blue-50/50 dark:bg-blue-950/20 border-blue-100 dark:border-blue-900/40'}`}>
             <h3 className={`text-[10px] font-black uppercase tracking-widest mb-4 ${isEditMode ? 'text-orange-600' : 'text-blue-600'}`}>
               Impacto Projetado
             </h3>
             <div className="space-y-4">
                <div className="flex justify-between items-center">
                   <span className="text-xs font-bold text-slate-500">Juros Mensal</span>
                   <span className="font-black text-slate-800 dark:text-slate-100">{formatCurrency(currentMonthlyInterest)}</span>
                </div>
                <div className="flex justify-between items-center">
                   <span className="text-xs font-bold text-slate-500">Total a Receber</span>
                   <span className="font-black text-slate-800 dark:text-slate-100">{formatCurrency(currentTotalRevenue)}</span>
                </div>
                {isEditMode && (
                  <div className={`mt-4 pt-4 border-t border-orange-100 dark:border-orange-900/50 flex justify-between items-center`}>
                    <span className="text-[10px] font-black uppercase text-orange-600">Diferença</span>
                    <span className={`text-sm font-black ${deltaRevenue >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
                       {deltaRevenue > 0 ? '+' : ''}{formatCurrency(deltaRevenue)}
                    </span>
                  </div>
                )}
             </div>
          </div>

          <div className="flex flex-col gap-3 pt-4">
            <button
              type="submit" form="loanForm"
              className={`w-full py-4 rounded-2xl font-black uppercase text-xs shadow-lg transition flex items-center justify-center gap-2 text-white ${isEditMode ? 'bg-orange-600 hover:bg-orange-700 shadow-orange-200' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-200 dark:shadow-none'}`}
            >
              <Save className="w-4 h-4" />
              {isEditMode ? 'Atualizar Contrato' : 'Efetivar Contrato'}
            </button>
            <button
              type="button" onClick={onCancel}
              className="w-full py-4 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 rounded-2xl font-black uppercase text-xs hover:bg-slate-50 transition"
            >
              Cancelar
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ViewState, Loan, Client, Collaborator, PenaltyPattern, Expense, Portfolio, PortfolioMovement, UserProfile, AppSettings } from './types';
import { Dashboard } from './components/Dashboard';
import { LoanList } from './components/LoanList';
import { AIAnalyst } from './components/AIAnalyst';
import { ClientManager } from './components/ClientManager';
import { PenaltyPatternManager } from './components/PenaltyPatternManager';
import { CollaboratorManager } from './components/CollaboratorManager';
import { ExpenseManager } from './components/ExpenseManager';
import { PortfolioManager } from './components/PortfolioManager';
import { Forecast } from './components/Forecast';
import { ProfileWidget } from './components/ProfileWidget';
import { ProfileView } from './components/ProfileView';
import { SettingsView } from './components/SettingsView';
import { LoanCalculator } from './components/LoanCalculator';
import { LoanForm } from './components/LoanForm';
import { LogoText } from './components/Logo';
import { generateInstallments } from './utils/calculations';
import { 
  LayoutDashboard, 
  List, 
  Bot, 
  Users,
  Briefcase,
  Gavel,
  Sun,
  Moon,
  Menu,
  X,
  Calculator
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<ViewState>(ViewState.DASHBOARD);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const savedTheme = localStorage.getItem('theme');
    return savedTheme === 'dark' || (!savedTheme && window.matchMedia('(prefers-color-scheme: dark)').matches);
  });

  const [loans, setLoans] = useState<Loan[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [collaborators, setCollaborators] = useState<Collaborator[]>([]);
  const [penaltyPatterns, setPenaltyPatterns] = useState<PenaltyPattern[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [portfolios, setPortfolios] = useState<Portfolio[]>([]);
  const [portfolioMovements, setPortfolioMovements] = useState<PortfolioMovement[]>([]);

  // Estado para preenchimento automático do LoanForm a partir da calculadora
  const [preFilledLoan, setPreFilledLoan] = useState<Partial<Loan> | null>(null);
  const [isAddingLoan, setIsAddingLoan] = useState(false);

  // Novos estados para Perfil e Configurações
  const [userProfile, setUserProfile] = useState<UserProfile>({
    name: 'Gestor SimpleFy',
    email: 'gestor@simplefy.com',
    businessName: 'SimpleFy Management',
    currency: 'BRL',
    timezone: 'GMT-3 (Brasília)',
    startDate: new Date().toISOString().split('T')[0],
    notes: ''
  });

  const [appSettings, setAppSettings] = useState<AppSettings>({
    defaultPenaltyRate: 2,
    defaultMoraRate: 1,
    interestType: 'Simples',
    decimalPlaces: 2,
    expenseImpactsProfit: true,
    allowTransfers: true,
    expenseCategories: ['Operacional', 'Pessoal', 'Investimento'],
    dashboardVisibility: {
      receitaProjetada: true,
      lucroProjetado: true,
      lucroLiquido: true,
      caixaDisponivel: true,
      roi: true,
    }
  });

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    const savedData = localStorage.getItem('simplefy_data_v22');
    if (savedData) {
      const parsed = JSON.parse(savedData);
      setLoans(parsed.loans || []);
      setClients(parsed.clients || []);
      setCollaborators(parsed.collaborators || []);
      setPenaltyPatterns(parsed.penaltyPatterns || []);
      setExpenses(parsed.expenses || []);
      setPortfolios(parsed.portfolios || []);
      setPortfolioMovements(parsed.portfolioMovements || []);
      if (parsed.userProfile) setUserProfile(parsed.userProfile);
      if (parsed.appSettings) setAppSettings(parsed.appSettings);
    } else {
        const seedPatterns: PenaltyPattern[] = [
           { id: "P001", name: "Padrão Legal (2% + 1% mês)", fixedRate: 2, monthlyInterest: 1, active: true },
           { id: "P002", name: "Multa Atraso Curto (1% + 0.5% mês)", fixedRate: 1, monthlyInterest: 0.5, active: true }
        ];

        const seedClients: Client[] = [
          { id: 'C001', name: 'Matheus', cpf: '000.000.000-01', phone: '1191425-6969', status: 'active' },
          { id: 'C002', name: 'Bruno', cpf: '000.000.000-02', phone: '1197752-3942', status: 'active' },
          { id: 'C003', name: 'Esposa Bruno', cpf: '000.000.000-03', phone: '1197752-3942', status: 'active' },
          { id: 'C004', name: 'Bahia', cpf: '000.000.000-04', phone: '1198342-4814', status: 'active' },
        ];

        const seedCollaborators: Collaborator[] = [
          { id: 'V001', name: 'Administrador Principal', type: 'percentage', base: 'profit', value: 0 }
        ];

        const seedPortfolios: Portfolio[] = [
          { id: 'PORT001', name: 'Reserva Emergência', type: 'Reserva' },
          { id: 'PORT002', name: 'Conta Cripto', type: 'Criptomoedas' }
        ];

        const rawLoans: Partial<Loan>[] = [
          { id: 'E001', clientId: 'C001', collaboratorId: 'V001', principal: 10000, monthlyInterestRate: 10, months: 4, startDate: '2025-09-01', status: 'Ativo' },
          { id: 'E002', clientId: 'C002', collaboratorId: 'V001', principal: 8000, monthlyInterestRate: 10, months: 10, startDate: '2025-09-01', status: 'Ativo' },
          { id: 'E003', clientId: 'C002', collaboratorId: 'V001', principal: 2800, monthlyInterestRate: 25, months: 1, startDate: '2025-11-01', status: 'Ativo' },
          { id: 'E004', clientId: 'C003', collaboratorId: 'V001', principal: 5000, monthlyInterestRate: 13.5, months: 10, startDate: '2025-11-01', status: 'Ativo' },
          { id: 'E005', clientId: 'C004', collaboratorId: 'V001', principal: 5800, monthlyInterestRate: 14.66, months: 10, startDate: '2025-12-01', status: 'Ativo' },
          { id: 'E006', clientId: 'C001', collaboratorId: 'V001', principal: 1000, monthlyInterestRate: 20, months: 1, startDate: '2025-11-01', status: 'Quitado' },
          { id: 'E007', clientId: 'C001', collaboratorId: 'V001', principal: 2000, monthlyInterestRate: 22.5, months: 2, startDate: '2025-12-01', status: 'Ativo' },
        ];

        const seedLoans = rawLoans.map(l => {
          const loan = l as Loan;
          const insts = generateInstallments(loan);
          if (loan.status === 'Quitado') insts.forEach(i => i.status = 'Pago');
          return { ...loan, installments: insts };
        });

        setPenaltyPatterns(seedPatterns);
        setClients(seedClients);
        setCollaborators(seedCollaborators);
        setLoans(seedLoans);
        setExpenses([]);
        setPortfolios(seedPortfolios);
        setPortfolioMovements([]);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('simplefy_data_v22', JSON.stringify({ 
      loans, clients, collaborators, penaltyPatterns, expenses, portfolios, portfolioMovements,
      userProfile, appSettings
    }));
  }, [loans, clients, collaborators, penaltyPatterns, expenses, portfolios, portfolioMovements, userProfile, appSettings]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const handleNavClick = (tab: ViewState) => {
    setActiveTab(tab);
    setIsMobileMenuOpen(false);
    setIsAddingLoan(false);
    setPreFilledLoan(null);
  };

  const handleAddExpense = (e: Expense) => {
    setExpenses([...expenses, e]);
    if (e.type === 'transfer_to_portfolio' && e.destination) {
      const movement: PortfolioMovement = {
        id: crypto.randomUUID(),
        portfolioId: e.destination,
        date: e.date,
        amount: e.amount,
        origin: 'Transferência (Despesas)',
        description: `Ref: ${e.description}`
      };
      setPortfolioMovements(prev => [...prev, movement]);
    }
  };

  const handleUpdateExpense = (u: Expense) => {
    const oldExp = expenses.find(e => e.id === u.id);
    setExpenses(expenses.map(e => e.id === u.id ? u : e));

    setPortfolioMovements(prev => prev.filter(m => !(m.origin === 'Transferência (Despesas)' && m.description.includes(oldExp?.description || '---'))));

    if (u.type === 'transfer_to_portfolio' && u.destination) {
      const movement: PortfolioMovement = {
        id: crypto.randomUUID(),
        portfolioId: u.destination,
        date: u.date,
        amount: u.amount,
        origin: 'Transferência (Despesas)',
        description: `Ref: ${u.description}`
      };
      setPortfolioMovements(prev => [...prev, movement]);
    }
  };

  const handleDeleteExpense = (id: string) => {
    const exp = expenses.find(e => e.id === id);
    setExpenses(expenses.filter(e => e.id !== id));
    if (exp?.type === 'transfer_to_portfolio') {
      setPortfolioMovements(prev => prev.filter(m => !(m.origin === 'Transferência (Despesas)' && m.description.includes(exp.description))));
    }
  };

  const handleCalculatorConversion = (data: { principal: number; rate: number; months: number }) => {
    setPreFilledLoan({
      principal: data.principal,
      monthlyInterestRate: data.rate,
      months: data.months,
      startDate: new Date().toISOString().split('T')[0]
    });
    setActiveTab(ViewState.LOANS);
    setIsAddingLoan(true);
  };

  const handleSaveLoan = (loan: Loan, newClient?: Client) => {
    if (newClient) {
      setClients(prev => [...prev, newClient]);
    }
    setLoans(prev => [...prev, loan]);
    setIsAddingLoan(false);
    setPreFilledLoan(null);
  };

  const getPageTitle = (tab: ViewState) => {
    switch(tab) {
      case ViewState.PORTFOLIOS: return 'Minha Carteira';
      case ViewState.EXPENSES: return 'Minhas Despesas';
      case ViewState.FORECAST: return 'Minha Previsão';
      case ViewState.PROFILE: return 'Meu Perfil';
      case ViewState.SETTINGS: return 'Configurações';
      case ViewState.LOAN_CALCULATOR: return 'Simulador de Empréstimo';
      default: return tab.replace('_', ' ');
    }
  };

  return (
    <div className="min-h-screen flex bg-gray-50 dark:bg-slate-950 overflow-x-hidden">
      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-40 lg:hidden" onClick={() => setIsMobileMenuOpen(false)} />
      )}

      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white flex flex-col transition-transform duration-300 lg:relative lg:translate-x-0 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="h-16 flex items-center justify-between px-6 border-b border-slate-800">
          <LogoText />
          <button onClick={() => setIsMobileMenuOpen(false)} className="lg:hidden p-2 text-slate-400 hover:text-white"><X className="w-6 h-6" /></button>
        </div>
        <nav className="flex-1 py-6 space-y-1 px-3 overflow-y-auto">
          <NavItem icon={LayoutDashboard} label="Dashboard" active={activeTab === ViewState.DASHBOARD} onClick={() => handleNavClick(ViewState.DASHBOARD)} />
          <NavItem icon={Calculator} label="Simulador" active={activeTab === ViewState.LOAN_CALCULATOR} onClick={() => handleNavClick(ViewState.LOAN_CALCULATOR)} color="bg-blue-600" />
          <NavItem icon={Users} label="Clientes" active={activeTab === ViewState.CLIENTS} onClick={() => handleNavClick(ViewState.CLIENTS)} />
          <NavItem icon={List} label="Contratos" active={activeTab === ViewState.LOANS} onClick={() => handleNavClick(ViewState.LOANS)} />
          <NavItem icon={Briefcase} label="Equipe" active={activeTab === ViewState.COLLABORATORS} onClick={() => handleNavClick(ViewState.COLLABORATORS)} />
          <NavItem icon={Gavel} label="Multas" active={activeTab === ViewState.PENALTY_PATTERNS} onClick={() => handleNavClick(ViewState.PENALTY_PATTERNS)} />
          <div className="pt-4 border-t border-slate-800 mt-4 opacity-30 text-[9px] font-black uppercase tracking-widest px-4">Inteligência</div>
          <NavItem icon={Bot} label="Analista IA" active={activeTab === ViewState.AI_ANALYST} onClick={() => handleNavClick(ViewState.AI_ANALYST)} color="bg-indigo-600" />
        </nav>
      </aside>

      <main className="flex-1 min-w-0 flex flex-col h-screen overflow-hidden">
        <header className="bg-white dark:bg-slate-900 shadow-sm border-b border-gray-200 dark:border-slate-800 h-16 flex items-center justify-between px-4 sm:px-8 shrink-0 z-20">
          <div className="flex items-center gap-3">
            <button onClick={() => setIsMobileMenuOpen(true)} className="lg:hidden p-2 -ml-2 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg"><Menu className="w-6 h-6" /></button>
            <h1 className="text-sm sm:text-xl font-black text-slate-800 dark:text-slate-100 uppercase tracking-tight truncate max-w-[150px] sm:max-w-none">
              {getPageTitle(activeTab)}
            </h1>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={toggleTheme} className="p-2.5 rounded-xl bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors">
              {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>
            <ProfileWidget activeTab={activeTab} onNavigate={handleNavClick} />
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 sm:p-8">
          <div className="max-w-7xl mx-auto space-y-6 pb-12">
            {activeTab === ViewState.DASHBOARD && <Dashboard loans={loans} collaborators={collaborators} clients={clients} expenses={expenses} settings={appSettings} />}
            {activeTab === ViewState.CLIENTS && <ClientManager clients={clients} loans={loans} onAddClient={c => setClients([...clients, c])} onUpdateClient={u => setClients(clients.map(c => c.id === u.id ? u : c))} onDeleteClient={id => setClients(clients.filter(c => c.id !== id))} />}
            {activeTab === ViewState.LOANS && (
              isAddingLoan ? (
                <LoanForm 
                  clients={clients} 
                  collaborators={collaborators} 
                  initialData={preFilledLoan ? (preFilledLoan as Loan) : undefined}
                  onSave={handleSaveLoan}
                  onCancel={() => {
                    setIsAddingLoan(false);
                    setPreFilledLoan(null);
                  }}
                />
              ) : (
                <div className="space-y-6">
                  <div className="flex justify-end">
                    <button onClick={() => setIsAddingLoan(true)} className="px-6 py-3 bg-blue-600 text-white rounded-2xl font-black uppercase text-xs shadow-lg hover:bg-blue-700 transition">Novo Contrato</button>
                  </div>
                  <LoanList loans={loans} clients={clients} collaborators={collaborators} penaltyPatterns={penaltyPatterns} onDelete={id => setLoans(loans.filter(l => l.id !== id))} onUpdate={u => setLoans(loans.map(l => l.id === u.id ? u : l))} />
                </div>
              )
            )}
            {activeTab === ViewState.LOAN_CALCULATOR && <LoanCalculator onConvertToLoan={handleCalculatorConversion} />}
            {activeTab === ViewState.FORECAST && <Forecast loans={loans} />}
            {activeTab === ViewState.EXPENSES && <ExpenseManager expenses={expenses} portfolios={portfolios} onAdd={handleAddExpense} onUpdate={handleUpdateExpense} onDelete={handleDeleteExpense} />}
            {activeTab === ViewState.PORTFOLIOS && <PortfolioManager portfolios={portfolios} movements={portfolioMovements} onAdd={p => setPortfolios([...portfolios, p])} onUpdate={u => setPortfolios(portfolios.map(p => p.id === u.id ? u : p))} onDelete={id => setPortfolios(portfolios.filter(p => p.id !== id))} onAddMovement={m => setPortfolioMovements([...portfolioMovements, m])} />}
            {activeTab === ViewState.COLLABORATORS && <CollaboratorManager collaborators={collaborators} onAdd={c => setCollaborators([...collaborators, c])} onUpdate={u => setCollaborators(collaborators.map(c => c.id === u.id ? u : c))} onDelete={id => setCollaborators(collaborators.filter(c => c.id !== id))} />}
            {activeTab === ViewState.PENALTY_PATTERNS && <PenaltyPatternManager patterns={penaltyPatterns} onAdd={p => setPenaltyPatterns([...penaltyPatterns, p])} onUpdate={u => setPenaltyPatterns(penaltyPatterns.map(p => p.id === u.id ? p : p))} onDelete={id => setPenaltyPatterns(penaltyPatterns.filter(p => p.id !== id))} />}
            {activeTab === ViewState.AI_ANALYST && <AIAnalyst loans={loans} clients={clients} collaborators={collaborators} />}
            {activeTab === ViewState.PROFILE && <ProfileView profile={userProfile} onSave={setUserProfile} />}
            {activeTab === ViewState.SETTINGS && <SettingsView settings={appSettings} onSave={setAppSettings} />}
          </div>
        </div>
      </main>
    </div>
  );
};

const NavItem = ({ icon: Icon, label, active, onClick, color }: any) => (
  <button onClick={onClick} className={`w-full flex items-center p-3 rounded-xl transition-all ${active ? (color || 'bg-blue-600 text-white shadow-lg') : 'text-slate-400 hover:bg-slate-800'}`}>
    <Icon className="w-5 h-5 shrink-0" />
    <span className="ml-3 font-bold text-sm truncate">{label}</span>
  </button>
);

export default App;

import React, { useState } from 'react';
import { formatCurrency } from '../utils/calculations';
import { Client, Collaborator } from '../types';
import { 
  Calculator, 
  DollarSign, 
  Percent, 
  Calendar, 
  ArrowRight, 
  List, 
  Info, 
  TrendingUp, 
  PiggyBank, 
  Users, 
  UserPlus, 
  Briefcase,
  CheckCircle2
} from 'lucide-react';

interface LoanCalculatorProps {
  clients: Client[];
  collaborators: Collaborator[];
  onConvertToLoan: (data: { 
    principal: number; 
    rate: number; 
    months: number; 
    clientId: string; 
    collaboratorId: string;
    newClient?: Client;
  }) => void;
}

export const LoanCalculator: React.FC<LoanCalculatorProps> = ({ clients, collaborators, onConvertToLoan }) => {
  // Dados Financeiros
  const [principal, setPrincipal] = useState<number>(5000);
  const [rate, setRate] = useState<number>(10);
  const [months, setMonths] = useState<number>(10);

  // Vínculo de Cliente
  const [isNewClientMode, setIsNewClientMode] = useState(clients.length === 0);
  const [selectedClientId, setSelectedClientId] = useState(clients.length > 0 ? clients[0].id : '');
  const [newClientData, setNewClientData] = useState<Partial<Client>>({
    name: '',
    cpf: '',
    phone: '',
    status: 'active'
  });

  // Vínculo de Colaborador
  const [selectedCollabId, setSelectedCollabId] = useState(collaborators.length > 0 ? collaborators[0].id : '');

  const monthlyInterest = principal * (rate / 100);
  const totalInterest = monthlyInterest * months;
  const totalAmount = principal + totalInterest;
  const yieldPercentage = (totalInterest / principal) * 100;

  const handleEfetivar = () => {
    let finalClientId = selectedClientId;
    let createdClient: Client | undefined = undefined;

    if (isNewClientMode) {
      if (!newClientData.name) {
        alert("Por favor, preencha o nome do novo cliente.");
        return;
      }
      createdClient = {
        id: `C${Date.now()}`,
        name: newClientData.name,
        cpf: newClientData.cpf || '',
        phone: newClientData.phone || '',
        status: 'active',
        notes: 'Cadastrado via simulador'
      };
      finalClientId = createdClient.id;
    }

    if (!finalClientId) {
      alert("Selecione ou crie um cliente para prosseguir.");
      return;
    }

    if (!selectedCollabId) {
      alert("Selecione um colaborador responsável.");
      return;
    }

    onConvertToLoan({
      principal,
      rate,
      months,
      clientId: finalClientId,
      collaboratorId: selectedCollabId,
      newClient: createdClient
    });
  };

  return (
    <div className="space-y-8 animate-fade-in max-w-7xl mx-auto">
      <div className="bg-white dark:bg-slate-900 p-6 sm:p-10 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden">
        <div className="flex items-center gap-4 mb-10">
          <div className="p-3 bg-blue-600 rounded-2xl text-white">
            <Calculator className="w-6 h-6" />
          </div>
          <div>
            <h2 className="text-xl font-black text-slate-800 dark:text-slate-100 uppercase tracking-tight">Simulação & Efetivação</h2>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Simule e converta propostas em contratos reais</p>
          </div>
        </div>

        <div className="grid grid-cols-1 xl:grid-cols-12 gap-12">
          {/* Coluna 1: Parâmetros e Resultados */}
          <div className="xl:col-span-5 space-y-8">
            <div className="bg-slate-50 dark:bg-slate-800/30 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 space-y-6">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 flex items-center gap-2">
