                      type="text" 
                      value={newClientData.phone} 
                      onChange={e => setNewClientData({...newClientData, phone: e.target.value})}
                      className="w-full px-4 py-3 bg-white dark:bg-slate-900 border dark:border-slate-700 rounded-xl outline-none font-bold dark:text-slate-100" 
                      placeholder="(00) 00000-0000"
                    />
                  </div>
                  <div className="sm:col-span-2 space-y-1">
                    <label className="text-[9px] font-black text-slate-500 uppercase ml-1">CPF (Opcional)</label>
                    <input 
                      type="text" 
                      value={newClientData.cpf} 
                      onChange={e => setNewClientData({...newClientData, cpf: e.target.value})}
                      className="w-full px-4 py-3 bg-white dark:bg-slate-900 border dark:border-slate-700 rounded-xl outline-none font-bold dark:text-slate-100" 
                      placeholder="000.000.000-00"
                    />
                  </div>
                </div>
              ) : (
                <div className="space-y-1 animate-slide-up">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Selecionar Cliente na Base</label>
                  <select 
                    value={selectedClientId}
                    onChange={e => setSelectedClientId(e.target.value)}
                    className="w-full px-5 py-4 bg-white dark:bg-slate-900 border dark:border-slate-700 rounded-2xl outline-none font-bold dark:text-slate-100 focus:ring-2 focus:ring-blue-500"
                  >
                    <option value="">Selecione...</option>
                    {clients.map(c => <option key={c.id} value={c.id}>{c.name} ({c.id})</option>)}
                  </select>
                </div>
              )}
            </div>

            <div className="pt-6">
              <button 
                onClick={handleEfetivar}
                className="w-full py-5 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 rounded-2xl font-black uppercase text-xs shadow-2xl active:scale-95 transition-all flex items-center justify-center gap-3 group"
              >
                Efetivar Contrato Agora <ArrowRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
              </button>
              <div className="mt-4 flex items-center justify-center gap-2 text-[10px] text-slate-400 font-bold uppercase">
                <CheckCircle2 className="w-3 h-3 text-emerald-500" />
                Os termos serão gerados automaticamente
