  LayoutDashboard, 
  List, 
  Bot, 
  Users,
  Briefcase,
  Gavel,
  Sun,
  Moon,
  Menu,
  X,
  Calculator
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<ViewState>(ViewState.DASHBOARD);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const savedTheme = localStorage.getItem('theme');
    return savedTheme === 'dark' || (!savedTheme && window.matchMedia('(prefers-color-scheme: dark)').matches);
  });

  const [loans, setLoans] = useState<Loan[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [collaborators, setCollaborators] = useState<Collaborator[]>([]);
  const [penaltyPatterns, setPenaltyPatterns] = useState<PenaltyPattern[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [portfolios, setPortfolios] = useState<Portfolio[]>([]);
  const [portfolioMovements, setPortfolioMovements] = useState<PortfolioMovement[]>([]);

  const [preFilledLoan, setPreFilledLoan] = useState<Partial<Loan> | null>(null);
  const [isAddingLoan, setIsAddingLoan] = useState(false);

  const [userProfile, setUserProfile] = useState<UserProfile>({
    name: 'Gestor SimpleFy',
    email: 'gestor@simplefy.com',
    businessName: 'SimpleFy Management',
    currency: 'BRL',
    timezone: 'GMT-3 (Brasília)',
    startDate: new Date().toISOString().split('T')[0],
    notes: ''
  });

  const [appSettings, setAppSettings] = useState<AppSettings>({
    defaultPenaltyRate: 2,
    defaultMoraRate: 1,
    interestType: 'Simples',
    decimalPlaces: 2,
    expenseImpactsProfit: true,
    allowTransfers: true,
    expenseCategories: ['Operacional', 'Pessoal', 'Investimento'],
    dashboardVisibility: {
      receitaProjetada: true,
      lucroProjetado: true,
      lucroLiquido: true,
      caixaDisponivel: true,
      roi: true,
    }
  });

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    const savedData = localStorage.getItem('simplefy_data_v22');
    if (savedData) {
      const parsed = JSON.parse(savedData);
      setLoans(parsed.loans || []);
      setClients(parsed.clients || []);
      setCollaborators(parsed.collaborators || []);
      setPenaltyPatterns(parsed.penaltyPatterns || []);
      setExpenses(parsed.expenses || []);
      setPortfolios(parsed.portfolios || []);
      setPortfolioMovements(parsed.portfolioMovements || []);
      if (parsed.userProfile) setUserProfile(parsed.userProfile);
      if (parsed.appSettings) setAppSettings(parsed.appSettings);
    } else {
        const seedPatterns: PenaltyPattern[] = [
           { id: "P001", name: "Padrão Legal (2% + 1% mês)", fixedRate: 2, monthlyInterest: 1, active: true },
           { id: "P002", name: "Multa Atraso Curto (1% + 0.5% mês)", fixedRate: 1, monthlyInterest: 0.5, active: true }
        ];
        const seedClients: Client[] = [
          { id: 'C001', name: 'Matheus', cpf: '000.000.000-01', phone: '1191425-6969', status: 'active' },
          { id: 'C002', name: 'Bruno', cpf: '000.000.000-02', phone: '1197752-3942', status: 'active' },
          { id: 'C003', name: 'Esposa Bruno', cpf: '000.000.000-03', phone: '1197752-3942', status: 'active' },
          { id: 'C004', name: 'Bahia', cpf: '000.000.000-04', phone: '1198342-4814', status: 'active' },
        ];
        const seedCollaborators: Collaborator[] = [
          { id: 'V001', name: 'Administrador Principal', type: 'percentage', base: 'profit', value: 0 }
        ];
        const seedPortfolios: Portfolio[] = [
          { id: 'PORT001', name: 'Reserva Emergência', type: 'Reserva' },
          { id: 'PORT002', name: 'Conta Cripto', type: 'Criptomoedas' }
        ];
        const rawLoans: Partial<Loan>[] = [
          { id: 'E001', clientId: 'C001', collaboratorId: 'V001', principal: 10000, monthlyInterestRate: 10, months: 4, startDate: '2025-09-01', status: 'Ativo' },
          { id: 'E002', clientId: 'C002', collaboratorId: 'V001', principal: 8000, monthlyInterestRate: 10, months: 10, startDate: '2025-09-01', status: 'Ativo' },
          { id: 'E003', clientId: 'C002', collaboratorId: 'V001', principal: 2800, monthlyInterestRate: 25, months: 1, startDate: '2025-11-01', status: 'Ativo' },
          { id: 'E004', clientId: 'C003', collaboratorId: 'V001', principal: 5000, monthlyInterestRate: 13.5, months: 10, startDate: '2025-11-01', status: 'Ativo' },
          { id: 'E005', clientId: 'C004', collaboratorId: 'V001', principal: 5800, monthlyInterestRate: 14.66, months: 10, startDate: '2025-12-01', status: 'Ativo' },
          { id: 'E006', clientId: 'C001', collaboratorId: 'V001', principal: 1000, monthlyInterestRate: 20, months: 1, startDate: '2025-11-01', status: 'Quitado' },
          { id: 'E007', clientId: 'C001', collaboratorId: 'V001', principal: 2000, monthlyInterestRate: 22.5, months: 2, startDate: '2025-12-01', status: 'Ativo' },
        ];
        const seedLoans = rawLoans.map(l => {
          const loan = l as Loan;
          const insts = generateInstallments(loan);
          if (loan.status === 'Quitado') insts.forEach(i => i.status = 'Pago');
          return { ...loan, installments: insts };
        });
        setPenaltyPatterns(seedPatterns);
        setClients(seedClients);
        setCollaborators(seedCollaborators);
        setLoans(seedLoans);
        setExpenses([]);
        setPortfolios(seedPortfolios);
        setPortfolioMovements([]);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('simplefy_data_v22', JSON.stringify({ 
      loans, clients, collaborators, penaltyPatterns, expenses, portfolios, portfolioMovements,
      userProfile, appSettings
    }));
  }, [loans, clients, collaborators, penaltyPatterns, expenses, portfolios, portfolioMovements, userProfile, appSettings]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const handleNavClick = (tab: ViewState) => {
    setActiveTab(tab);
    setIsMobileMenuOpen(false);
    setIsAddingLoan(false);
    setPreFilledLoan(null);
  };

  const handleAddExpense = (e: Expense) => {
    setExpenses([...expenses, e]);
    if (e.type === 'transfer_to_portfolio' && e.destination) {
      const movement: PortfolioMovement = {
        id: crypto.randomUUID(),
        portfolioId: e.destination,
        date: e.date,
        amount: e.amount,
        origin: 'Transferência (Despesas)',
        description: `Ref: ${e.description}`
      };
      setPortfolioMovements(prev => [...prev, movement]);
    }
  };

  const handleUpdateExpense = (u: Expense) => {
    const oldExp = expenses.find(e => e.id === u.id);
    setExpenses(expenses.map(e => e.id === u.id ? u : e));
    setPortfolioMovements(prev => prev.filter(m => !(m.origin === 'Transferência (Despesas)' && m.description.includes(oldExp?.description || '---'))));
    if (u.type === 'transfer_to_portfolio' && u.destination) {
      const movement: PortfolioMovement = {
        id: crypto.randomUUID(),
        portfolioId: u.destination,
        date: u.date,
        amount: u.amount,
        origin: 'Transferência (Despesas)',
        description: `Ref: ${u.description}`
      };
      setPortfolioMovements(prev => [...prev, movement]);
    }
  };

  const handleDeleteExpense = (id: string) => {
    const exp = expenses.find(e => e.id === id);
    setExpenses(expenses.filter(e => e.id !== id));
    if (exp?.type === 'transfer_to_portfolio') {
      setPortfolioMovements(prev => prev.filter(m => !(m.origin === 'Transferência (Despesas)' && m.description.includes(exp.description))));
    }
  };

  const handleCalculatorConversion = (data: { 
    principal: number; 
    rate: number; 
    months: number; 
    clientId: string; 
    collaboratorId: string;
    newClient?: Client;
  }) => {
    const loanData: Partial<Loan> = {
      principal: data.principal,
      monthlyInterestRate: data.rate,
      months: data.months,
      startDate: new Date().toISOString().split('T')[0],
    };
    const installments = generateInstallments(loanData);
    const newLoan: Loan = {
      id: crypto.randomUUID(),
      clientId: data.clientId,
      collaboratorId: data.collaboratorId,
      principal: data.principal,
      monthlyInterestRate: data.rate,
      months: data.months,
      startDate: loanData.startDate!,
      status: 'Ativo',
      installments: installments
    };
    if (data.newClient) {
      setClients(prev => [...prev, data.newClient!]);
    }
    setLoans(prev => [...prev, newLoan]);
    setActiveTab(ViewState.LOANS);
  };

  const handleSaveLoan = (loan: Loan, newClient?: Client) => {
    if (newClient) {
      setClients(prev => [...prev, newClient]);
    }
    setLoans(prev => [...prev, loan]);
    setIsAddingLoan(false);
    setPreFilledLoan(null);
  };

  const getPageTitle = (tab: ViewState) => {
    switch(tab) {
      case ViewState.PORTFOLIOS: return 'Carteiras';
      case ViewState.EXPENSES: return 'Despesas';
      case ViewState.FORECAST: return 'Previsão';
      case ViewState.PROFILE: return 'Perfil';
      case ViewState.SETTINGS: return 'Configurações';
      case ViewState.LOAN_CALCULATOR: return 'Simulador';
      default: return tab.replace('_', ' ');
    }
  };

  return (
    <div className="min-h-screen flex bg-simplefy-bg dark:bg-slate-950">
      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-xs z-40 lg:hidden" onClick={() => setIsMobileMenuOpen(false)} />
