      <aside className={`fixed inset-y-0 left-0 z-50 w-60 bg-simplefy-primary text-white flex flex-col transition-transform duration-200 lg:relative lg:translate-x-0 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}>
