          <LogoText />
        </div>
        <nav className="flex-1 py-4 space-y-0.5 px-3 overflow-y-auto">
          <NavItem icon={LayoutDashboard} label="Dashboard" active={activeTab === ViewState.DASHBOARD} onClick={() => handleNavClick(ViewState.DASHBOARD)} />
          <NavItem icon={Calculator} label="Simulador" active={activeTab === ViewState.LOAN_CALCULATOR} onClick={() => handleNavClick(ViewState.LOAN_CALCULATOR)} />
          <NavItem icon={Users} label="Clientes" active={activeTab === ViewState.CLIENTS} onClick={() => handleNavClick(ViewState.CLIENTS)} />
          <NavItem icon={List} label="Contratos" active={activeTab === ViewState.LOANS} onClick={() => handleNavClick(ViewState.LOANS)} />
          <NavItem icon={Briefcase} label="Equipe" active={activeTab === ViewState.COLLABORATORS} onClick={() => handleNavClick(ViewState.COLLABORATORS)} />
          <NavItem icon={Gavel} label="Multas" active={activeTab === ViewState.PENALTY_PATTERNS} onClick={() => handleNavClick(ViewState.PENALTY_PATTERNS)} />
          <div className="pt-6 pb-2 px-4 opacity-30 text-[9px] font-bold uppercase tracking-[0.2em]">Inteligência</div>
          <NavItem icon={Bot} label="Analista IA" active={activeTab === ViewState.AI_ANALYST} onClick={() => handleNavClick(ViewState.AI_ANALYST)} isSpecial={true} />
        </nav>
      </aside>

      <main className="flex-1 flex flex-col h-screen overflow-hidden">
        <header className="bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 h-16 flex items-center justify-between px-6 shrink-0 z-20">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsMobileMenuOpen(true)} className="lg:hidden p-2 -ml-2 text-slate-500 hover:bg-slate-50 rounded-lg"><Menu className="w-5 h-5" /></button>
            <h1 className="text-base font-bold text-simplefy-primary dark:text-slate-100 uppercase tracking-tight">
              {getPageTitle(activeTab)}
            </h1>
          </div>
          <div className="flex items-center gap-3">
            <button onClick={toggleTheme} className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 transition-colors">
              {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>
            <ProfileWidget activeTab={activeTab} onNavigate={handleNavClick} />
          </div>
        </header>

        <div className="flex-1 overflow-y-auto px-6 py-8">
          <div className="max-w-7xl mx-auto pb-12">
            {activeTab === ViewState.DASHBOARD && <Dashboard loans={loans} collaborators={collaborators} clients={clients} expenses={expenses} settings={appSettings} />}
            {activeTab === ViewState.CLIENTS && <ClientManager clients={clients} loans={loans} onAddClient={c => setClients([...clients, c])} onUpdateClient={u => setClients(clients.map(c => c.id === u.id ? u : c))} onDeleteClient={id => setClients(clients.filter(c => c.id !== id))} />}
            {activeTab === ViewState.LOANS && (
              isAddingLoan ? (
                <LoanForm 
                  clients={clients} 
                  collaborators={collaborators} 
                  initialData={preFilledLoan ? (preFilledLoan as Loan) : undefined}
                  onSave={handleSaveLoan}
                  onCancel={() => {
                    setIsAddingLoan(false);
                    setPreFilledLoan(null);
                  }}
                />
              ) : (
                <div className="space-y-6">
                  <div className="flex justify-end">
                    <button onClick={() => setIsAddingLoan(true)} className="px-5 py-2.5 bg-simplefy-primary text-white rounded-lg font-bold text-xs hover:bg-slate-800 transition shadow-xs">Novo Contrato</button>
                  </div>
                  <LoanList loans={loans} clients={clients} collaborators={collaborators} penaltyPatterns={penaltyPatterns} onDelete={id => setLoans(loans.filter(l => l.id !== id))} onUpdate={u => setLoans(loans.map(l => l.id === u.id ? u : l))} />
                </div>
              )
            )}
            {activeTab === ViewState.LOAN_CALCULATOR && (
              <LoanCalculator 
                clients={clients} 
                collaborators={collaborators} 
                onConvertToLoan={handleCalculatorConversion} 
              />
            )}
            {activeTab === ViewState.FORECAST && <Forecast loans={loans} />}
            {activeTab === ViewState.EXPENSES && <ExpenseManager expenses={expenses} portfolios={portfolios} onAdd={handleAddExpense} onUpdate={handleUpdateExpense} onDelete={handleDeleteExpense} />}
            {activeTab === ViewState.PORTFOLIOS && <PortfolioManager portfolios={portfolios} movements={portfolioMovements} onAdd={p => setPortfolios([...portfolios, p])} onUpdate={u => setPortfolios(portfolios.map(p => p.id === u.id ? u : p))} onDelete={id => setPortfolios(portfolios.filter(p => p.id !== id))} onAddMovement={m => setPortfolioMovements([...portfolioMovements, m])} />}
            {activeTab === ViewState.COLLABORATORS && <CollaboratorManager collaborators={collaborators} onAdd={c => setCollaborators([...collaborators, c])} onUpdate={u => setCollaborators(collaborators.map(c => c.id === u.id ? u : c))} onDelete={id => setCollaborators(collaborators.filter(c => c.id !== id))} />}
            {activeTab === ViewState.PENALTY_PATTERNS && <PenaltyPatternManager patterns={penaltyPatterns} onAdd={p => setPenaltyPatterns([...penaltyPatterns, p])} onUpdate={u => setPenaltyPatterns(penaltyPatterns.map(p => p.id === u.id ? p : p))} onDelete={id => setPenaltyPatterns(penaltyPatterns.filter(p => p.id !== id))} />}
            {activeTab === ViewState.AI_ANALYST && <AIAnalyst loans={loans} clients={clients} collaborators={collaborators} />}
            {activeTab === ViewState.PROFILE && <ProfileView profile={userProfile} onSave={setUserProfile} />}
            {activeTab === ViewState.SETTINGS && <SettingsView settings={appSettings} onSave={setAppSettings} />}
          </div>
        </div>
      </main>
    </div>
  );
};

