import React, { useState } from 'react';
import { Collaborator, CommissionType, CommissionBase } from '../types';
import { Plus, Trash2, Edit, Save, X, Briefcase, DollarSign, Percent } from 'lucide-react';

interface Props {
  collaborators: Collaborator[];
  onAdd: (c: Collaborator) => void;
  onUpdate: (c: Collaborator) => void;
  onDelete: (id: string) => void;
}

export const CollaboratorManager: React.FC<Props> = ({ collaborators, onAdd, onUpdate, onDelete }) => {
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Collaborator>({
    id: '',
    name: '',
    type: 'percentage',
    base: 'profit',
    value: 0
  });

  const handleOpenForm = (c?: Collaborator) => {
    if (c) {
      setFormData(c);
      setEditingId(c.id);
    } else {
      setFormData({
        id: `V${String(collaborators.length + 1).padStart(3, '0')}`,
        name: '',
        type: 'percentage',
        base: 'profit',
        value: 0
      });
      setEditingId(null);
    }
    setIsFormOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingId) onUpdate(formData);
    else onAdd(formData);
    setIsFormOpen(false);
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-lg font-bold text-simplefy-primary dark:text-slate-100 uppercase tracking-tight">Equipe & Comissões</h2>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Regras de remuneração e parceiros</p>
        </div>
        <button 
          onClick={() => handleOpenForm()} 
          className="flex items-center gap-2 bg-simplefy-primary text-white px-5 py-2.5 rounded-lg font-bold text-xs shadow-sm hover:brightness-110 transition-all"
        >
          <Plus className="w-4 h-4" /> Novo Membro
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {collaborators.map(c => (
          <div key={c.id} className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm hover:border-slate-300 dark:hover:border-slate-700 transition-colors group">
            <div className="flex justify-between items-start mb-6">
              <div className="w-10 h-10 rounded-lg bg-slate-50 dark:bg-slate-800 flex items-center justify-center text-slate-400 group-hover:text-simplefy-primary transition-colors">
                <Briefcase className="w-5 h-5" />
              </div>
              <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                <button onClick={() => handleOpenForm(c)} className="p-2 text-slate-400 hover:text-simplefy-primary"><Edit className="w-4 h-4" /></button>
                <button onClick={() => onDelete(c.id)} className="p-2 text-slate-400 hover:text-simplefy-danger"><Trash2 className="w-4 h-4" /></button>
              </div>
            </div>

            <div className="mb-6">
              <h3 className="font-bold text-simplefy-primary dark:text-slate-100 text-base">{c.name}</h3>
              <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-0.5">ID: {c.id}</p>
            </div>

            <div className="space-y-3 pt-4 border-t border-slate-50 dark:border-slate-800/50">
              <div className="flex justify-between items-center text-[10px]">
                <span className="text-slate-400 font-bold uppercase tracking-widest">Base de Cálculo</span>
                <span className="font-bold text-slate-700 dark:text-slate-300 uppercase tracking-tight">
                  {c.base === 'gross' ? 'Montante Bruto' : 'Lucro Gerado'}
                </span>
              </div>
              <div className="flex justify-between items-center text-[10px]">
                <span className="text-slate-400 font-bold uppercase tracking-widest">Modelo</span>
                <span className="font-bold text-slate-700 dark:text-slate-300 uppercase tracking-tight">
                  {c.type === 'percentage' ? 'Comissão %' : 'Fixo por Cliente'}
                </span>
              </div>
              <div className="flex justify-between items-end mt-4 pt-2">
                <span className="text-[9px] font-black text-simplefy-primary dark:text-slate-500 uppercase tracking-[0.2em]">Repasse</span>
                <span className="text-xl font-black text-simplefy-primary dark:text-slate-100 tracking-tighter">
                  {c.type === 'percentage' ? `${c.value}%` : new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(c.value)}
                </span>
              </div>
            </div>
          </div>
        ))}
      </div>

      {isFormOpen && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-xs z-50 flex items-center justify-center p-4">
          <form onSubmit={handleSubmit} className="bg-white dark:bg-slate-900 w-full max-w-md rounded-2xl shadow-2xl p-8 border border-slate-200 dark:border-slate-800 animate-slide-up">
            <div className="flex justify-between items-center mb-8">
              <div>
                <h3 className="text-base font-bold text-simplefy-primary dark:text-slate-100 uppercase tracking-tight">
                  {editingId ? 'Editar Colaborador' : 'Novo Colaborador'}
                </h3>
                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Parâmetros de remuneração</p>
              </div>
              <button type="button" onClick={() => setIsFormOpen(false)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg">
                <X className="w-5 h-5 text-slate-400" />
              </button>
            </div>

            <div className="space-y-5">
              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-1">Nome Completo</label>
                <input 
                  required 
                  type="text" 
                  value={formData.name} 
                  onChange={e => setFormData({...formData, name: e.target.value})} 
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl outline-none focus:border-simplefy-primary font-bold text-sm dark:text-slate-100" 
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-1">Tipo</label>
                  <select 
                    value={formData.type} 
                    onChange={e => setFormData({...formData, type: e.target.value as CommissionType})} 
                    className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl outline-none font-bold text-xs dark:text-slate-100"
                  >
                    <option value="percentage">Percentual (%)</option>
                    <option value="fixed_per_client">Fixo (R$)</option>
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-1">Base</label>
                  <select 
                    value={formData.base} 
                    onChange={e => setFormData({...formData, base: e.target.value as CommissionBase})} 
                    className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl outline-none font-bold text-xs dark:text-slate-100"
                  >
                    <option value="profit">Sobre o Lucro</option>
                    <option value="gross">Sobre o Bruto</option>
                  </select>
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-1">
                  Valor {formData.type === 'percentage' ? '(%)' : '(R$)'}
                </label>
                <div className="relative">
                  <input 
                    required 
                    type="number" 
                    step="0.01" 
                    value={formData.value} 
                    onChange={e => setFormData({...formData, value: Number(e.target.value)})} 
                    className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl outline-none font-black text-sm dark:text-slate-100" 
                  />
                  <div className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300">
                    {formData.type === 'percentage' ? <Percent className="w-4 h-4" /> : <DollarSign className="w-4 h-4" />}
                  </div>
                </div>
              </div>
            </div>

            <div className="flex gap-4 mt-10">
              <button 
                type="button" 
                onClick={() => setIsFormOpen(false)} 
                className="flex-1 py-3 px-4 bg-slate-100 dark:bg-slate-800 text-slate-500 rounded-lg font-bold uppercase text-[10px] tracking-widest"
              >
                Cancelar
              </button>
              <button 
                type="submit" 
                className="flex-1 py-3 px-4 bg-simplefy-primary text-white rounded-lg font-bold uppercase text-[10px] tracking-widest shadow-md hover:brightness-110 transition-all"
              >
                Salvar
              </button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Client, Loan } from '../types';
import { 
  UserPlus, 
  Search, 
  User, 
  Phone, 
  Mail, 
  FileText, 
  CheckCircle2, 
  X, 
  ArrowLeft, 
  CreditCard, 
  Hash, 
  Calendar, 
  Trash2, 
  Edit,
  Activity,
  DollarSign,
  Briefcase,
  ExternalLink,
  ShieldCheck,
  MapPin,
  Clock
} from 'lucide-react';
import { formatCurrency } from '../utils/calculations';

interface ClientManagerProps {
  clients: Client[];
  loans: Loan[];
  onAddClient: (client: Client) => void;
  onUpdateClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
}

export const ClientManager: React.FC<ClientManagerProps> = ({ clients, loans, onAddClient, onUpdateClient, onDeleteClient }) => {
  const [view, setView] = useState<'list' | 'form' | 'details'>('list');
  const [searchTerm, setSearchTerm] = useState('');
  const [successMsg, setSuccessMsg] = useState('');
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [isEditing, setIsEditing] = useState(false);

  const [formData, setFormData] = useState<Client>({
    id: '',
    name: '',
    cpf: '',
    phone: '',
    email: '',
    notes: '',
    status: 'active'
  });

  const generateId = () => {
    const nextNum = clients.length + 1;
    return `C${String(nextNum).padStart(3, '0')}`;
  };

  const handleOpenForm = () => {
    setFormData({
      id: generateId(),
      name: '',
      cpf: '',
      phone: '',
      email: '',
      notes: '',
      status: 'active'
    });
    setSuccessMsg('');
    setIsEditing(false);
    setView('form');
    setSelectedClient(null);
  };

  const handleEditClient = (client: Client) => {
    setFormData(client);
    setSuccessMsg('');
    setIsEditing(true);
    setView('form');
  };

  const handleDeleteClientAttempt = (client: Client) => {
    const hasActiveLoans = loans.some(l => l.clientId === client.id);
    if (hasActiveLoans) {
        alert(`Não é possível excluir o cliente ${client.name} pois ele possui empréstimos ativos.`);
        return;
    }
    if (window.confirm(`Confirmar exclusão definitiva do cliente ${client.name}?`)) {
        onDeleteClient(client.id);
        if (selectedClient?.id === client.id) {
            setView('list');
            setSelectedClient(null);
        }
    }
  };

  const handleViewClient = (client: Client) => {
    setSelectedClient(client);
    setView('details');
  };

  const handleBackToList = () => {
    setView('list');
    setSelectedClient(null);
    setIsEditing(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isEditing) {
        onUpdateClient(formData);
        setSuccessMsg(`Cliente atualizado.`);
    } else {
        onAddClient(formData);
        setSuccessMsg(`Cliente cadastrado.`);
    }
    setTimeout(() => {
        setView('list');
        setSuccessMsg('');
    }, 1500);
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const getClientStats = (clientId: string) => {
    const clientLoans = loans.filter(l => l.clientId === clientId);
    const totalPrincipal = clientLoans.reduce((acc, l) => acc + l.principal, 0);
    return {
      count: clientLoans.length,
      totalPrincipal,
      activeCount: clientLoans.filter(l => l.status === 'Ativo').length,
      paidCount: clientLoans.filter(l => l.status === 'Quitado').length,
      allLoans: clientLoans
    };
  };

  const InfoField = ({ icon: Icon, label, value }: any) => (
    <div className="flex items-center gap-3 p-3 rounded-lg hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
      <div className="p-2 rounded-lg bg-slate-100 dark:bg-slate-800 text-slate-400 shrink-0">
        <Icon className="w-3.5 h-3.5" />
      </div>
      <div className="flex flex-col min-w-0">
        <span className="text-[9px] font-bold uppercase tracking-[0.15em] text-slate-400">{label}</span>
        <span className="text-xs font-bold text-simplefy-primary dark:text-slate-200 truncate">{value || '---'}</span>
      </div>
    </div>
  );

  return (
    <div className="space-y-6 animate-fade-in">
      {view === 'list' && (
        <div className="flex flex-col sm:flex-row gap-4">
          <div className="relative flex-1 group">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-simplefy-primary w-4 h-4 transition-colors" />
            <input 
              type="text"
              placeholder="Buscar por nome ou código..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-11 pr-4 py-3 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-xl outline-none shadow-xs focus:border-simplefy-primary transition-all text-xs font-medium"
            />
          </div>
          <button
            onClick={handleOpenForm}
            className="px-6 py-3 bg-simplefy-primary text-white rounded-xl font-bold flex items-center justify-center gap-2 shadow-sm transition hover:brightness-110 text-xs uppercase tracking-widest"
          >
            <UserPlus className="w-4 h-4" />
            Novo Cliente
          </button>
        </div>
      )}

      {view === 'list' && (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-5">
          {filteredClients.map(client => (
            <div 
              key={client.id} 
              onClick={() => handleViewClient(client)}
              className="bg-white dark:bg-slate-900 p-5 rounded-xl border border-slate-200 dark:border-slate-800 hover:border-simplefy-primary dark:hover:border-simplefy-primary/50 transition-all group cursor-pointer shadow-xs"
            >
              <div className="flex justify-between items-start mb-4">
                <div className="w-9 h-9 rounded-lg bg-slate-50 dark:bg-slate-800 flex items-center justify-center text-slate-400 font-black text-sm group-hover:bg-simplefy-primary group-hover:text-white transition-all">
                  {client.name.charAt(0)}
                </div>
                <span className={`px-2 py-0.5 rounded text-[8px] font-black uppercase border ${client.status === 'active' ? 'bg-simplefy-success/10 text-simplefy-success border-simplefy-success/20' : 'bg-simplefy-danger/10 text-simplefy-danger border-simplefy-danger/20'}`}>
                  {client.status === 'active' ? 'Ativo' : 'Inativo'}
                </span>
              </div>
              <h3 className="font-bold text-simplefy-primary dark:text-slate-100 text-sm truncate tracking-tight">{client.name}</h3>
              <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest mt-0.5 mb-5">{client.id}</p>

              <div className="space-y-2 border-t border-slate-50 dark:border-slate-800/50 pt-4 flex items-center gap-2 text-[10px] text-slate-500 font-medium">
                <Phone className="w-3.5 h-3.5 opacity-50" />
                <span>{client.phone || 'Sem contato'}</span>
              </div>
            </div>
          ))}
          {filteredClients.length === 0 && (
            <div className="col-span-full py-20 text-center bg-slate-50 dark:bg-slate-900/50 rounded-xl border-2 border-dashed border-slate-100 dark:border-slate-800">
               <p className="text-slate-400 font-bold text-xs uppercase tracking-widest italic">Nenhum cliente encontrado</p>
            </div>
          )}
        </div>
      )}

      {view === 'details' && selectedClient && (
        <div className="space-y-6 max-w-5xl mx-auto">
          <div className="flex items-center justify-between">
            <button onClick={handleBackToList} className="flex items-center gap-2 text-slate-400 hover:text-simplefy-primary font-bold text-[10px] uppercase tracking-widest transition-colors">
              <ArrowLeft className="w-3.5 h-3.5" /> Voltar
            </button>
            <div className="flex gap-2">
              <button onClick={() => handleEditClient(selectedClient)} className="p-2.5 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-800 rounded-lg text-slate-500 hover:text-simplefy-primary transition shadow-xs"><Edit className="w-4 h-4" /></button>
              <button onClick={() => handleDeleteClientAttempt(selectedClient)} className="p-2.5 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-800 rounded-lg text-slate-500 hover:text-simplefy-danger transition shadow-xs"><Trash2 className="w-4 h-4" /></button>
            </div>
          </div>

          <div className="bg-white dark:bg-slate-900 rounded-2xl p-6 sm:p-10 border border-slate-200 dark:border-slate-800 flex flex-col sm:flex-row items-center gap-8 shadow-xs">
             <div className="w-24 h-24 rounded-2xl bg-simplefy-primary text-white flex items-center justify-center text-4xl font-black shrink-0">
                {selectedClient.name.charAt(0)}
             </div>
             <div className="text-center sm:text-left min-w-0">
               <h2 className="text-2xl font-black text-simplefy-primary dark:text-slate-100 tracking-tight truncate">{selectedClient.name}</h2>
               <div className="flex flex-wrap justify-center sm:justify-start gap-3 mt-3">
                  <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{selectedClient.id}</span>
                  <div className={`flex items-center gap-1.5 text-[9px] font-black uppercase px-2.5 py-1 rounded-full border ${selectedClient.status === 'active' ? 'bg-simplefy-success/10 text-simplefy-success border-simplefy-success/20' : 'bg-simplefy-danger/10 text-simplefy-danger border-simplefy-danger/20'}`}>
                    <div className={`w-1.5 h-1.5 rounded-full ${selectedClient.status === 'active' ? 'bg-simplefy-success' : 'bg-simplefy-danger'}`} />
                    {selectedClient.status === 'active' ? 'Conta Ativa' : 'Inativo'}
                  </div>
               </div>
             </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white dark:bg-slate-900 rounded-2xl p-6 border border-slate-200 dark:border-slate-800 space-y-4 shadow-xs">
              <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-4">Informações de Contato</h4>
              <InfoField icon={CreditCard} label="Documento (CPF)" value={selectedClient.cpf} />
              <InfoField icon={Phone} label="Telefone / WhatsApp" value={selectedClient.phone} />
              <InfoField icon={Mail} label="Email Registrado" value={selectedClient.email} />
            </div>

            <div className="bg-white dark:bg-slate-900 rounded-2xl p-6 border border-slate-200 dark:border-slate-800 space-y-4 shadow-xs">
              <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-4">Métricas Financeiras</h4>
              {(() => {
                  const stats = getClientStats(selectedClient.id);
                  return (
                    <div className="space-y-4">
                       <div className="bg-slate-50 dark:bg-slate-800/40 p-5 rounded-xl text-center border border-slate-100 dark:border-slate-800">
                          <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-1">Total Transacionado</p>
                          <p className="text-xl font-black text-simplefy-primary dark:text-slate-100 tracking-tight">{formatCurrency(stats.totalPrincipal)}</p>
                       </div>
                       <div className="grid grid-cols-2 gap-3">
                          <div className="bg-white dark:bg-slate-800/60 p-3 rounded-lg border border-slate-100 dark:border-slate-700 text-center">
                             <p className="text-[8px] font-bold text-slate-400 uppercase">Quitados</p>
                             <p className="text-sm font-black text-simplefy-success">{stats.paidCount}</p>
                          </div>
                          <div className="bg-white dark:bg-slate-800/60 p-3 rounded-lg border border-slate-100 dark:border-slate-700 text-center">
                             <p className="text-[8px] font-bold text-slate-400 uppercase">Em Aberto</p>
                             <p className="text-sm font-black text-simplefy-primary dark:text-slate-200">{stats.activeCount}</p>
                          </div>
                       </div>
                    </div>
                  );
              })()}
            </div>

            <div className="bg-white dark:bg-slate-900 rounded-2xl p-6 border border-slate-200 dark:border-slate-800 space-y-4 shadow-xs">
              <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-4">Notas Internas</h4>
              <div className="bg-slate-50 dark:bg-slate-800/40 p-4 rounded-xl border border-slate-100 dark:border-slate-800 min-h-[120px]">
                <p className="text-[11px] text-slate-500 dark:text-slate-400 leading-relaxed font-medium">
                  {selectedClient.notes || "Nenhuma observação relevante registrada para este cliente."}
                </p>
              </div>
            </div>
          </div>

          <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-xs">
             <div className="px-6 py-4 bg-slate-50 dark:bg-slate-800/50 border-b dark:border-slate-800">
               <h4 className="font-bold text-simplefy-primary dark:text-slate-400 uppercase tracking-widest text-[10px]">Histórico de Contratos</h4>
             </div>
             <div className="overflow-x-auto">
               <table className="w-full text-left">
                  <thead>
                    <tr className="text-[9px] font-bold text-slate-400 uppercase tracking-widest border-b dark:border-slate-800 bg-slate-50/20">
                      <th className="px-8 py-4">ID de Sistema</th>
                      <th className="px-8 py-4">Status</th>
                      <th className="px-8 py-4">Capital (P)</th>
                      <th className="px-8 py-4">Vigência</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50 dark:divide-slate-800">
                    {getClientStats(selectedClient.id).allLoans.map(loan => (
                      <tr key={loan.id} className="text-xs group hover:bg-slate-50 dark:hover:bg-slate-800/30 transition-colors">
                        <td className="px-8 py-4 font-bold text-slate-500 font-mono text-[10px]">{loan.id.slice(0, 12)}</td>
                        <td className="px-8 py-4">
                           <span className={`px-2 py-0.5 rounded text-[8px] font-black uppercase border ${loan.status === 'Ativo' ? 'bg-simplefy-primary/10 text-simplefy-primary border-simplefy-primary/20' : 'bg-slate-100 dark:bg-slate-800 text-slate-500 border-slate-200 dark:border-slate-700'}`}>
                             {loan.status}
                           </span>
                        </td>
                        <td className="px-8 py-4 font-bold text-simplefy-primary dark:text-slate-200">{formatCurrency(loan.principal)}</td>
                        <td className="px-8 py-4 text-slate-400 font-medium">{loan.startDate.split('-').reverse().join('/')}</td>
                      </tr>
                    ))}
                    {getClientStats(selectedClient.id).allLoans.length === 0 && (
                      <tr>
                        <td colSpan={4} className="px-8 py-10 text-center text-slate-400 font-bold uppercase tracking-widest text-[9px] italic">Sem contratos registrados</td>
                      </tr>
                    )}
                  </tbody>
               </table>
             </div>
          </div>
        </div>
      )}

      {view === 'form' && (
        <div className="max-w-xl mx-auto">
          <form onSubmit={handleSubmit} className="bg-white dark:bg-slate-900 p-8 rounded-2xl shadow-xl border border-slate-200 dark:border-slate-800 animate-slide-up">
            <div className="mb-8">
              <h3 className="text-lg font-black text-simplefy-primary dark:text-slate-100 uppercase tracking-tight">
                {isEditing ? 'Atualizar Cliente' : 'Cadastro de Cliente'}
              </h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Preencha as informações fundamentais</p>
            </div>

            <div className="space-y-5">
               <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-1">Código ID</label>
                    <input required type="text" value={formData.id} disabled={isEditing} onChange={e => setFormData({...formData, id: e.target.value})} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl outline-none font-bold text-sm disabled:opacity-50" />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-1">Situação</label>
                    <select value={formData.status} onChange={e => setFormData({...formData, status: e.target.value as 'active' | 'inactive'})} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl outline-none font-bold text-sm dark:text-slate-100">
                      <option value="active">Conta Ativa</option>
                      <option value="inactive">Inativo / Bloqueado</option>
                    </select>
                  </div>
               </div>
               <div className="space-y-1.5">
                 <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-1">Nome Completo</label>
                 <input required type="text" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl outline-none font-bold text-sm dark:text-slate-100" />
               </div>
               <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-1">CPF</label>
                    <input type="text" value={formData.cpf} onChange={e => setFormData({...formData, cpf: e.target.value})} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl outline-none font-bold text-sm dark:text-slate-100" />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-1">Telefone</label>
                    <input type="text" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl outline-none font-bold text-sm dark:text-slate-100" />
                  </div>
               </div>
               <div className="space-y-1.5">
                 <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-1">Observações Internas</label>
                 <textarea rows={3} value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl outline-none font-medium text-xs dark:text-slate-100 resize-none" placeholder="Detalhes adicionais sobre o perfil do cliente..." />
               </div>
            </div>

            <div className="flex flex-col sm:flex-row gap-4 mt-10">
              <button type="submit" className="flex-1 py-3.5 bg-simplefy-primary text-white rounded-xl font-bold uppercase text-[10px] tracking-widest shadow-md hover:brightness-110 active:scale-[0.98] transition-all">
                {isEditing ? 'Salvar Alterações' : 'Concluir Cadastro'}
              </button>
              <button type="button" onClick={handleBackToList} className="flex-1 py-3.5 bg-slate-100 dark:bg-slate-800 text-slate-500 rounded-xl font-bold uppercase text-[10px] tracking-widest hover:bg-slate-200 transition-colors">
                Cancelar
              </button>
            </div>
          </form>
        </div>
      )}

      {successMsg && (
        <div className="fixed bottom-10 right-10 bg-simplefy-primary text-white px-6 py-4 rounded-xl shadow-2xl flex items-center gap-3 animate-slide-up z-50 border border-white/10">
          <CheckCircle2 className="w-5 h-5 text-simplefy-success" />
          <span className="text-xs font-bold uppercase tracking-widest">{successMsg}</span>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ViewState, Loan, Client, Collaborator, PenaltyPattern, Expense, Portfolio, PortfolioMovement, UserProfile, AppSettings, InstallmentStatus } from './types';
import { Dashboard } from './components/Dashboard';
import { LoanList } from './components/LoanList';
import { AIAnalyst } from './components/AIAnalyst';
import { ClientManager } from './components/ClientManager';
import { PenaltyPatternManager } from './components/PenaltyPatternManager';
import { CollaboratorManager } from './components/CollaboratorManager';
import { ExpenseManager } from './components/ExpenseManager';
import { PortfolioManager } from './components/PortfolioManager';
import { Forecast } from './components/Forecast';
import { ProfileWidget } from './components/ProfileWidget';
import { ProfileView } from './components/ProfileView';
import { SettingsView } from './components/SettingsView';
import { LoanCalculator } from './components/LoanCalculator';
import { LoanForm } from './components/LoanForm';
import { LogoText } from './components/Logo';
import { generateInstallments } from './utils/calculations';
import { 
  LayoutDashboard, 
  List, 
  Bot, 
  Users,
  Briefcase,
  Gavel,
  Sun,
  Moon,
  Menu,
  X,
  Calculator
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<ViewState>(ViewState.DASHBOARD);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const savedTheme = localStorage.getItem('theme');
    return savedTheme === 'dark' || (!savedTheme && window.matchMedia('(prefers-color-scheme: dark)').matches);
  });

  const [loans, setLoans] = useState<Loan[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [collaborators, setCollaborators] = useState<Collaborator[]>([]);
  const [penaltyPatterns, setPenaltyPatterns] = useState<PenaltyPattern[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [portfolios, setPortfolios] = useState<Portfolio[]>([]);
  const [portfolioMovements, setPortfolioMovements] = useState<PortfolioMovement[]>([]);

  const [preFilledLoan, setPreFilledLoan] = useState<Partial<Loan> | null>(null);
  const [isAddingLoan, setIsAddingLoan] = useState(false);

  const [userProfile, setUserProfile] = useState<UserProfile>({
    name: 'Gestor SimpleFy',
    email: 'gestor@simplefy.com',
    businessName: 'SimpleFy Management',
    currency: 'BRL',
    timezone: 'GMT-3 (Brasília)',
    startDate: new Date().toISOString().split('T')[0],
    notes: ''
  });

  const [appSettings, setAppSettings] = useState<AppSettings>({
    defaultPenaltyRate: 2,
    defaultMoraRate: 1,
    interestType: 'Simples',
    decimalPlaces: 2,
    expenseImpactsProfit: true,
    allowTransfers: true,
    expenseCategories: ['Operacional', 'Pessoal', 'Investimento'],
    dashboardVisibility: {
      receitaProjetada: true,
      lucroProjetado: true,
      lucroLiquido: true,
      caixaDisponivel: true,
      roi: true,
    }
  });

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    const savedData = localStorage.getItem('simplefy_data_v22');
    if (savedData) {
      const parsed = JSON.parse(savedData);
      setLoans(parsed.loans || []);
      setClients(parsed.clients || []);
      setCollaborators(parsed.collaborators || []);
      setPenaltyPatterns(parsed.penaltyPatterns || []);
      setExpenses(parsed.expenses || []);
      setPortfolios(parsed.portfolios || []);
      setPortfolioMovements(parsed.portfolioMovements || []);
      if (parsed.userProfile) setUserProfile(parsed.userProfile);
      if (parsed.appSettings) setAppSettings(parsed.appSettings);
    } else {
        const seedPatterns: PenaltyPattern[] = [
           { id: "P001", name: "Padrão Legal (2% + 1% mês)", fixedRate: 2, monthlyInterest: 1, active: true },
           { id: "P002", name: "Multa Atraso Curto (1% + 0.5% mês)", fixedRate: 1, monthlyInterest: 0.5, active: true }
        ];
        const seedClients: Client[] = [
          { id: 'C001', name: 'Matheus', cpf: '000.000.000-01', phone: '1191425-6969', status: 'active' },
          { id: 'C002', name: 'Bruno', cpf: '000.000.000-02', phone: '1197752-3942', status: 'active' },
          { id: 'C003', name: 'Esposa Bruno', cpf: '000.000.000-03', phone: '1197752-3942', status: 'active' },
          { id: 'C004', name: 'Bahia', cpf: '000.000.000-04', phone: '1198342-4814', status: 'active' },
        ];
        const seedCollaborators: Collaborator[] = [
          { id: 'V001', name: 'Administrador Principal', type: 'percentage', base: 'profit', value: 0 }
        ];
        const seedPortfolios: Portfolio[] = [
          { id: 'PORT001', name: 'Reserva Emergência', type: 'Reserva' },
          { id: 'PORT002', name: 'Conta Cripto', type: 'Criptomoedas' }
        ];
        const rawLoans: Partial<Loan>[] = [
          { id: 'E001', clientId: 'C001', collaboratorId: 'V001', principal: 10000, monthlyInterestRate: 10, months: 4, startDate: '2025-09-01', status: 'Ativo' },
          { id: 'E002', clientId: 'C002', collaboratorId: 'V001', principal: 8000, monthlyInterestRate: 10, months: 10, startDate: '2025-09-01', status: 'Ativo' },
          { id: 'E003', clientId: 'C002', collaboratorId: 'V001', principal: 2800, monthlyInterestRate: 25, months: 1, startDate: '2025-11-01', status: 'Ativo' },
          { id: 'E004', clientId: 'C003', collaboratorId: 'V001', principal: 5000, monthlyInterestRate: 13.5, months: 10, startDate: '2025-11-01', status: 'Ativo' },
          { id: 'E005', clientId: 'C004', collaboratorId: 'V001', principal: 5800, monthlyInterestRate: 14.66, months: 10, startDate: '2025-12-01', status: 'Ativo' },
          { id: 'E006', clientId: 'C001', collaboratorId: 'V001', principal: 1000, monthlyInterestRate: 20, months: 1, startDate: '2025-11-01', status: 'Quitado' },
          { id: 'E007', clientId: 'C001', collaboratorId: 'V001', principal: 2000, monthlyInterestRate: 22.5, months: 2, startDate: '2025-12-01', status: 'Ativo' },
        ];
        const seedLoans = rawLoans.map(l => {
          const loan = l as Loan;
          let insts;

          // Lógica especial para o contrato E001 (Capital amortizado mensalmente)
          if (loan.id === 'E001') {
            insts = [];
            const principalPerMonth = loan.principal / loan.months;
            const interestPerMonth = loan.principal * (loan.monthlyInterestRate / 100);

            for (let i = 1; i <= loan.months; i++) {
              const d = new Date(loan.startDate + 'T12:00:00');
              d.setMonth(d.getMonth() + i);
              insts.push({
                number: i,
                dueDate: d.toISOString().split('T')[0],
                principalValue: principalPerMonth,
                interestValue: interestPerMonth,
                penaltyValue: 0,
                status: 'Pendente' as InstallmentStatus
              });
            }
          } else {
            // Regra padrão para os demais contratos
            insts = generateInstallments(loan);
          }

          if (loan.status === 'Quitado') insts.forEach(i => i.status = 'Pago');
          return { ...loan, installments: insts };
        });
        setPenaltyPatterns(seedPatterns);
        setClients(seedClients);
        setCollaborators(seedCollaborators);
        setLoans(seedLoans);
        setExpenses([]);
        setPortfolios(seedPortfolios);
        setPortfolioMovements([]);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('simplefy_data_v22', JSON.stringify({ 
      loans, clients, collaborators, penaltyPatterns, expenses, portfolios, portfolioMovements,
      userProfile, appSettings
    }));
  }, [loans, clients, collaborators, penaltyPatterns, expenses, portfolios, portfolioMovements, userProfile, appSettings]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const handleNavClick = (tab: ViewState) => {
    setActiveTab(tab);
    setIsMobileMenuOpen(false);
    setIsAddingLoan(false);
    setPreFilledLoan(null);
  };

  const handleAddExpense = (e: Expense) => {
    setExpenses([...expenses, e]);
    if (e.type === 'transfer_to_portfolio' && e.destination) {
      const movement: PortfolioMovement = {
        id: crypto.randomUUID(),
        portfolioId: e.destination,
        date: e.date,
        amount: e.amount,
        origin: 'Transferência (Despesas)',
        description: `Ref: ${e.description}`
      };
      setPortfolioMovements(prev => [...prev, movement]);
    }
  };

  const handleUpdateExpense = (u: Expense) => {
    const oldExp = expenses.find(e => e.id === u.id);
    setExpenses(expenses.map(e => e.id === u.id ? u : e));
    setPortfolioMovements(prev => prev.filter(m => !(m.origin === 'Transferência (Despesas)' && m.description.includes(oldExp?.description || '---'))));
    if (u.type === 'transfer_to_portfolio' && u.destination) {
      const movement: PortfolioMovement = {
        id: crypto.randomUUID(),
        portfolioId: u.destination,
        date: u.date,
        amount: u.amount,
        origin: 'Transferência (Despesas)',
        description: `Ref: ${u.description}`
      };
      setPortfolioMovements(prev => [...prev, movement]);
    }
  };

  const handleDeleteExpense = (id: string) => {
    const exp = expenses.find(e => e.id === id);
    setExpenses(expenses.filter(e => e.id !== id));
    if (exp?.type === 'transfer_to_portfolio') {
      setPortfolioMovements(prev => prev.filter(m => !(m.origin === 'Transferência (Despesas)' && m.description.includes(exp.description))));
    }
  };

  const handleCalculatorConversion = (data: { 
    principal: number; 
    rate: number; 
    months: number; 
    clientId: string; 
    collaboratorId: string;
    newClient?: Client;
  }) => {
    const loanData: Partial<Loan> = {
      principal: data.principal,
      monthlyInterestRate: data.rate,
      months: data.months,
      startDate: new Date().toISOString().split('T')[0],
    };
    const installments = generateInstallments(loanData);
    const newLoan: Loan = {
      id: crypto.randomUUID(),
      clientId: data.clientId,
      collaboratorId: data.collaboratorId,
      principal: data.principal,
      monthlyInterestRate: data.rate,
      months: data.months,
      startDate: loanData.startDate!,
      status: 'Ativo',
      installments: installments
    };
    if (data.newClient) {
      setClients(prev => [...prev, data.newClient!]);
    }
    setLoans(prev => [...prev, newLoan]);
    setActiveTab(ViewState.LOANS);
  };

  const handleSaveLoan = (loan: Loan, newClient?: Client) => {
    if (newClient) {
      setClients(prev => [...prev, newClient]);
    }
    setLoans(prev => [...prev, loan]);
    setIsAddingLoan(false);
    setPreFilledLoan(null);
  };

  const getPageTitle = (tab: ViewState) => {
    switch(tab) {
      case ViewState.PORTFOLIOS: return 'Carteiras';
      case ViewState.EXPENSES: return 'Despesas';
      case ViewState.FORECAST: return 'Previsão';
      case ViewState.PROFILE: return 'Perfil';
      case ViewState.SETTINGS: return 'Configurações';
      case ViewState.LOAN_CALCULATOR: return 'Simulador';
      default: return tab.replace('_', ' ');
    }
  };

  return (
    <div className="min-h-screen flex bg-simplefy-bg dark:bg-slate-950">
      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-xs z-40 lg:hidden" onClick={() => setIsMobileMenuOpen(false)} />
      )}

      <aside className={`fixed inset-y-0 left-0 z-50 w-60 bg-simplefy-primary text-white flex flex-col transition-transform duration-200 lg:relative lg:translate-x-0 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="h-16 flex items-center px-6 border-b border-white/5">
          <LogoText />
        </div>
        <nav className="flex-1 py-4 space-y-0.5 px-3 overflow-y-auto">
          <NavItem icon={LayoutDashboard} label="Dashboard" active={activeTab === ViewState.DASHBOARD} onClick={() => handleNavClick(ViewState.DASHBOARD)} />
          <NavItem icon={Calculator} label="Simulador" active={activeTab === ViewState.LOAN_CALCULATOR} onClick={() => handleNavClick(ViewState.LOAN_CALCULATOR)} />
          <NavItem icon={Users} label="Clientes" active={activeTab === ViewState.CLIENTS} onClick={() => handleNavClick(ViewState.CLIENTS)} />
          <NavItem icon={List} label="Contratos" active={activeTab === ViewState.LOANS} onClick={() => handleNavClick(ViewState.LOANS)} />
          <NavItem icon={Briefcase} label="Equipe" active={activeTab === ViewState.COLLABORATORS} onClick={() => handleNavClick(ViewState.COLLABORATORS)} />
          <NavItem icon={Gavel} label="Multas" active={activeTab === ViewState.PENALTY_PATTERNS} onClick={() => handleNavClick(ViewState.PENALTY_PATTERNS)} />
          <div className="pt-6 pb-2 px-4 opacity-30 text-[9px] font-bold uppercase tracking-[0.2em]">Inteligência</div>
          <NavItem icon={Bot} label="Analista IA" active={activeTab === ViewState.AI_ANALYST} onClick={() => handleNavClick(ViewState.AI_ANALYST)} isSpecial={true} />
        </nav>
      </aside>

      <main className="flex-1 flex flex-col h-screen overflow-hidden">
        <header className="bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 h-16 flex items-center justify-between px-6 shrink-0 z-20">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsMobileMenuOpen(true)} className="lg:hidden p-2 -ml-2 text-slate-500 hover:bg-slate-50 rounded-lg"><Menu className="w-5 h-5" /></button>
            <h1 className="text-base font-bold text-simplefy-primary dark:text-slate-100 uppercase tracking-tight">
              {getPageTitle(activeTab)}
            </h1>
          </div>
          <div className="flex items-center gap-3">
            <button onClick={toggleTheme} className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 transition-colors">
              {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>
            <ProfileWidget activeTab={activeTab} onNavigate={handleNavClick} />
          </div>
        </header>

        <div className="flex-1 overflow-y-auto px-6 py-8">
          <div className="max-w-7xl mx-auto pb-12">
            {activeTab === ViewState.DASHBOARD && <Dashboard loans={loans} collaborators={collaborators} clients={clients} expenses={expenses} settings={appSettings} />}
            {activeTab === ViewState.CLIENTS && <ClientManager clients={clients} loans={loans} onAddClient={c => setClients([...clients, c])} onUpdateClient={u => setClients(clients.map(c => c.id === u.id ? u : c))} onDeleteClient={id => setClients(clients.filter(c => c.id !== id))} />}
            {activeTab === ViewState.LOANS && (
              isAddingLoan ? (
                <LoanForm 
                  clients={clients} 
                  collaborators={collaborators} 
                  initialData={preFilledLoan ? (preFilledLoan as Loan) : undefined}
                  onSave={handleSaveLoan}
                  onCancel={() => {
                    setIsAddingLoan(false);
                    setPreFilledLoan(null);
                  }}
                />
              ) : (
                <div className="space-y-6">
                  <div className="flex justify-end">
                    <button onClick={() => setIsAddingLoan(true)} className="px-5 py-2.5 bg-simplefy-primary text-white rounded-lg font-bold text-xs hover:bg-slate-800 transition shadow-xs">Novo Contrato</button>
                  </div>
                  <LoanList loans={loans} clients={clients} collaborators={collaborators} penaltyPatterns={penaltyPatterns} onDelete={id => setLoans(loans.filter(l => l.id !== id))} onUpdate={u => setLoans(loans.map(l => l.id === u.id ? u : l))} />
                </div>
              )
            )}
            {activeTab === ViewState.LOAN_CALCULATOR && (
              <LoanCalculator 
                clients={clients} 
                collaborators={collaborators} 
                onConvertToLoan={handleCalculatorConversion} 
              />
            )}
            {activeTab === ViewState.FORECAST && <Forecast loans={loans} />}
            {activeTab === ViewState.EXPENSES && <ExpenseManager expenses={expenses} portfolios={portfolios} onAdd={handleAddExpense} onUpdate={handleUpdateExpense} onDelete={handleDeleteExpense} />}
            {activeTab === ViewState.PORTFOLIOS && <PortfolioManager portfolios={portfolios} movements={portfolioMovements} onAdd={p => setPortfolios([...portfolios, p])} onUpdate={u => setPortfolios(portfolios.map(p => p.id === u.id ? u : p))} onDelete={id => setPortfolios(portfolios.filter(p => p.id !== id))} onAddMovement={m => setPortfolioMovements([...portfolioMovements, m])} />}
            {activeTab === ViewState.COLLABORATORS && <CollaboratorManager collaborators={collaborators} onAdd={c => setCollaborators([...collaborators, c])} onUpdate={u => setCollaborators(collaborators.map(c => c.id === u.id ? u : c))} onDelete={id => setCollaborators(collaborators.filter(c => c.id !== id))} />}
            {activeTab === ViewState.PENALTY_PATTERNS && <PenaltyPatternManager patterns={penaltyPatterns} onAdd={p => setPenaltyPatterns([...penaltyPatterns, p])} onUpdate={u => setPenaltyPatterns(penaltyPatterns.map(p => p.id === u.id ? p : p))} onDelete={id => setPenaltyPatterns(penaltyPatterns.filter(p => p.id !== id))} />}
            {activeTab === ViewState.AI_ANALYST && <AIAnalyst loans={loans} clients={clients} collaborators={collaborators} />}
            {activeTab === ViewState.PROFILE && <ProfileView profile={userProfile} onSave={setUserProfile} />}
            {activeTab === ViewState.SETTINGS && <SettingsView settings={appSettings} onSave={setAppSettings} />}
          </div>
        </div>
      </main>
    </div>
  );
};

const NavItem = ({ icon: Icon, label, active, onClick, isSpecial }: any) => (
  <button 
    onClick={onClick} 
    className={`w-full flex items-center px-4 py-2.5 rounded-lg transition-all ${
      active 
        ? 'bg-white/10 text-white font-bold' 
        : 'text-white/50 hover:text-white hover:bg-white/5'
    } ${isSpecial ? 'bg-white/5 text-blue-400' : ''}`}
  >
    <Icon className={`w-4 h-4 shrink-0 ${active ? 'text-white' : 'text-inherit opacity-70'}`} />
    <span className="ml-3 text-sm tracking-tight">{label}</span>
  </button>
);

export default App;
